  // ---------- Helpers ----------
  const $ = (sel, root=document) => root.querySelector(sel);
  const $$ = (sel, root=document) => Array.from(root.querySelectorAll(sel));
  const on = (el, evt, fn, opts) => el && el.addEventListener && el.addEventListener(evt, fn, opts);
  // PERF: debounce rapid list filters (search) — same render logic, fewer main-thread passes
  const perfDebounce = (fn, ms = 250) => {
    let timer = null;
    return (...args) => {
      clearTimeout(timer);
      timer = window.setTimeout(() => fn(...args), ms);
    };
  };
  const perfIdle = (fn, timeout = 1500) => {
    if(typeof requestIdleCallback === "function"){
      return requestIdleCallback(fn, { timeout });
    }
    return window.setTimeout(fn, 80);
  };
  const perfYield = () => new Promise((resolve) => {
    if(typeof requestIdleCallback === "function"){
      requestIdleCallback(() => resolve(), { timeout: 32 });
    } else {
      window.setTimeout(resolve, 0);
    }
  });
  const perfMapChunked = async (rows, mapper, chunkSize = LOAD_SHEETS_MAP_CHUNK_SIZE) => {
    const list = Array.isArray(rows) ? rows : [];
    const out = new Array(list.length);
    for(let idx = 0; idx < list.length; idx += 1){
      out[idx] = mapper(list[idx], idx);
      if(idx > 0 && (idx % chunkSize) === 0) await perfYield();
    }
    return out;
  };
  const perfCloneArray = (arr) => {
    if(!Array.isArray(arr) || !arr.length) return arr;
    try {
      if(typeof structuredClone === "function") return structuredClone(arr);
    } catch(_e) {}
    try { return JSON.parse(JSON.stringify(arr)); } catch(_e2) { return arr.slice(); }
  };
  const GiPerf = {
    mark(name){
      try { if(typeof performance !== "undefined" && performance.mark) performance.mark("gi:" + name); } catch(_e) {}
    },
    measure(name, startName){
      try {
        if(typeof performance === "undefined" || !performance.measure) return;
        const start = "gi:" + (startName || name);
        const end = "gi:" + name + ":end";
        performance.measure("gi:" + name, start, end);
        const entry = performance.getEntriesByName("gi:" + name).pop();
        if(entry && entry.duration >= GI_PERF_LOG_MS){
          console.info("[GiPerf]", name, Math.round(entry.duration) + "ms");
        }
      } catch(_e) {}
    },
    run(name, fn){
      this.mark(name);
      try {
        const result = fn();
        this.mark(name + ":end");
        this.measure(name, name);
        return result;
      } catch(err){
        this.mark(name + ":end");
        this.measure(name, name);
        throw err;
      }
    }
  };
  const safeTrim = (v) => String(v ?? "").trim();

  function estimateRecordPayloadBytes(rec){
    const p = rec?.payload;
    if(!p) return 0;
    if(typeof p === "string") return p.length;
    try { return JSON.stringify(p).length; } catch(_e) { return 0; }
  }

  function isCustomerPayloadTooHeavyForSyncMetrics(rec){
    return estimateRecordPayloadBytes(rec) > CUSTOMER_PAYLOAD_METRICS_SKIP_BYTES;
  }

  function getCustomerRawNewPolicies(rec){
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    if(Array.isArray(payload.newPolicies) && payload.newPolicies.length) return payload.newPolicies;
    if(Array.isArray(payload?.operational?.newPolicies) && payload.operational.newPolicies.length) return payload.operational.newPolicies;
    return [];
  }

  function clonePolicyForMetrics(raw){
    if(!raw || typeof raw !== "object") return raw;
    try {
      const p = JSON.parse(JSON.stringify(raw));
      if(typeof Wizard !== "undefined" && Wizard?.normalizeAllNewPolicies){
        const normalized = Wizard.normalizeAllNewPolicies([p]);
        return normalized[0] || p;
      }
      if(typeof Wizard !== "undefined" && Wizard?.normalizeHealthPolicyPremiums) Wizard.normalizeHealthPolicyPremiums(p);
      return p;
    } catch(_e) {
      return raw;
    }
  }

  function invalidateCachesAfterDataSync(scope = "all"){
    if(scope === "all"){
      try { DashboardUI.invalidateMetricsCache?.(); } catch(_e) {}
      try { CustomersUI.invalidatePolicyCollectCache?.(); } catch(_e) {}
      return;
    }
    const customerIds = Array.isArray(scope?.customerIds) ? scope.customerIds : [];
    const proposalIds = Array.isArray(scope?.proposalIds) ? scope.proposalIds : [];
    if(customerIds.length || proposalIds.length){
      try { DashboardUI.invalidateMetricsCache?.(); } catch(_e) {}
      try { CustomersUI.invalidatePolicyCollectCache?.(customerIds); } catch(_e) {}
    }
  }

  function isPdfMimeType(type){
    const t = safeTrim(type || "").toLowerCase();
    if(!t) return false;
    if(t === "application/pdf" || t === "application/x-pdf" || t === "application/acrobat" || t === "application/vnd.pdf") return true;
    return /pdf/i.test(t);
  }

  function isPdfUploadFile(file){
    if(!file) return false;
    const name = safeTrim(file?.name || "");
    if(/\.pdf$/i.test(name)) return true;
    return isPdfMimeType(file?.type);
  }

  async function isPdfUploadFileAsync(file){
    if(isPdfUploadFile(file)) return true;
    try{
      const buf = await file.slice(0, 5).arrayBuffer();
      const head = new TextDecoder("latin1").decode(buf);
      return head.startsWith("%PDF");
    }catch(_e){
      return false;
    }
  }

  function isExcelUploadFile(file){
    const name = safeTrim(file?.name || "");
    const type = safeTrim(file?.type || "");
    return /\.(xlsx|xls|csv)$/i.test(name)
      || /spreadsheet|excel|ms-excel|officedocument\.spreadsheetml/i.test(type);
  }

  function bindFileDropZone(zone, options = {}){
    if(!zone || zone._giFileDropBound) return;
    zone._giFileDropBound = true;
    const acceptFile = typeof options.acceptFile === "function" ? options.acceptFile : () => true;
    const onFile = typeof options.onFile === "function" ? options.onFile : () => {};
    const onReject = typeof options.onReject === "function" ? options.onReject : null;
    const dragOverClass = safeTrim(options.dragOverClass) || "is-dragover";
    const hasFiles = (dt) => dt && Array.from(dt.types || []).includes("Files");
    const clearDrag = () => zone.classList.remove(dragOverClass);
    const onDragEnter = (e) => {
      if(!hasFiles(e.dataTransfer)) return;
      e.preventDefault();
      e.stopPropagation();
      zone.classList.add(dragOverClass);
    };
    const onDragOver = (e) => {
      if(!hasFiles(e.dataTransfer)) return;
      e.preventDefault();
      e.stopPropagation();
      try { e.dataTransfer.dropEffect = "copy"; } catch(_e){}
      zone.classList.add(dragOverClass);
    };
    const onDragLeave = (e) => {
      if(e.relatedTarget && zone.contains(e.relatedTarget)) return;
      clearDrag();
    };
    const onDrop = async (e) => {
      e.preventDefault();
      e.stopPropagation();
      clearDrag();
      const file = e.dataTransfer?.files?.[0];
      if(!file) return;
      const accepted = await Promise.resolve(acceptFile(file));
      if(!accepted){
        if(onReject) onReject(file);
        return;
      }
      await onFile(file);
    };
    zone.addEventListener("dragenter", onDragEnter);
    zone.addEventListener("dragover", onDragOver);
    zone.addEventListener("dragleave", onDragLeave);
    zone.addEventListener("drop", onDrop);
  }

