  function isValidIsraeliId(value){
    const raw = normalizeIdValue(value);
    if(!raw || raw.length > 9) return false;
    const id = raw.padStart(9, '0');
    let sum = 0;
    for(let i=0; i<9; i += 1){
      let num = Number(id[i]) * ((i % 2) + 1);
      if(num > 9) num -= 9;
      sum += num;
    }
    return sum % 10 === 0;
  }

  function isValidIsraeliPhone(value){
    const phone = normalizePhoneValue(value);
    if(!/^0\d{8,9}$/.test(phone)) return false;
    const mobile = /^05\d{8}$/.test(phone);
    const landline = /^0(?:2|3|4|8|9)\d{7}$/.test(phone);
    const special = /^07\d{8}$/.test(phone);
    return mobile || landline || special;
  }

  function isValidEmailAddress(value){
    const email = normalizeEmailValue(value);
    if(!email) return true;
    return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
  }

  function getValidationConfigForBind(path){
    const bind = safeTrim(path);
    if(!bind) return null;
    if(/(^|\.)idNumber$/.test(bind) || /(^|\.)holderId$/.test(bind)) return { kind:'id', label:'תעודת זהות' };
    if(/(^|\.)phone$/.test(bind)) return { kind:'phone', label:'טלפון' };
    if(/(^|\.)email$/.test(bind)) return { kind:'email', label:'מייל' };
    return null;
  }

  function validateValueByKind(kind, value, options = {}){
    const raw = String(value ?? '');
    const clean = kind === 'id' ? normalizeIdValue(raw) : kind === 'phone' ? normalizePhoneValue(raw) : normalizeEmailValue(raw);
    const allowBlank = options.allowBlank !== false;
    if(!clean){
      return { ok: !!allowBlank, clean, message: allowBlank ? '' : (options.requiredMessage || 'שדה חובה') };
    }
    if(kind === 'id') return { ok: isValidIsraeliId(clean), clean, message: 'מספר זהות לא תקין' };
    if(kind === 'phone') return { ok: isValidIsraeliPhone(clean), clean, message: 'מספר טלפון לא תקין' };
    if(kind === 'email') return { ok: isValidEmailAddress(clean), clean, message: 'כתובת מייל לא תקינה' };
    return { ok:true, clean, message:'' };
  }

  function normalizeHarWorkbookCell(value){
    return safeTrim(value)
      .replace(/[\u00A0\u2007\u202F]/g, ' ')
      .replace(/[\u200E\u200F]/g, '')
      .replace(/[״“”]/g, '"')
      .replace(/[׳‘’]/g, "'")
      .replace(/["'׳״`´]/g, '')
      .replace(/[()\[\]{}]/g, ' ')
      .replace(/[‐‑‒–—−]/g, '-')
      .replace(/\s+/g, ' ')
      .replace(/[:;,]+$/g, '')
      .trim();
  }

  function findHarWorkbookHeaderRow(rows, headerMatchers, options = {}){
    if(!Array.isArray(rows) || !rows.length) return { index:-1, score:0, requiredHits:0 };
    const normalize = typeof options.normalize === "function" ? options.normalize : ((value) => normalizeHarWorkbookCell(value));
    const requiredKeys = Array.isArray(options.requiredKeys) && options.requiredKeys.length ? options.requiredKeys : ["idNumber", "main", "company", "policyNumber"];
    let best = { index:-1, score:0, requiredHits:0, populated:0 };
    const HAR_META_ROW_RE = /התיק הביטוחי|הופק מאתר|משרד האוצר|בתאריך/;
    rows.forEach((row, idx) => {
      if(!Array.isArray(row) || !row.length) return;
      // דלג על שורות מטא של הר הביטוח — בדיקה על הטקסט הגולמי לפני normalize
      // (התאריך עשוי להיות בתא נפרד, לכן בודקים את כל השורה הגולמית יחד)
      const rawRowStr = row.map((v) => String(v ?? "")).join(" ");
      if(HAR_META_ROW_RE.test(rawRowStr)) return;
      const normalizedRow = row.map((value) => normalize(value)).filter(Boolean);
      if(!normalizedRow.length) return;
      const hitsByKey = Object.fromEntries(Object.entries(headerMatchers || {}).map(([key, patterns]) => [key, normalizedRow.some((cell) => patterns.some((pattern) => pattern.test(cell)))]));
      const score = Object.values(hitsByKey).reduce((sum, hit) => sum + (hit ? 1 : 0), 0);
      const requiredHits = requiredKeys.reduce((sum, key) => sum + (hitsByKey[key] ? 1 : 0), 0);
      const populated = normalizedRow.length;
      if(requiredHits > best.requiredHits || (requiredHits === best.requiredHits && score > best.score) || (requiredHits === best.requiredHits && score === best.score && populated > best.populated)) {
        best = { index:idx, score, requiredHits, populated };
      }
    });
    return { index: best.index, score: best.score, requiredHits: best.requiredHits };
  }

  const OPS_RESULT_OPTIONS = {
    pendingSignatures: "בוצע שיקוף · ממתין לחתימות",
    notInterested: "נעצרה שיחת שיקוף · לא מעוניין",
    waitingAgentInfo: "ממתין להשלמת מידע מהנציג"
  };

  function ensureOpsProcess(rec){
    if(!rec || typeof rec !== "object") return {};
    const payload = rec.payload && typeof rec.payload === "object" ? rec.payload : (rec.payload = {});
    const store = payload.opsProcess && typeof payload.opsProcess === "object" ? payload.opsProcess : (payload.opsProcess = {});
    return store;
  }

  function setOpsTouch(rec, patch = {}){
    if(!rec) return {};
    const store = ensureOpsProcess(rec);
    Object.assign(store, patch || {});
    const stamp = safeTrim((patch || {}).updatedAt) || nowISO();
    store.updatedAt = stamp;
    if(!store.updatedBy) store.updatedBy = safeTrim(Auth?.current?.name);
    rec.updatedAt = stamp;
    if(State?.data?.meta) State.data.meta.updatedAt = stamp;
    return store;
  }

  function getOpsResultLabel(key){
    const k = safeTrim(key);
    return OPS_RESULT_OPTIONS[k] || "";
  }

  function getOpsStatePresentation(rec){
    const ops = ensureOpsProcess(rec);
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    const mirrorFlow = payload?.mirrorFlow && typeof payload.mirrorFlow === 'object' ? payload.mirrorFlow : {};
    const call = (mirrorFlow.callSession && typeof mirrorFlow.callSession === 'object')
      ? mirrorFlow.callSession
      : ((mirrorFlow.call && typeof mirrorFlow.call === 'object') ? mirrorFlow.call : {});
    const finalLabel = getOpsResultLabel(ops.resultStatus);
    let liveKey = safeTrim(ops.liveState);
    let liveLabel = "ממתין לשיקוף";
    let tone = "info";

    if(call?.active){
      liveKey = "in_call";
      liveLabel = "הלקוח בשיחת שיקוף כעת";
      tone = "warn";
    } else if(finalLabel){
      liveLabel = "הלקוח סיים שיחת שיקוף";
      tone = ops.resultStatus === 'notInterested' ? 'danger' : 'success';
    } else if(liveKey === "call_finished"){
      liveLabel = "הלקוח סיים שיחת שיקוף";
      tone = "success";
    } else if(liveKey === "handling"){
      liveLabel = "הלקוח בטיפול מחלקת תפעול";
      tone = "info";
    }

    let timerText = "00:00";
    let timerMeta = "הטיימר יתחיל ברגע שתופעל שיחת שיקוף";
    let timerLive = false;
    if(call?.active && call?.startedAt){
      const sec = Math.max(0, Math.floor((Date.now() - new Date(call.startedAt).getTime()) / 1000));
      timerText = MirrorFlowReadModel?.formatDuration?.(sec) || "00:00";
      timerMeta = `בשיחה החל מ־${MirrorFlowReadModel?.formatClock?.(call.startedAt) || '—'}`;
      timerLive = true;
    } else if(call?.durationText){
      timerText = safeTrim(call.durationText) || "00:00";
      timerMeta = `שיחה אחרונה · התחלה ${safeTrim(call.startTime) || '—'} · סיום ${safeTrim(call.endTime) || '—'}`;
    } else if(safeTrim(call?.startedAt)){
      timerMeta = `שיחה אחרונה בתאריך ${MirrorFlowReadModel?.formatFullDate?.(call.startedAt) || '—'}`;
    }

    return {
      store: ops,
      liveKey: liveKey || 'waiting',
      liveLabel,
      finalLabel,
      tone,
      resultKey: safeTrim(ops.resultStatus),
      timerText,
      timerMeta,
      timerLive,
      waitingInfo: liveKey && liveKey !== 'waiting' ? 'יש טיפול פעיל/קודם בתהליך זה' : 'טרם התחיל טיפול תפעולי בלקוח זה',
      ownerText: safeTrim(ops.ownerName || call?.startedBy || ops.updatedBy || ''),
      updatedText: safeTrim(ops.updatedAt || rec?.updatedAt || '')
    };
  }


  function releaseGlobalUiLocks(){
    try { document.body.style.overflow = ""; } catch(_e) {}
    try { document.body.style.pointerEvents = ""; } catch(_e) {}
    try { document.documentElement.style.overflow = ""; } catch(_e) {}
    try { document.documentElement.style.pointerEvents = ""; } catch(_e) {}
    try { document.body.removeAttribute("inert"); } catch(_e) {}
    try { document.documentElement.removeAttribute("inert"); } catch(_e) {}
    try { document.body.classList.remove("is-loading", "is-busy", "modal-open", "lcBusy", "appBusy", "lcLeadShellOpen"); } catch(_e) {}
    try { document.activeElement?.blur?.(); } catch(_e) {}
    $$('[aria-busy="true"]').forEach((el) => el.setAttribute("aria-busy", "false"));
  }

  function forceCloseUiLayers(options = {}){
    const keepIds = new Set(Array.isArray(options.keepIds) ? options.keepIds.filter(Boolean) : []);

    const closeById = (id, cfg = {}) => {
      if(!id || keepIds.has(id)) return;
      const el = document.getElementById(id);
      if(!el) return;
      try { el.classList.remove("is-open", "is-active", "is-visible"); } catch(_e) {}
      if(cfg.hidden) {
        try { el.hidden = true; } catch(_e) {}
      }
      if(cfg.ariaHidden !== false) {
        try { el.setAttribute("aria-hidden", "true"); } catch(_e) {}
      }
      if(cfg.hideStyle) {
        try { el.style.display = "none"; } catch(_e) {}
      }
    };

    try { ForgotPasswordUI?.close?.(); } catch(_e) {}
    try { UsersUI?.closeModal?.(); } catch(_e) {}
    try { ArchiveCustomerUI?.close?.(); } catch(_e) {}
    try { PurgeArchivedCustomerUI?.close?.(); } catch(_e) {}
    try { CustomersUI?.closePolicyModal?.(); } catch(_e) {}
    try { CustomersUI?.close?.(); } catch(_e) {}
    try { LeadShellUI?.close?.(); } catch(_e) {}
    try { Wizard?.closeHealthFindingsModal?.(); } catch(_e) {}
    try { Wizard?.closePicker?.(); } catch(_e) {}
    try { Wizard?.closeCoversDrawer?.(); } catch(_e) {}
    try { Wizard?.closePolicyAddedModal?.(); } catch(_e) {}
    try { Wizard?.closePolicyDiscountModal?.(); } catch(_e) {}
    try { Wizard?.closeOperationalReport?.(); } catch(_e) {}
    try { Wizard?.hideFinishFlow?.(); } catch(_e) {}

    [
      ["lcForgotModal", {}],
      ["lcUserModal", {}],
      ["customerFull", {}],
      ["customerPolicyModal", {}],
      ["lcArchiveCustomerModal", {}],
      ["lcPurgeArchivedCustomerModal", {}],
      ["lcClearCampaignLeadsModal", {}],
      ["lcInsPicker", {}],
      ["lcCoversDrawer", {}],
      ["lcPolicyAddedModal", {}],
      ["lcPolicyDiscountModal", {}],
      ["lcLeadShell", {}],
      ["lcReport", {}],
      ["lcFlow", { hideStyle:true }],
    ].forEach(([id, cfg]) => closeById(id, cfg));

    try {
      document.querySelectorAll('.modal.is-open, .drawer.is-open, .lcWizard.is-open').forEach((el) => {
        const id = safeTrim(el.id);
        if(id && keepIds.has(id)) return;
        el.classList.remove('is-open', 'is-active', 'is-visible');
        if(el.classList.contains('lcFlow')) el.style.display = 'none';
        el.setAttribute('aria-hidden', 'true');
      });
    } catch(_e) {}

    releaseGlobalUiLocks();
  }

  function prepareInteractiveWizardOpen(){
    forceCloseUiLayers({ keepIds:["lcWizard"] });
    try {
      const wizard = document.getElementById("lcWizard");
      if(wizard){
        wizard.style.pointerEvents = "";
        wizard.removeAttribute("inert");
      }
      wizard?.querySelectorAll?.('input,select,textarea,button').forEach((el) => {
        el.disabled = false;
        el.readOnly = false;
      });
    } catch(_e) {}
  }

  // Visible error box (login)
  function showLoginError(msg){
    const box = $("#lcLoginError");
    if (box) box.textContent = msg ? String(msg) : "";
  }

  window.__GI_RUNTIME_ERRORS__ = Array.isArray(window.__GI_RUNTIME_ERRORS__) ? window.__GI_RUNTIME_ERRORS__ : [];
  window.addEventListener("error", (ev) => {
    try {
      window.__GI_RUNTIME_ERRORS__.push({ type:"error", at: nowISO(), message: String(ev?.message || ev?.error || "") });
      window.__GI_RUNTIME_ERRORS__ = window.__GI_RUNTIME_ERRORS__.slice(-10);
      console.error("GLOBAL_ERROR:", ev?.error || ev?.message || ev);
      if ($("#lcLogin") && document.body.classList.contains("lcAuthLock")) {
        if (!$("#lcLoginError")?.textContent) showLoginError("שגיאה במערכת. פתח קונסול (F12) לפרטים.");
      }
    } catch(_e) {}
  });
  window.addEventListener("unhandledrejection", (ev) => {
    try {
      window.__GI_RUNTIME_ERRORS__.push({ type:"promise", at: nowISO(), message: String(ev?.reason || "") });
      window.__GI_RUNTIME_ERRORS__ = window.__GI_RUNTIME_ERRORS__.slice(-10);
      console.error("UNHANDLED_REJECTION:", ev?.reason || ev);
      if ($("#lcLogin") && document.body.classList.contains("lcAuthLock")) {
        if (!$("#lcLoginError")?.textContent) showLoginError("שגיאה במערכת. פתח קונסול (F12) לפרטים.");
      }
    } catch(_e) {}
  });

  // ---------- Config / Local keys ----------
  const LS_SESSION_KEY = "GEMEL_SESSION_V1";
  const LS_BACKUP_KEY  = "GEMEL_STATE_BACKUP_V1"; // legacy only - Server Only mode clears and ignores it
  const LS_FAST_CACHE_KEY = "GEMEL_FAST_CACHE_V1"; // legacy only - Server Only mode clears and ignores it
  const LS_TABLE_CACHE_PREFIX = "GEMEL_TABLE_CACHE_V1_"; // legacy only - Server Only mode clears and ignores it
  const FAST_CACHE_MAX_AGE_MS = 1000 * 60 * 15;
  const GI_SERVER_CACHE_KEY = "GEMEL_SERVER_STATE_CACHE_V2";
  const GI_SERVER_CACHE_TTL_MS = 1000 * 60 * 5;
  const GI_NETWORK_TIMEOUT_MS = 12000;
  const GI_NETWORK_RETRY_COUNT = 2;
  const GI_NETWORK_RETRY_DELAY_MS = 900;
  const GI_WAVE3_INCR_OVERLAP_MS = 60000;
  const GI_META_READ_TIMEOUT_MS = 5000;

  function isWave3IncrementalEnabled(){
    try {
      const v = localStorage.getItem("GI_WAVE3_INCR");
      return v !== "0" && v !== "false";
    } catch(_e) { return true; }
  }

  // ---------- State ----------

  function normalizeUsersManagementAccess(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    return {
      pinHash: safeTrim(input.pinHash || input.hash),
      salt: safeTrim(input.salt),
      updatedAt: safeTrim(input.updatedAt || input.updated_at),
      updatedBy: safeTrim(input.updatedBy || input.updated_by)
    };
  }

  const SYSTEM_ADMIN_AGENT_NAMES = ["איתי סומך", "סוניה ארנשטיין"];

  function isSystemAdminAgentIdentity(agentLike = null){
    const name = safeTrim(agentLike?.name || agentLike?.username || Auth?.current?.name);
    return SYSTEM_ADMIN_AGENT_NAMES.includes(name);
  }

  function isOwnerIdentity(agentLike = null){
    const name = safeTrim(agentLike?.name || agentLike?.username || Auth?.current?.name);
    const secEmail = safeTrim(agentLike?.authEmail || agentLike?.email || getAgentSecurity?.(agentLike?.id)?.authEmail || "").toLowerCase();
    return name === "אוריה סומך" || secEmail === ADMIN_CONTACT_EMAIL.toLowerCase();
  }

  async function hashUsersGatePin(pin, salt){
    const clean = String(pin ?? '').replace(/\D+/g, '').slice(0, 6);
    const usedSalt = safeTrim(salt) || Math.random().toString(36).slice(2) + Date.now().toString(36);
    const source = `${usedSalt}:${clean}`;
    const subtle = window.crypto && window.crypto.subtle;
    if(!subtle) throw new Error('CRYPTO_NOT_AVAILABLE');
    const bytes = new TextEncoder().encode(source);
    const digest = await subtle.digest('SHA-256', bytes);
    const hash = Array.from(new Uint8Array(digest)).map((b) => b.toString(16).padStart(2, '0')).join('');
    return { hash, salt: usedSalt };
  }

  function getUsersManagementAccessConfig(){
    State.data.meta = State.data.meta && typeof State.data.meta === 'object' ? State.data.meta : {};
    State.data.meta.usersManagementAccess = normalizeUsersManagementAccess(State.data.meta.usersManagementAccess);
    return State.data.meta.usersManagementAccess;
  }

  function hasUsersManagementPin(){
    const cfg = getUsersManagementAccessConfig();
    return !!(safeTrim(cfg.pinHash) && safeTrim(cfg.salt));
  }

  async function verifyUsersManagementPin(code){
    const clean = String(code ?? '').replace(/\D+/g, '').slice(0, 6);
    if(!clean) return { ok:false, error:'נא להזין קוד מורשה' };
    const cfg = getUsersManagementAccessConfig();
    if(hasUsersManagementPin()){
      const hashed = await hashUsersGatePin(clean, cfg.salt);
      if(hashed.hash === cfg.pinHash) return { ok:true, source:'usersManagementAccess' };
      return { ok:false, error:'קוד מורשה שגוי' };
    }
    const adminPin = safeTrim(State.data?.meta?.adminAuth?.pin);
    if(clean === adminPin) return { ok:true, source:'adminFallback' };
    return { ok:false, error:'קוד מורשה שגוי' };
  }

  const defaultState = () => ({
    meta: {
      updatedAt: null,
      adminAuth: { username: "מנהל מערכת", pin: "1234", active: true },
      opsEvents: [],
      chatAvatars: {},
      auditLog: [],
      revision: { stateVersion: 0, updatedAt: null, updatedBy: "", sessionId: "" },
      usersManagementAccess: { pinHash:"", salt:"", updatedAt:null, updatedBy:"" },
      agentsShadow: [],
      customersShadow: [],
      proposalsShadow: [],
      archivedCustomers: [],
      elementaryReferrals: [],
      deletedElementaryReferralIds: [],
      proposalAssignInbox: [],
      campaignLeadAssignInbox: [],
      companyDiscountOverrides: {},
      campaignLines: [],
      landingLeadIngest: {
        campaignId: "cmp_health_risk_landing",
        campaignLabel: "ביטוחי בריאות וסיכונים — דף נחיתה",
        autoAssignEnabled: false,
        autoAssignAgentId: "",
        autoAssignAgentName: ""
      },
      teamManagerAssignments: {},
      teamManagerAssignmentsUpdatedAt: null,
      agentReportAliases: {},
      agentReportAliasesUpdatedAt: null,
      dataUpdatedAt: null,
      referralsUpdatedAt: null,
      campaignInboxUpdatedAt: null,
      proposalInboxUpdatedAt: null,
      settingsUpdatedAt: null
    },
    agents: [
      { id:"a_0", name:"יובל מנדלסון", username:"יובל מנדלסון", pin:"0000", birthDate:"", active:true }
    ],
    customers: [],
    proposals: []
  });

  const State = {
    data: defaultState()
  };

  function normalizeState(s){
    const base = defaultState();
    const out = {
      meta: { ...(s?.meta || {}) },
      agents: Array.isArray(s?.agents) ? s.agents : base.agents,
      customers: Array.isArray(s?.customers) ? s.customers : [],
      proposals: Array.isArray(s?.proposals) ? s.proposals : []
    };

    const defAdmin = base.meta.adminAuth;
    const rawAdmin = out.meta.adminAuth || {};
    out.meta.adminAuth = {
      username: safeTrim(rawAdmin.username) || defAdmin.username,
      pin: safeTrim(rawAdmin.pin) || defAdmin.pin,
      active: (rawAdmin.active === false) ? false : true
    };

    out.agents = (out.agents || []).map((a, idx) => normalizeAgentRecord(a, idx)).filter(a => safeTrim(a?.name));
    out.meta.teamManagerAssignments = normalizeTeamManagerAssignmentsMap(out.meta.teamManagerAssignments);
    // BUG-FIX: reconcile from agent rows BEFORE applying map — otherwise an empty/stale
    // teamManagerAssignments map wipes team_manager_id loaded from the agents table.
    reconcileTeamManagerAssignmentsFromAgents(out);
    applyTeamManagerAssignmentsToAgents(out);

    if (!out.agents.length) out.agents = base.agents;
    out.customers = (out.customers || []).map((c, idx) => normalizeCustomerRecord(c, idx)).filter(Boolean);
    out.customers = out.customers.filter((c) => !isServerArchivedCustomerRecord(c));
    out.proposals = (out.proposals || []).map((p, idx) => normalizeProposalRecord(p, idx)).filter(Boolean);
    out.meta.opsEvents = Array.isArray(out.meta.opsEvents) ? out.meta.opsEvents.map((ev, idx) => normalizeOpsEvent(ev, idx)).filter(Boolean) : [];
    out.meta.chatAvatars = normalizeChatAvatarMap(out.meta.chatAvatars);
    out.meta.auditLog = normalizeAuditLogList(out.meta.auditLog);
    out.meta.revision = normalizeRevisionMeta(out.meta.revision, out.meta.updatedAt);
    out.meta.usersManagementAccess = normalizeUsersManagementAccess(out.meta.usersManagementAccess);
    out.meta.archivedCustomers = normalizeArchivedCustomersList(out.meta.archivedCustomers || []);
    out.meta.elementaryReferrals = (Array.isArray(out.meta.elementaryReferrals) ? out.meta.elementaryReferrals : [])
      .map((row, idx) => normalizeElementaryReferral(row, idx))
      .filter(Boolean);
    out.meta.deletedElementaryReferralIds = normalizeDeletedElementaryReferralIds(out.meta.deletedElementaryReferralIds);
    const deletedReferralIds = new Set(out.meta.deletedElementaryReferralIds);
    if(deletedReferralIds.size){
      out.meta.elementaryReferrals = out.meta.elementaryReferrals.filter((row) => !deletedReferralIds.has(String(row.id)));
    }
    out.meta.proposalAssignInbox = normalizeProposalAssignInboxList(out.meta.proposalAssignInbox);
    out.meta.campaignLeadAssignInbox = normalizeCampaignLeadAssignInboxList(out.meta.campaignLeadAssignInbox);
    out.meta.updatedAt = safeTrim(out.meta.updatedAt) || safeTrim(out.meta.revision?.updatedAt) || nowISO();
    out.meta.revision = normalizeRevisionMeta(out.meta.revision, out.meta.updatedAt);
    Object.assign(out.meta, normalizeMetaSyncClocks(out.meta));
    // BUG-FIX: explicitly preserve agentTargets and agentSecurity through every normalizeState call.
    // Without this, code paths that reconstruct meta from a partial object lose these maps.
    if(typeof normalizeAgentTargetMap === 'function'){
      out.meta.agentTargets = normalizeAgentTargetMap(out.meta.agentTargets);
    }
    if(typeof normalizeAgentSecurityMap === 'function'){
      out.meta.agentSecurity = normalizeAgentSecurityMap(out.meta.agentSecurity);
    }
    out.meta.agentReportAliases = normalizeAgentReportAliasesMap(out.meta.agentReportAliases);
    if(!safeTrim(out.meta.agentReportAliasesUpdatedAt) && Object.keys(out.meta.agentReportAliases || {}).length){
      out.meta.agentReportAliasesUpdatedAt = safeTrim(out.meta.updatedAt) || nowISO();
    }
    out.meta.teamManagerAssignments = normalizeTeamManagerAssignmentsMap(out.meta.teamManagerAssignments);
    if(!safeTrim(out.meta.teamManagerAssignmentsUpdatedAt) && Object.keys(out.meta.teamManagerAssignments || {}).length){
      out.meta.teamManagerAssignmentsUpdatedAt = safeTrim(out.meta.updatedAt) || nowISO();
    }
    out.meta.companyDiscountOverrides = normalizeCompanyDiscountOverrides(out.meta.companyDiscountOverrides);
    out.meta.campaignLines = normalizeCampaignLineList(out.meta.campaignLines);
    out.meta.landingLeadIngest = normalizeLandingLeadIngestConfig(out.meta.landingLeadIngest);
    out.meta.agentNameHistory = normalizeAgentNameHistoryMap(out.meta.agentNameHistory);
    enrichStateAgentOwnership(out);
    reconcileAllAgentOwnershipInState(out);
    return out;
  }


  function normalizeAuditLogEntry(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    return {
      id: safeTrim(input.id) || ("audit_" + Math.random().toString(16).slice(2) + "_" + Date.now().toString(16)),
      type: safeTrim(input.type) || "save",
      entity: safeTrim(input.entity) || "state",
      entityId: safeTrim(input.entityId || input.idRef),
      label: safeTrim(input.label || input.message),
      actorId: safeTrim(input.actorId || input.userId || Auth?.current?.id),
      actorName: safeTrim(input.actorName || input.userName || Auth?.current?.name || "מערכת"),
      sessionId: safeTrim(input.sessionId) || APP_SESSION_ID,
      at: safeTrim(input.at || input.createdAt || input.updatedAt) || nowISO(),
      details: input.details && typeof input.details === "object" ? input.details : {}
    };
  }

  function normalizeAuditLogList(raw){
    return (Array.isArray(raw) ? raw : []).map((entry) => normalizeAuditLogEntry(entry)).filter(Boolean)
      .sort((a,b) => new Date(a.at || 0) - new Date(b.at || 0))
      .slice(-400);
  }

  function cloneCustomerRecordDeep(rec){
    try {
      if(typeof structuredClone === "function") return structuredClone(rec);
    } catch(_e){}
    try { return JSON.parse(JSON.stringify(rec)); } catch(_e){}
    return rec && typeof rec === "object" ? { ...rec } : rec;
  }

  function normalizeArchivedCustomerEntry(raw, idx){
    const input = raw && typeof raw === "object" ? raw : {};
    const custRaw = input.customer;
    if(!custRaw || typeof custRaw !== "object") return null;
    const customer = normalizeCustomerRecord(custRaw, idx);
    if(!customer || !safeTrim(customer.id)) return null;
    return {
      id: safeTrim(customer.id),
      archivedAt: safeTrim(input.archivedAt) || nowISO(),
      archivedBy: safeTrim(input.archivedBy),
      customer
    };
  }

  function mergeArchivedCustomerLists(serverList, localList){
    const map = new Map();
    const ingest = (entry, fallbackIdx) => {
      const n = normalizeArchivedCustomerEntry(entry, fallbackIdx);
      if(!n?.id) return;
      const prev = map.get(n.id);
      if(!prev || compareIsoStamps(n.archivedAt, prev.archivedAt) >= 0) map.set(n.id, n);
    };
    (Array.isArray(serverList) ? serverList : []).forEach((e, i) => ingest(e, i));
    (Array.isArray(localList) ? localList : []).forEach((e, i) => ingest(e, i));
    return Array.from(map.values()).sort((a, b) => compareIsoStamps(b.archivedAt, a.archivedAt));
  }

  function normalizeArchivedCustomersList(raw){
    return mergeArchivedCustomerLists([], Array.isArray(raw) ? raw : []);
  }

  function normalizeRevisionMeta(raw, fallbackUpdatedAt = ""){
    const input = raw && typeof raw === "object" ? raw : {};
    const stateVersion = Math.max(0, Number(input.stateVersion || input.version || 0) || 0);
    return {
      stateVersion,
      updatedAt: safeTrim(input.updatedAt || input.updated_at) || safeTrim(fallbackUpdatedAt) || nowISO(),
      updatedBy: safeTrim(input.updatedBy || input.updated_by),
      sessionId: safeTrim(input.sessionId || input.session_id)
    };
  }

  function appendAuditLog(entry = {}){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const log = normalizeAuditLogList(State.data.meta.auditLog);
    log.push(normalizeAuditLogEntry(entry));
    State.data.meta.auditLog = normalizeAuditLogList(log);
    return State.data.meta.auditLog;
  }

  function getRecordStamp(rec){
    return safeTrim(rec?.updatedAt || rec?.updated_at || rec?.createdAt || rec?.created_at || "");
  }

  function compareIsoStamps(a, b){
    const ta = Date.parse(safeTrim(a) || "") || 0;
    const tb = Date.parse(safeTrim(b) || "") || 0;
    if(ta === tb) return 0;
    return ta > tb ? 1 : -1;
  }

  function mergeNormalizedEntities(listA, listB, normalizer){
    const first = Array.isArray(listA) ? listA.map((item, idx) => normalizer(item, idx)).filter(Boolean) : [];
    const second = Array.isArray(listB) ? listB.map((item, idx) => normalizer(item, idx)).filter(Boolean) : [];
    return mergeEntityArraysByRecency(first, second);
  }

  function refreshStateShadows(options = {}){
    if(options.skipNormalize !== true){
      State.data = normalizeState(State.data);
    }
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    State.data.meta.agentsShadow = mergeNormalizedEntities(State.data.agents, State.data.meta.agentsShadow, normalizeAgentRecord);
    if(options.lightShadows !== true){
      State.data.meta.customersShadow = mergeNormalizedEntities(State.data.customers, State.data.meta.customersShadow, normalizeCustomerRecord);
      State.data.meta.proposalsShadow = mergeNormalizedEntities(State.data.proposals, State.data.meta.proposalsShadow, normalizeProposalRecord);
    }
    return State.data.meta;
  }

  function mergeMetaObjects(localMeta, serverMeta, options = {}){
    const local = localMeta && typeof localMeta === "object" ? localMeta : {};
    const server = serverMeta && typeof serverMeta === "object" ? serverMeta : {};
    const preferredUpdatedAt = compareIsoStamps(local.updatedAt, server.updatedAt) >= 0 ? safeTrim(local.updatedAt) : safeTrim(server.updatedAt);
    // Merge agentSecurity: combine server + local, prefer entry with newer updatedAt per agent
    const mergeAgentSecurityMaps = (srv, loc) => {
      const s = normalizeAgentSecurityMap(srv);
      const l = normalizeAgentSecurityMap(loc);
      const out = { ...s };
      Object.entries(l).forEach(([key, lEntry]) => {
        const sEntry = s[key];
        if(!sEntry || compareIsoStamps(lEntry.updatedAt, sEntry.updatedAt) >= 0){
          out[key] = lEntry;
        }
      });
      return out;
    };
    // Merge agentTargets: same strategy — combine server + local, prefer newer
    const mergeAgentTargetMaps = (srv, loc) => {
      const s = normalizeAgentTargetMap(srv);
      const l = normalizeAgentTargetMap(loc);
      const out = { ...s };
      Object.entries(l).forEach(([key, lEntry]) => {
        const sEntry = s[key];
        if(!sEntry || compareIsoStamps(lEntry.updatedAt, sEntry.updatedAt) >= 0){
          out[key] = lEntry;
        }
      });
      return out;
    };
    const merged = {
      ...server,
      ...local,
      adminAuth: { ...(server.adminAuth || {}), ...(local.adminAuth || {}) },
      usersManagementAccess: normalizeUsersManagementAccess(compareIsoStamps(local?.usersManagementAccess?.updatedAt, server?.usersManagementAccess?.updatedAt) >= 0 ? local.usersManagementAccess : server.usersManagementAccess),
      chatAvatars: { ...normalizeChatAvatarMap(server.chatAvatars), ...normalizeChatAvatarMap(local.chatAvatars) },
      auditLog: normalizeAuditLogList([...(Array.isArray(server.auditLog) ? server.auditLog : []), ...(Array.isArray(local.auditLog) ? local.auditLog : [])]),
      agentSecurity: mergeAgentSecurityMaps(server.agentSecurity, local.agentSecurity),
      agentTargets: mergeAgentTargetMaps(server.agentTargets, local.agentTargets),
      agentReportAliases: mergeAgentReportAliasesMapsByRecency(
        server.agentReportAliases,
        local.agentReportAliases,
        {
          localAt: safeTrim(local.agentReportAliasesUpdatedAt),
          remoteAt: safeTrim(server.agentReportAliasesUpdatedAt)
        }
      ),
      updatedAt: preferredUpdatedAt || nowISO()
    };
    merged.agentReportAliasesUpdatedAt = (() => {
      const localAt = safeTrim(local.agentReportAliasesUpdatedAt);
      const serverAt = safeTrim(server.agentReportAliasesUpdatedAt);
      if(localAt && serverAt){
        return compareIsoStamps(localAt, serverAt) >= 0 ? localAt : serverAt;
      }
      return localAt || serverAt || preferredUpdatedAt || nowISO();
    })();
    merged.opsEvents = (() => {
      const map = new Map();
      [...(Array.isArray(server.opsEvents) ? server.opsEvents : []), ...(Array.isArray(local.opsEvents) ? local.opsEvents : [])].forEach((ev, idx) => {
        const normalized = normalizeOpsEvent(ev, idx);
        if(!normalized) return;
        const key = safeTrim(normalized.id) || ("ops_" + idx);
        const existing = map.get(key);
        if(!existing || compareIsoStamps(normalized.updatedAt, existing.updatedAt) >= 0) map.set(key, normalized);
      });
      return Array.from(map.values());
    })();
    merged.archivedCustomers = mergeArchivedCustomerLists(
      Array.isArray(server.archivedCustomers) ? server.archivedCustomers : [],
      Array.isArray(local.archivedCustomers) ? local.archivedCustomers : []
    );
    merged.elementaryReferrals = mergeElementaryReferralsListsByRecency(
      Array.isArray(local.elementaryReferrals) ? local.elementaryReferrals : [],
      Array.isArray(server.elementaryReferrals) ? server.elementaryReferrals : []
    );
    merged.proposalAssignInbox = (() => {
      const map = new Map();
      [...(Array.isArray(server.proposalAssignInbox) ? server.proposalAssignInbox : []), ...(Array.isArray(local.proposalAssignInbox) ? local.proposalAssignInbox : [])].forEach((row, idx) => {
        const normalized = normalizeProposalAssignInboxEntry(row);
        const key = safeTrim(normalized.id) || ("pbinv_merge_" + idx);
        const existing = map.get(key);
        if(!existing || compareIsoStamps(normalized.at, existing.at) >= 0) map.set(key, normalized);
      });
      return normalizeProposalAssignInboxList(Array.from(map.values()));
    })();
    merged.campaignLeadAssignInbox = mergeCampaignLeadAssignInboxLists(
      local.campaignLeadAssignInbox,
      server.campaignLeadAssignInbox
    );
    merged.companyDiscountOverrides = (
      compareIsoStamps(server.updatedAt, local.updatedAt) > 0
        ? normalizeCompanyDiscountOverrides(server.companyDiscountOverrides)
        : normalizeCompanyDiscountOverrides(local.companyDiscountOverrides)
    );
    merged.teamManagerAssignments = mergeTeamManagerAssignmentsMaps(
      local.teamManagerAssignments,
      server.teamManagerAssignments,
      {
        localAt: safeTrim(local.teamManagerAssignmentsUpdatedAt),
        remoteAt: safeTrim(server.teamManagerAssignmentsUpdatedAt)
      }
    );
    merged.teamManagerAssignmentsUpdatedAt = (() => {
      const localTmaAt = safeTrim(local.teamManagerAssignmentsUpdatedAt);
      const serverTmaAt = safeTrim(server.teamManagerAssignmentsUpdatedAt);
      if(localTmaAt && serverTmaAt){
        return compareIsoStamps(localTmaAt, serverTmaAt) >= 0 ? localTmaAt : serverTmaAt;
      }
      return localTmaAt || serverTmaAt || preferredUpdatedAt || nowISO();
    })();
    const serverRevision = normalizeRevisionMeta(server.revision, server.updatedAt);
    const localRevision = normalizeRevisionMeta(local.revision, local.updatedAt);
    const nextVersion = Math.max(serverRevision.stateVersion, localRevision.stateVersion) + (options.bumpRevision === false ? 0 : 1);
    merged.revision = normalizeRevisionMeta({
      stateVersion: nextVersion,
      updatedAt: merged.updatedAt,
      updatedBy: safeTrim(Auth?.current?.name || localRevision.updatedBy || serverRevision.updatedBy),
      sessionId: APP_SESSION_ID
    }, merged.updatedAt);
    return merged;
  }

  function mergeEntityArraysByRecency(localRows = [], serverRows = []){
    const map = new Map();
    const ingest = (row) => {
      if(!row || typeof row !== "object") return;
      const id = safeTrim(row.id);
      if(!id) return;
      const prev = map.get(id);
      if(!prev){
        map.set(id, row);
        return;
      }
      const stampCmp = compareIsoStamps(getRecordStamp(row), getRecordStamp(prev));
      if(stampCmp > 0){
        map.set(id, row);
        return;
      }
      if(stampCmp === 0){
        const rowKeys = Object.keys(row || {}).length;
        const prevKeys = Object.keys(prev || {}).length;
        if(rowKeys >= prevKeys) map.set(id, row);
      }
    };
    (Array.isArray(serverRows) ? serverRows : []).forEach(ingest);
    (Array.isArray(localRows) ? localRows : []).forEach(ingest);
    return Array.from(map.values());
  }

  /** טבלת agents + agentsShadow ב-meta — מיזוג לפי עדכון אחרון (תיקון נציגים שנשמרו ב-meta בלבד). */
  function mergeAgentsTableWithMetaShadow(tableAgents = [], meta = {}){
    const fromTable = (Array.isArray(tableAgents) ? tableAgents : []).map((row, idx) => normalizeAgentRecord(row, idx)).filter((a) => safeTrim(a?.name));
    const shadow = Array.isArray(meta?.agentsShadow) ? meta.agentsShadow : [];
    const fromShadow = shadow.map((row, idx) => normalizeAgentRecord({
      id: row?.id,
      name: row?.name,
      username: row?.username,
      pin: row?.pin,
      birthDate: row?.birthDate || row?.birth_date,
      email: row?.email,
      monthlySalesTarget: row?.monthlySalesTarget ?? row?.monthly_sales_target,
      role: row?.role,
      teamManagerId: row?.teamManagerId || row?.team_manager_id,
      active: row?.active,
      createdAt: row?.createdAt || row?.created_at,
      updatedAt: row?.updatedAt || row?.updated_at
    }, idx)).filter((a) => safeTrim(a?.name));
    const merged = mergeEntityArraysByRecency(fromShadow, fromTable);
    const shadowMap = new Map(fromShadow.map((a) => [safeTrim(a?.id), a]));
    const tmaMap = normalizeTeamManagerAssignmentsMap(meta?.teamManagerAssignments);
    return merged.map((agent) => {
      const id = safeTrim(agent?.id);
      const shadowAgent = shadowMap.get(id);
      let next = agent;
      if(agent.role === "agent" && shadowAgent && shadowAgent.role && shadowAgent.role !== "agent"){
        next = { ...next, role: shadowAgent.role };
      }
      let teamManagerId = safeTrim(next.teamManagerId);
      if(!teamManagerId && shadowAgent) teamManagerId = safeTrim(shadowAgent.teamManagerId);
      if(!teamManagerId && id){
        Object.entries(tmaMap).some(([mgrId, ids]) => {
          if(!Array.isArray(ids) || !ids.some((aid) => String(aid) === String(id))) return false;
          teamManagerId = safeTrim(mgrId);
          return true;
        });
      }
      if(teamManagerId && teamManagerId !== safeTrim(next.teamManagerId)){
        next = { ...next, teamManagerId };
      }
      return next;
    });
  }

  function buildSafeMergedState(localState, serverState, options = {}){
    const local = normalizeState(localState || defaultState());
    const server = normalizeState(serverState || defaultState());
    return normalizeState({
      meta: mergeMetaObjects(local.meta, server.meta, options),
      agents: mergeEntityArraysByRecency(local.agents, server.agents),
      customers: mergeEntityArraysByRecency(local.customers, server.customers),
      proposals: mergeEntityArraysByRecency(local.proposals, server.proposals)
    });
  }

  function normalizeChatAvatarMap(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    const out = {};
    Object.entries(input).forEach(([key, value]) => {
      const entry = value && typeof value === "object" ? value : {};
      const image = safeTrim(entry.image || entry.url || entry.dataUrl);
      if(!key || !image) return;
      out[String(key)] = {
        image,
        updatedAt: safeTrim(entry.updatedAt) || nowISO()
      };
    });
    return out;
  }

  function getChatAvatarMap(){
    return normalizeChatAvatarMap(State?.data?.meta?.chatAvatars);
  }

  function getChatAvatarEntry(userId){
    const key = safeTrim(userId);
    if(!key) return null;
    const map = getChatAvatarMap();
    return map[key] || null;
  }

  /** שורת הנחה אחת — תואם לאובייקטים ב־Wizard.COMPANY_DISCOUNT_OPTIONS */
  function normalizeDiscountOptionRow(raw){
    const o = raw && typeof raw === "object" ? raw : {};
    const pct = Number(String(o.pct ?? "0").replace(/[^\d.-]/g, "")) || 0;
    const yearsRaw = o.years;
    let years = null;
    if(yearsRaw !== null && yearsRaw !== undefined && yearsRaw !== ""){
      const n = Number(yearsRaw);
      if(!isNaN(n) && n > 0) years = Math.max(0, Math.min(40, n));
    }
    const out = {
      label: safeTrim(o.label) || "",
      pct,
      years
    };
    if(safeTrim(o.packageNum)) out.packageNum = String(o.packageNum);
    if(o.schedule != null && safeTrim(String(o.schedule))) out.schedule = String(o.schedule);
    if(o.isException) out.isException = true;
    if(o.requiresApproval) out.requiresApproval = true;
    return out;
  }

  /** מפה: חברה → סוג מוצר → מערך שורות הנחה (נשמר ב־meta לצד שרת) */
  function normalizeCompanyDiscountOverrides(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    const out = {};
    Object.keys(input).forEach((coKey) => {
      const c = safeTrim(coKey);
      if(!c) return;
      const inner = input[coKey];
      if(!inner || typeof inner !== "object") return;
      const pmap = {};
      Object.keys(inner).forEach((ptKey) => {
        const t = safeTrim(ptKey);
        if(!t) return;
        const arr = inner[ptKey];
        if(!Array.isArray(arr)) return;
        const rows = arr.map(normalizeDiscountOptionRow).filter((r) => safeTrim(r.label));
        pmap[t] = rows;
      });
      if(Object.keys(pmap).length) out[c] = pmap;
    });
    return out;
  }

  function setChatAvatarEntry(userId, image){
    const key = safeTrim(userId);
    if(!key) return null;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const map = getChatAvatarMap();
    const cleanImage = safeTrim(image);
    if(cleanImage){
      map[key] = { image: cleanImage, updatedAt: nowISO() };
    } else {
      delete map[key];
    }
    State.data.meta.chatAvatars = map;
    State.data.meta.updatedAt = nowISO();
    return map[key] || null;
  }



  function parseFlexibleBirthDate(value){
    const raw = safeTrim(value);
    if(!raw) return null;
    let m = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if(m) return { year:Number(m[1]), month:Number(m[2]), day:Number(m[3]) };
    m = raw.match(/^(\d{2})[\/.\-](\d{2})[\/.\-](\d{4})$/);
    if(m) return { day:Number(m[1]), month:Number(m[2]), year:Number(m[3]) };
    m = raw.match(/^(\d{2})[\/.\-](\d{2})[\/.\-](\d{2})$/);
    if(m) return { day:Number(m[1]), month:Number(m[2]), year:2000 + Number(m[3]) };
    return null;
  }

  function formatBirthDateDisplay(value){
    const p = parseFlexibleBirthDate(value);
    if(!p) return '—';
    return `${String(p.day).padStart(2,'0')}/${String(p.month).padStart(2,'0')}/${String(p.year).padStart(4,'0')}`;
  }

  function formatDmyFromDigits(value){
    const clean = String(value ?? '').replace(/\D+/g, '').slice(0, 8);
    if(!clean) return "";
    let out = clean.slice(0, 2);
    if(clean.length > 2) out += "/" + clean.slice(2, 4);
    if(clean.length > 4) out += "/" + clean.slice(4, 8);
    return out;
  }

  function applyDmyAutoFormat(el){
    if(!el) return "";
    const raw = String(el.value ?? "");
    const start = Number.isFinite(el.selectionStart) ? el.selectionStart : raw.length;
    const digitsBeforeCursor = raw.slice(0, start).replace(/\D+/g, '').length;
    const formatted = formatDmyFromDigits(raw);
    if(raw !== formatted) el.value = formatted;

    let cursor = formatted.length;
    if(digitsBeforeCursor <= 0){
      cursor = 0;
    } else {
      let seenDigits = 0;
      for(let i = 0; i < formatted.length; i += 1){
        if(/\d/.test(formatted[i])) seenDigits += 1;
        if(seenDigits >= digitsBeforeCursor){
          cursor = i + 1;
          break;
        }
      }
    }
    try { el.setSelectionRange(cursor, cursor); } catch(_e) {}
    return formatted;
  }

  /** תאריך DD/MM/YYYY או YYYY-MM-DD או 8 ספרות רצופות DDMMyyyy — ללא מגבלת עתיד (לוח שנה / ביטוח) */
  function parseAnyDmyDate(value){
    const s = safeTrim(value);
    if(!s) return null;
    let y = null, m = null, d = null;
    let hit = /^(\d{4})-(\d{2})-(\d{2})$/.exec(s);
    if(hit){
      y = Number(hit[1]);
      m = Number(hit[2]);
      d = Number(hit[3]);
    } else {
      hit = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s);
      if(hit){
        d = Number(hit[1]);
        m = Number(hit[2]);
        y = Number(hit[3]);
      }
    }
    if(!y || !m || !d){
      const dig = s.replace(/\D+/g, "");
      if(dig.length === 8){
        d = Number(dig.slice(0, 2));
        m = Number(dig.slice(2, 4));
        y = Number(dig.slice(4, 8));
      }
    }
    if(!y || !m || !d) return null;
    if(m < 1 || m > 12 || d < 1 || d > 31) return null;
    const dt = new Date(y, m - 1, d);
    if(Number.isNaN(dt.getTime())) return null;
    if(dt.getFullYear() !== y || dt.getMonth() !== (m - 1) || dt.getDate() !== d) return null;
    return { year:y, month:m, day:d, date:dt };
  }

  function parseBirthDateValue(value){
    const p = parseAnyDmyDate(value);
    if(!p) return null;
    const today = new Date();
    if(p.date > today) return null;
    return { year:p.year, month:p.month, day:p.day, date:p.date };
  }

  function formatDmyFromParts(y, m, d){
    return `${String(d).padStart(2, "0")}/${String(m).padStart(2, "0")}/${String(y).padStart(4, "0")}`;
  }

  function elementaryLicenseIssueYearMin(){
    return 1950;
  }

  function elementaryLicenseIssueYearMax(){
    return new Date().getFullYear();
  }

  /** שנה בלבד או תאריך מלא ישן (תאימות לאחור) → YYYY */
  function elementaryLicenseIssueYearFromStored(raw){
    const s = safeTrim(raw);
    if(!s) return "";
    const dig = digitsOnly(s);
    if(dig.length === 4) return dig;
    const p = parseBirthDateValue(s);
    if(p && p.year) return String(p.year);
    return "";
  }

  function normalizeElementaryLicenseIssueYearInput(raw){
    return digitsOnly(safeTrim(raw)).slice(0, 4);
  }

  function isElementaryLicenseIssueYearValid(raw){
    const y = elementaryLicenseIssueYearFromStored(raw);
    if(!y || y.length !== 4) return false;
    const n = parseInt(y, 10);
    return Number.isFinite(n) && n >= elementaryLicenseIssueYearMin() && n <= elementaryLicenseIssueYearMax();
  }

  /** JSONP ל־services.israelpost.co.il/zip_data.nsf (מנגנון כמו באתר locatezip של דואר ישראל) */
  function israelPostZipDataJsonp(pathAfterNsf){
    return new Promise((resolve, reject) => {
      const cb = "_ipJp_" + Math.random().toString(36).slice(2, 10) + "_" + Date.now().toString(36);
      let finished = false;
      const cleanup = () => {
        if(finished) return;
        finished = true;
        try{ delete window[cb]; }catch(_e){}
        try{ scr.remove(); }catch(_e){}
      };
      const tmr = window.setTimeout(() => {
        cleanup();
        reject(new Error("ip-timeout"));
      }, 14000);
      window[cb] = (payload) => {
        window.clearTimeout(tmr);
        cleanup();
        resolve(payload);
      };
      const scr = document.createElement("script");
      scr.async = true;
      const base = "https://services.israelpost.co.il/zip_data.nsf/";
      const join = pathAfterNsf.includes("?") ? "&" : "?";
      scr.src = base + pathAfterNsf + join + "callback=" + encodeURIComponent(cb);
      scr.onerror = () => {
        window.clearTimeout(tmr);
        cleanup();
        reject(new Error("ip-load"));
      };
      document.head.appendChild(scr);
    });
  }

  /** מחלץ שמות ממבנה JSONP של דואר (locations / streets וכו׳) */
  function extractIsraelPostNameList(payload){
    const out = [];
    const take = (arr) => {
      if(!Array.isArray(arr)) return;
      arr.forEach((x) => {
        if(!x || typeof x !== "object") return;
        const n = safeTrim(x.n || x.N || x.name || x.Name || x.street || x.Street || "");
        if(n) out.push(n);
      });
    };
    take(payload?.locations);
    take(payload?.Locations);
    take(payload?.streets);
    take(payload?.Streets);
    return out;
  }

  function normalizeOpsEvent(ev, idx=0){
    if(!ev || typeof ev !== "object") return null;
    const range = ev.range && typeof ev.range === "object" ? ev.range : {};
    const reminder = ev.reminder && typeof ev.reminder === "object" ? ev.reminder : {};
    const title = safeTrim(ev.title) || "שיחת שיקוף ללקוח";
    const date = safeTrim(ev.date);
    const rangeStart = safeTrim(ev.rangeStart) || safeTrim(range.start);
    const rangeEnd = safeTrim(ev.rangeEnd) || safeTrim(range.end);
    const scheduledAt = safeTrim(ev.scheduledAt) || buildOpsEventDateTime(date, rangeStart);
    const reminderAt = safeTrim(ev.reminderAt) || shiftIsoMinutes(scheduledAt, -2);
    return {
      id: safeTrim(ev.id) || ("ops_event_" + idx + "_" + Math.random().toString(16).slice(2,8)),
      customerId: safeTrim(ev.customerId),
      customerName: safeTrim(ev.customerName) || "לקוח",
      customerPhone: safeTrim(ev.customerPhone),
      customerIdNumber: safeTrim(ev.customerIdNumber),
      title,
      notes: safeTrim(ev.notes),
      date,
      rangeStart,
      rangeEnd,
      range: { start: rangeStart, end: rangeEnd },
      scheduledAt,
      reminderAt,
      status: safeTrim(ev.status) || "scheduled",
      createdAt: safeTrim(ev.createdAt) || nowISO(),
      updatedAt: safeTrim(ev.updatedAt) || safeTrim(ev.createdAt) || nowISO(),
      createdByKey: safeTrim(ev.createdByKey),
      createdByName: safeTrim(ev.createdByName) || "נציג",
      acknowledgedAt: safeTrim(ev.acknowledgedAt),
      reminder: {
        offsetMinutes: Number(reminder.offsetMinutes || ev.reminderOffsetMinutes || 2) || 2,
        toastShownAt: safeTrim(reminder.toastShownAt) || safeTrim(ev.toastShownAt),
        acknowledgedAt: safeTrim(reminder.acknowledgedAt) || safeTrim(ev.acknowledgedAt)
      }
    };
  }

  function buildOpsEventDateTime(dateStr, timeStr){
    const d = safeTrim(dateStr);
    const t = safeTrim(timeStr);
    if(!d || !t) return "";
    return `${d}T${t}:00`;
  }

  function shiftIsoMinutes(isoStr, diffMinutes){
    const ms = Date.parse(isoStr || "");
    if(!Number.isFinite(ms)) return "";
    return new Date(ms + (Number(diffMinutes || 0) * 60000)).toISOString();
  }

  function formatOpsTime(timeStr){
    const value = safeTrim(timeStr);
    return value ? value.slice(0,5) : "—";
  }

  function formatOpsDateTime(isoStr){
    const ms = Date.parse(isoStr || "");
    if(!Number.isFinite(ms)) return "—";
    try {
      return new Intl.DateTimeFormat('he-IL', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' }).format(new Date(ms));
    } catch(_e) {
      return new Date(ms).toLocaleString('he-IL');
    }
  }

  function showHarBituachImportModal(options = {}){
    const policies = Array.isArray(options.policies) ? options.policies : [];
    const title = safeTrim(options.title) || `זוהו ${policies.length} פוליסות רלוונטיות לייבוא`;
    const note = safeTrim(options.note) || "ניתן להוסיף גם פוליסות ידנית.";
    const confirmText = safeTrim(options.confirmText) || "אישור";
    const cancelText = safeTrim(options.cancelText) || "ביטול";

    return new Promise((resolve) => {
      let settled = false;
      const existing = document.getElementById('lcHarImportModal');
      if(existing) existing.remove();

      const root = document.createElement('div');
      root.id = 'lcHarImportModal';
      root.className = 'lcHarImportModal';
      root.setAttribute('dir', 'rtl');
      root.innerHTML = `
        <div class="lcHarImportModal__backdrop"></div>
        <div class="lcHarImportModal__panel" role="dialog" aria-modal="true" aria-label="ייבוא מהר הביטוח">
          <button class="lcHarImportModal__close" type="button" aria-label="סגור">×</button>
          <div class="lcHarImportModal__hero">
            <div class="lcHarImportModal__iconWrap" aria-hidden="true">
              <div class="lcHarImportModal__scan"></div>
              <div class="lcHarImportModal__mountain"></div>
              <div class="lcHarImportModal__shield">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round">
                  <path d="M12 3l7 3v5c0 5-3.5 8.5-7 10-3.5-1.5-7-5-7-10V6l7-3z"></path>
                  <path d="M8.75 12.1l2.1 2.15 4.4-4.55"></path>
                </svg>
              </div>
            </div>
            <div class="lcHarImportModal__title">${escapeHtml(title)}</div>
            <div class="lcHarImportModal__note">${escapeHtml(note)}</div>
          </div>
          <div class="lcHarImportModal__listWrap">
            <div class="lcHarImportModal__listTitle">פוליסות שזוהו בקובץ</div>
            <ul class="lcHarImportModal__list">
              ${policies.slice(0, 12).map((p) => {
                const logo = renderCompanyLogoHtmlForCompany(p.company, "mini");
                return `<li class="lcHarImportModal__policyItem">${logo}<span><b>${escapeHtml(p.company || 'חברה')}</b> · ${escapeHtml(p.policyNumber || 'ללא מספר')} · ${escapeHtml(p.type || 'פוליסה')}</span></li>`;
              }).join('')}
              ${policies.length > 12 ? `<li>ועוד ${policies.length - 12} פוליסות נוספות…</li>` : ''}
            </ul>
          </div>
          <div class="lcHarImportModal__actions">
            <button class="btn" data-har-cancel type="button">${escapeHtml(cancelText)}</button>
            <button class="btn btn--primary" data-har-confirm type="button">${escapeHtml(confirmText)}</button>
          </div>
        </div>
      `;

      const close = (approved) => {
        if(settled) return;
        settled = true;
        root.classList.remove('is-open');
        root.classList.add('is-closing');
        window.setTimeout(() => {
          root.remove();
          resolve(!!approved);
        }, 220);
      };

      root.addEventListener('click', (ev) => {
        if(ev.target === root || ev.target.classList.contains('lcHarImportModal__backdrop')) close(false);
      });
      root.querySelector('[data-har-cancel]')?.addEventListener('click', () => close(false));
      root.querySelector('[data-har-confirm]')?.addEventListener('click', () => close(true));
      root.querySelector('.lcHarImportModal__close')?.addEventListener('click', () => close(false));
      document.addEventListener('keydown', function onKey(ev){
        if(!document.body.contains(root)) {
          document.removeEventListener('keydown', onKey);
          return;
        }
        if(ev.key === 'Escape'){
          document.removeEventListener('keydown', onKey);
          close(false);
        }
      });

      document.body.appendChild(root);
      window.requestAnimationFrame(() => root.classList.add('is-open'));
      window.setTimeout(() => root.classList.add('is-revealed'), 950);
    });
  }

  function showHarBituachProcessingModal(options = {}){
    const title = safeTrim(options.title) || 'מוריד נתוני הר הביטוח למערכת';
    const subtitle = safeTrim(options.subtitle) || 'מנתח את הקובץ ומכין את הפוליסות להצגה';
    const successTitle = safeTrim(options.successTitle) || 'בוצע בהצלחה';
    const successSubtitle = safeTrim(options.successSubtitle) || 'הנתונים הוכנו ומוצגים במערכת';
    const loadingMs = Math.max(500, Number(options.loadingMs) || 1200);
    const successMs = Math.max(450, Number(options.successMs) || 900);

    return new Promise((resolve) => {
      const existing = document.getElementById('lcHarProcessingModal');
      if(existing) existing.remove();
      const root = document.createElement('div');
      root.id = 'lcHarProcessingModal';
      root.className = 'lcHarProcessingModal';
      root.setAttribute('dir', 'rtl');
      root.innerHTML = `
        <div class="lcHarProcessingModal__backdrop"></div>
        <div class="lcHarProcessingModal__panel" role="status" aria-live="polite" aria-label="טעינת נתוני הר הביטוח">
          <div class="lcHarProcessingModal__glow" aria-hidden="true"></div>
          <div class="lcHarProcessingModal__badge">הר הביטוח</div>
          <div class="lcHarProcessingModal__orb" aria-hidden="true">
            <div class="lcHarProcessingModal__scanLine"></div>
            <div class="lcHarProcessingModal__mountain"></div>
            <div class="lcHarProcessingModal__shield">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round">
                <path d="M12 3l7 3v5c0 5-3.5 8.5-7 10-3.5-1.5-7-5-7-10V6l7-3z"></path>
                <path class="lcHarProcessingModal__checkPath" d="M8.75 12.1l2.1 2.15 4.4-4.55"></path>
              </svg>
            </div>
          </div>
          <div class="lcHarProcessingModal__title" data-stage-title>${escapeHtml(title)}</div>
          <div class="lcHarProcessingModal__subtitle" data-stage-subtitle>${escapeHtml(subtitle)}</div>
          <div class="lcHarProcessingModal__loader" data-stage-loader aria-hidden="true">
            <span></span><span></span><span></span>
          </div>
        </div>
      `;
      document.body.appendChild(root);
      const titleEl = root.querySelector('[data-stage-title]');
      const subtitleEl = root.querySelector('[data-stage-subtitle]');
      const loaderEl = root.querySelector('[data-stage-loader]');
      window.requestAnimationFrame(() => root.classList.add('is-open'));
      window.setTimeout(() => root.classList.add('is-loading'), 30);
      window.setTimeout(() => {
        root.classList.remove('is-loading');
        root.classList.add('is-success');
        if(titleEl) titleEl.textContent = successTitle;
        if(subtitleEl) subtitleEl.textContent = successSubtitle;
        if(loaderEl) loaderEl.style.display = 'none';
      }, loadingMs);
      window.setTimeout(() => {
        root.classList.remove('is-open', 'is-loading', 'is-success');
        root.classList.add('is-closing');
        window.setTimeout(() => {
          root.remove();
          resolve(true);
        }, 240);
      }, loadingMs + successMs);
    });
  }

  function showWizardHarAlertModal(options = {}){
    const title = safeTrim(options.title) || "שים לב";
    const text = safeTrim(options.text) || "";
    const confirmText = safeTrim(options.confirmText) || "הבנתי";
    const cancelText = safeTrim(options.cancelText);
    const showCancel = options.showCancel === true || !!cancelText;
    const showConfirm = options.showConfirm !== false;

    return new Promise((resolve) => {
      const existing = document.getElementById("giWizardHarAlertModal");
      if(existing) existing.remove();

      const modal = document.createElement("div");
      modal.id = "giWizardHarAlertModal";
      modal.className = "giValModal giWizardHarAlertModal";
      modal.setAttribute("role", "dialog");
      modal.setAttribute("aria-modal", "true");
      modal.setAttribute("aria-label", title);
      modal.setAttribute("dir", "rtl");
      modal.innerHTML = `
        <div class="giValModal__backdrop"></div>
        <div class="giValModal__card">
          <div class="giValModal__head">
            <span class="giValModal__headIcon" aria-hidden="true">⚠️</span>
            <div class="giValModal__headText">
              <div class="giValModal__title">${escapeHtml(title)}</div>
            </div>
          </div>
          <div class="giValModal__body">
            <p class="giWizardHarAlertModal__text">${escapeHtml(text)}</p>
          </div>
          <div class="giValModal__foot">
            ${showCancel ? `<button class="btn" type="button" data-har-alert-cancel>${escapeHtml(cancelText || "ביטול")}</button>` : ""}
            ${showConfirm ? `<button class="btn btn--primary giValModal__closeBtn" type="button" data-har-alert-confirm>${escapeHtml(confirmText)}</button>` : ""}
          </div>
        </div>
      `;

      const close = (result) => {
        modal.classList.add("giValModal--leaving");
        window.setTimeout(() => {
          modal.remove();
          resolve(result);
        }, 220);
      };

      modal.querySelector(".giValModal__backdrop")?.addEventListener("click", () => close(showCancel ? false : true));
      modal.querySelector("[data-har-alert-confirm]")?.addEventListener("click", () => close(true));
      modal.querySelector("[data-har-alert-cancel]")?.addEventListener("click", () => close(false));
      document.addEventListener("keydown", function onKey(ev){
        if(!document.body.contains(modal)){
          document.removeEventListener("keydown", onKey);
          return;
        }
        if(ev.key === "Escape"){
          document.removeEventListener("keydown", onKey);
          close(false);
        }
      });

      document.body.appendChild(modal);
      requestAnimationFrame(() => modal.classList.add("giValModal--visible"));
    });
  }


  function premiumCustomerIcon(name){
    const icons = {
      medical: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M12 21s-6.5-4.35-8.6-8.02C1.42 9.56 3.15 5.5 6.7 5.5c2.03 0 3.14 1.06 4.05 2.24.56.73 1.93.73 2.5 0 .9-1.18 2.01-2.24 4.04-2.24 3.56 0 5.3 4.06 3.3 7.48C18.5 16.65 12 21 12 21Z"></path><path d="M12 9v6"></path><path d="M9 12h6"></path></svg>',
      briefcase: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M8 7V6a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v1"></path><path d="M4.5 9.5h15a1.5 1.5 0 0 1 1.5 1.5v6a3 3 0 0 1-3 3H6a3 3 0 0 1-3-3v-6A1.5 1.5 0 0 1 4.5 9.5Z"></path><path d="M3 13h18"></path></svg>',
      building: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M4 20h16"></path><path d="M7 20V6.5A1.5 1.5 0 0 1 8.5 5h7A1.5 1.5 0 0 1 17 6.5V20"></path><path d="M10 9h1"></path><path d="M13 9h1"></path><path d="M10 12h1"></path><path d="M13 12h1"></path><path d="M11 20v-3h2v3"></path></svg>',
      folder: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M3.75 8.75a2 2 0 0 1 2-2h4.15l1.5 1.7h6.85a2 2 0 0 1 2 2v6.8a2 2 0 0 1-2 2H5.75a2 2 0 0 1-2-2v-8.5Z"></path><path d="M3.75 10.25h16.5"></path></svg>',
      activity: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M3 12h4l2.1-4.5L13 16l2.2-4H21"></path></svg>',
      document: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M8 4.75h6.5l4 4V18a2 2 0 0 1-2 2h-8a2 2 0 0 1-2-2V6.75a2 2 0 0 1 2-2Z"></path><path d="M14.5 4.75v4h4"></path><path d="M9 12h6"></path><path d="M9 15.5h6"></path></svg>',
      car: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M5 17h14"></path><path d="M6.5 17l1.2-4.2A2 2 0 0 1 9.6 11h4.8a2 2 0 0 1 1.9 1.3L17.5 17"></path><circle cx="7.5" cy="17.5" r="1.5"></circle><circle cx="16.5" cy="17.5" r="1.5"></circle><path d="M8 11l1.2-3h5.6L16 11"></path></svg>'
    };
    return `<span class="premiumMonoIcon premiumMonoIcon--${String(name || 'folder')}" aria-hidden="true">${icons[name] || icons.folder}</span>`;
  }

  function currentAgentIdentity(){
    const currentName = safeTrim(Auth?.current?.name);
    const currentRole = safeTrim(Auth?.current?.role) || 'agent';
    const found = findAgentRecordForSession();
    const idPart = safeTrim(found?.id) || safeTrim(Auth?.current?.id) || currentName || 'agent';
    const userPart = safeTrim(found?.username) || safeTrim(found?.name) || currentName || 'agent';
    return {
      key: `${idPart}__${userPart}`.toLowerCase().replace(/\s+/g, '_'),
      name: safeTrim(found?.name) || currentName || 'נציג',
      role: safeTrim(found?.role) || currentRole
    };
  }

  let _sessionAgentCacheSig = "";
  let _sessionAgentCache = null;
  function findAgentRecordForSession(){
    if(!Auth?.current) return null;
    const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
    const curName = safeTrim(Auth.current?.name);
    const curId = safeTrim(Auth.current?.id);
    const sig = curId + "|" + curName
      + "|" + safeTrim(State.data?.meta?.updatedAt)
      + "|" + safeTrim(State.data?.meta?.revision?.stateVersion);
    if(_sessionAgentCacheSig === sig) return _sessionAgentCache;
    const found = agents.find((a) =>
      (curId && safeTrim(a?.id) === curId)
      || safeTrim(a?.name) === curName
      || safeTrim(a?.username) === curName
    ) || null;
    _sessionAgentCacheSig = sig;
    _sessionAgentCache = found;
    return found;
  }

  function findAgentForLogin(username, agents = []){
    const label = safeTrim(username);
    if(!label) return { agent:null, error:"נא להזין שם משתמש" };
    const list = Array.isArray(agents) ? agents : [];
    const active = list.filter((a) => a?.active !== false);
    const byUsername = active.filter((a) => safeTrim(a?.username) === label);
    if(byUsername.length === 1) return { agent: byUsername[0], error:"" };
    const byName = active.filter((a) => safeTrim(a?.name) === label);
    if(byName.length === 1) return { agent: byName[0], error:"" };
    if(byUsername.length > 1) return { agent:null, error:"שם המשתמש לא חד-משמעי. פנה למנהל המערכת." };
    if(byName.length > 1) return { agent:null, error:"שם המשתמש לא חד-משמעי. פנה למנהל המערכת." };
    if(byUsername.length === 0 && byName.length === 0 && isAmbiguousSingleTokenAgentLabel(label)){
      const hint = active
        .filter((a) => {
          const tokens = agentLabelTokens(a?.name || a?.username);
          return tokens.length >= 2 && tokens[0] === normalizeAgentLabelToken(label);
        })
        .map((a) => safeTrim(a?.username) || safeTrim(a?.name))
        .filter(Boolean);
      if(hint.length){
        return { agent:null, error:"יש כמה נציגים עם השם הזה. היכנס עם שם המשתמש המלא, למשל: " + hint.join(" / ") };
      }
    }
    return { agent:null, error:"שם משתמש לא נמצא" };
  }

  function normalizeAgentLabelToken(value){
    return safeTrim(value)
      .replace(/[\u200e\u200f\u202a-\u202e\u2066-\u2069\ufeff]/g, "")
      .toLowerCase()
      .replace(/["'`׳״.,;:!?()[\]{}<>|\\/+\-_]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();
  }

  function agentLabelTokens(value){
    return normalizeAgentLabelToken(value).split(/\s+/).filter(Boolean);
  }

  const AGENT_LABEL_TOKEN_ALIASES = {
    "ודים": ["ואדים"],
    "ואדים": ["ודים"]
  };

  function agentLabelTokenMatches(candidate, token){
    if(candidate === token) return true;
    const aliases = AGENT_LABEL_TOKEN_ALIASES[token];
    if(aliases && aliases.includes(candidate)) return true;
    const reverse = AGENT_LABEL_TOKEN_ALIASES[candidate];
    return !!(reverse && reverse.includes(token));
  }

  function agentLabelTokensSubset(allTokens, partTokens){
    return partTokens.length > 0 && partTokens.every((token) =>
      allTokens.some((candidate) => agentLabelTokenMatches(candidate, token))
    );
  }

  function resolveAgentIdByLabel(agentLabel, agents = []){
    const label = safeTrim(agentLabel);
    if(!label) return "";
    const list = Array.isArray(agents) ? agents : [];
    for(const agent of list){
      if(agent?.active === false) continue;
      const profile = getAgentOwnershipProfileForAgent({
        id: safeTrim(agent?.id),
        name: safeTrim(agent?.name),
        username: safeTrim(agent?.username)
      });
      if(agentLabelMatchesProfile(label, profile)) return safeTrim(agent?.id);
    }
    return "";
  }

  function stampRecordAgentOwnership(record, options = {}){
    if(!record || typeof record !== "object") return record;
    record.payload = record.payload && typeof record.payload === "object" ? record.payload : {};
    const existingId = safeTrim(record.agentId) || safeTrim(record.payload.agentId);
    const existingName = safeTrim(record.agentName) || safeTrim(record.payload.agentName)
      || safeTrim(record.createdBy) || safeTrim(record.payload.createdBy);

    // Admin/manager/ops editing an existing record — preserve the owning agent.
    if(!options.force && Auth?.canViewAllCustomers?.() && (existingId || existingName)){
      if(existingId){
        record.agentId = existingId;
        record.payload.agentId = existingId;
      }
      if(existingName){
        record.agentName = existingName;
        record.createdBy = safeTrim(record.createdBy) || existingName;
        record.payload.agentName = safeTrim(record.payload.agentName) || existingName;
        record.payload.createdBy = safeTrim(record.payload.createdBy) || existingName;
      }
      const existingKey = safeTrim(record.payload.createdByKey) || safeTrim(record.createdByKey);
      if(existingKey) record.payload.createdByKey = existingKey;
      return record;
    }

    const identity = currentAgentIdentity();
    const agent = findAgentRecordForSession();
    const agentId = safeTrim(agent?.id) || safeTrim(Auth?.current?.id);
    const agentName = safeTrim(agent?.name) || safeTrim(identity?.name) || safeTrim(Auth?.current?.name);
    const createdByKey = safeTrim(identity?.key);
    if(agentId) record.agentId = agentId;
    if(agentName){
      record.agentName = safeTrim(record.agentName) || agentName;
      record.createdBy = safeTrim(record.createdBy) || agentName;
    }
    if(agentId) record.payload.agentId = agentId;
    if(agentName){
      record.payload.agentName = safeTrim(record.payload.agentName) || agentName;
      record.payload.createdBy = safeTrim(record.payload.createdBy) || agentName;
    }
    if(createdByKey) record.payload.createdByKey = createdByKey;
    return record;
  }

  function enrichRecordAgentOwnership(rec, agents = []){
    if(!rec || typeof rec !== "object") return rec;
    const list = Array.isArray(agents) ? agents : [];
    const payload = rec.payload && typeof rec.payload === "object" ? rec.payload : {};
    rec.payload = payload;
    const existingId = safeTrim(rec.agentId) || safeTrim(payload.agentId);
    if(existingId){
      rec.agentId = existingId;
      payload.agentId = existingId;
      return rec;
    }
    const label = safeTrim(rec.agentName) || safeTrim(rec.createdBy) || safeTrim(payload.agentName) || safeTrim(payload.createdBy);
    const resolvedId = resolveAgentIdByLabel(label, list);
    if(resolvedId){
      rec.agentId = resolvedId;
      payload.agentId = resolvedId;
      return rec;
    }
    const keyLabel = safeTrim(payload.createdByKey) || safeTrim(rec.createdByKey);
    if(keyLabel.includes("__")){
      const idGuess = safeTrim(keyLabel.split("__")[0]);
      if(idGuess && list.some((a) => String(safeTrim(a?.id)).toLowerCase() === idGuess.toLowerCase())){
        rec.agentId = idGuess;
        payload.agentId = idGuess;
      }
    }
    return rec;
  }

  function normalizeAgentNameHistoryMap(raw){
    const out = {};
    if(!raw || typeof raw !== "object") return out;
    Object.entries(raw).forEach(([agentId, names]) => {
      const id = safeTrim(agentId);
      if(!id) return;
      const list = Array.isArray(names) ? names.map(safeTrim).filter(Boolean) : [];
      if(list.length) out[id] = [...new Set(list)];
    });
    return out;
  }

  function getAgentNameHistory(agentId){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const map = normalizeAgentNameHistoryMap(State.data.meta.agentNameHistory);
    return map[safeTrim(agentId)] || [];
  }

  function rememberAgentNameHistory(agentId, names){
    const id = safeTrim(agentId);
    if(!id) return;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const map = normalizeAgentNameHistoryMap(State.data.meta.agentNameHistory);
    const prev = map[id] || [];
    const add = (Array.isArray(names) ? names : [names])
      .map(safeTrim)
      .filter(Boolean)
      .filter((name) => !isAmbiguousSingleTokenAgentLabel(name));
    map[id] = [...new Set([...prev, ...add])];
    State.data.meta.agentNameHistory = map;
  }

  // Report aliases: explicit, admin-entered extra labels used ONLY for matching
  // a daily-report "נציג" cell to an agent (e.g. an agent whose name in the system
  // is "זיו ג'הסי" but who appears in the report as "זיו עצמאי"). Stored in meta
  // alongside agentNameHistory/agentTargets so no agents-table schema change is needed.
  function normalizeAgentReportAliasesMap(raw){
    const out = {};
    if(raw && typeof raw === "object"){
      Object.keys(raw).forEach((k) => {
        const id = safeTrim(k);
        if(!id) return;
        const list = Array.isArray(raw[k]) ? raw[k] : [raw[k]];
        const clean = [...new Set(list.map(safeTrim).filter(Boolean))];
        if(clean.length) out[id] = clean;
      });
    }
    return out;
  }

  function getAgentReportAliases(agentId){
    const id = safeTrim(agentId);
    if(!id) return [];
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const map = normalizeAgentReportAliasesMap(State.data.meta.agentReportAliases);
    if(map[id]) return map[id];
    const lower = id.toLowerCase();
    for(const k of Object.keys(map)){
      if(k.toLowerCase() === lower) return map[k];
    }
    return [];
  }

  function setAgentReportAliases(agentId, names){
    const id = safeTrim(agentId);
    if(!id) return;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const map = normalizeAgentReportAliasesMap(State.data.meta.agentReportAliases);
    Object.keys(map).forEach((k) => { if(k.toLowerCase() === id.toLowerCase()) delete map[k]; });
    const clean = [...new Set((Array.isArray(names) ? names : [names]).map(safeTrim).filter(Boolean))];
    if(clean.length) map[id] = clean;
    State.data.meta.agentReportAliases = map;
    State.data.meta.agentReportAliasesUpdatedAt = nowISO();
    State.data.meta.updatedAt = nowISO();
    try { invalidateDailyReportMatchCaches(); } catch(_e) {}
  }

  function mergeAgentReportAliasesMapsByRecency(localMap, remoteMap, options = {}){
    const loc = normalizeAgentReportAliasesMap(localMap);
    const rem = normalizeAgentReportAliasesMap(remoteMap);
    const localAt = safeTrim(options.localAt);
    const remoteAt = safeTrim(options.remoteAt);
    if(localAt && remoteAt){
      const localNewer = compareIsoStamps(localAt, remoteAt) >= 0;
      const winner = localNewer ? loc : rem;
      const loser = localNewer ? rem : loc;
      return normalizeAgentReportAliasesMap({ ...loser, ...winner });
    }
    if(localAt && Object.keys(loc).length) return loc;
    if(remoteAt && Object.keys(rem).length) return rem;
    const out = { ...rem };
    Object.entries(loc).forEach(([agentId, names]) => {
      if(!Array.isArray(names) || !names.length) return;
      if(!Array.isArray(out[agentId]) || !out[agentId].length) out[agentId] = names.slice();
      else out[agentId] = [...new Set([...out[agentId], ...names])];
    });
    return normalizeAgentReportAliasesMap(out);
  }

  function parseAgentReportAliasesInput(value){
    return String(value == null ? "" : value)
      .split(/[\n,;]+/)
      .map(safeTrim)
      .filter(Boolean);
  }

  function bootstrapAgentNameHistoryFromLinkedRecords(stateRef){
    const state = stateRef || State.data;
    if(!state || typeof state !== "object") return;
    const agents = Array.isArray(state.agents) ? state.agents : [];
    const byId = new Map(agents.map((a) => [String(safeTrim(a?.id)), a]).filter(([id]) => id));
    const rememberLinkedNames = (rec, agentId) => {
      if(!rec || !agentId) return;
      [
        rec?.agentName,
        rec?.createdBy,
        rec?.payload?.agentName,
        rec?.payload?.createdBy
      ].forEach((value) => {
        const name = safeTrim(value);
        if(name) rememberAgentNameHistory(agentId, name);
      });
    };
    (Array.isArray(state.customers) ? state.customers : []).forEach((rec) => {
      const agentId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
      const key = safeTrim(rec?.payload?.createdByKey) || safeTrim(rec?.createdByKey);
      if(agentId && byId.has(String(agentId))){
        rememberLinkedNames(rec, agentId);
        return;
      }
      if(!key || !key.includes("__")) return;
      const idGuess = safeTrim(key.split("__")[0]);
      if(idGuess && byId.has(String(idGuess))) rememberLinkedNames(rec, idGuess);
    });
    (Array.isArray(state.proposals) ? state.proposals : []).forEach((rec) => {
      const agentId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
      const key = safeTrim(rec?.payload?.createdByKey) || safeTrim(rec?.createdByKey);
      if(agentId && byId.has(String(agentId))){
        rememberLinkedNames(rec, agentId);
        return;
      }
      if(!key || !key.includes("__")) return;
      const idGuess = safeTrim(key.split("__")[0]);
      if(idGuess && byId.has(String(idGuess))) rememberLinkedNames(rec, idGuess);
    });
  }

  function getAgentOwnershipProfileForAgent(agent, options = {}){
    const profile = getAgentOwnershipProfile({
      id: safeTrim(agent?.id),
      name: safeTrim(agent?.name),
      username: safeTrim(agent?.username),
      sessionName: safeTrim(options.sessionName) || safeTrim(agent?.name)
    });
    getAgentNameHistory(agent?.id).forEach((name) => {
      if(isAmbiguousSingleTokenAgentLabel(name)) return;
      const norm = normalizeAgentLabelToken(name);
      if(norm) profile.names.add(norm);
    });
    getAgentReportAliases(agent?.id).forEach((alias) => {
      const trimmed = safeTrim(alias);
      if(!trimmed) return;
      if(isAmbiguousSingleTokenAgentLabel(trimmed)) return;
      const norm = normalizeAgentLabelToken(trimmed);
      if(norm) profile.names.add(norm);
    });
    let authEmail = safeTrim(agent?.email);
    try {
      if(typeof resolveAgentAuthEmail === "function"){
        authEmail = resolveAgentAuthEmail(agent) || authEmail;
      }
    } catch(_e){}
    if(authEmail.includes("@")){
      normalizeAgentLabelToken(authEmail.split("@")[0]).split(/\s+/).filter(Boolean).forEach((token) => {
        if(token.length >= 3) profile.names.add(token);
      });
    }
    return profile;
  }

  function recordBelongsToAgent(rec, agent, options = {}){
    if(!rec || !agent) return false;
    const agentId = safeTrim(agent?.id);
    const recId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    if(agentId && recId){
      if(String(agentId) === String(recId)) return true;
      if(recordExplicitlyAssignedToOtherActiveAgent(rec, agentId)) return false;
    }
    const key = safeTrim(rec?.payload?.createdByKey) || safeTrim(rec?.createdByKey);
    if(agentId && key && key.toLowerCase().startsWith(String(agentId).toLowerCase() + "__")) return true;
    if(recordExplicitlyAssignedToOtherActiveAgent(rec, agentId)) return false;
    return recordOwnedByAgent(rec, getAgentOwnershipProfileForAgent(agent, options));
  }

  function stampAgentOwnershipOnRecord(rec, agent){
    if(!rec || !agent) return false;
    const agentId = safeTrim(agent?.id);
    const agentName = safeTrim(agent?.name) || safeTrim(agent?.username) || "נציג";
    if(!agentId) return false;
    const beforeId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    const beforeName = safeTrim(rec?.agentName);
    rec.agentId = agentId;
    rec.agentName = agentName;
    rec.createdBy = safeTrim(rec?.createdBy) || agentName;
    rec.payload = rec.payload && typeof rec.payload === "object" ? rec.payload : {};
    rec.payload.agentId = agentId;
    rec.payload.agentName = agentName;
    rec.payload.createdBy = safeTrim(rec.payload.createdBy) || agentName;
    const changed = beforeId !== agentId || beforeName !== agentName;
    if(changed){
      const touch = nowISO();
      rec.updatedAt = touch;
      rec.updated_at = touch;
    }
    return changed;
  }

  function reconcileAgentOwnershipForAgent(agent, options = {}){
    if(!agent || !safeTrim(agent?.id)) return { changed: 0, customers: 0, proposals: 0 };
    bootstrapAgentNameHistoryFromLinkedRecords(State.data);
    let changed = 0;
    let customers = 0;
    let proposals = 0;
    (Array.isArray(State.data?.customers) ? State.data.customers : []).forEach((rec) => {
      if(!recordBelongsToAgent(rec, agent, options)) return;
      if(stampAgentOwnershipOnRecord(rec, agent)){
        changed += 1;
        customers += 1;
      }
    });
    (Array.isArray(State.data?.proposals) ? State.data.proposals : []).forEach((rec) => {
      if(!recordBelongsToAgent(rec, agent, options)) return;
      if(stampAgentOwnershipOnRecord(rec, agent)){
        changed += 1;
        proposals += 1;
      }
    });
    return { changed, customers, proposals };
  }

  function reconcileAllAgentOwnershipInState(stateRef){
    const state = stateRef || State.data;
    if(!state || typeof state !== "object") return { changed: 0 };
    bootstrapAgentNameHistoryFromLinkedRecords(state);
    let changed = 0;
    (Array.isArray(state.agents) ? state.agents : []).forEach((agent) => {
      if(agent?.active === false) return;
      changed += reconcileAgentOwnershipForAgent(agent).changed;
    });
    return { changed };
  }

  function enrichStateAgentOwnership(state){
    const out = state && typeof state === "object" ? state : {};
    const agents = Array.isArray(out.agents) ? out.agents : [];
    if(Array.isArray(out.customers)){
      out.customers.forEach((rec) => enrichRecordAgentOwnership(rec, agents));
    }
    if(Array.isArray(out.proposals)){
      out.proposals.forEach((rec) => enrichRecordAgentOwnership(rec, agents));
    }
    return out;
  }

  function getAgentOwnershipProfile(agentContext){
    const ctx = agentContext && typeof agentContext === "object" ? agentContext : {};
    const names = new Set();
    const ids = new Set();
    const keys = new Set();
    const addName = (value) => {
      const trimmed = safeTrim(value);
      if(!trimmed) return;
      const tokens = agentLabelTokens(trimmed);
      if(tokens.length === 1 && isAmbiguousSingleTokenAgentLabel(trimmed)) return;
      const norm = normalizeAgentLabelToken(value);
      if(norm) names.add(norm);
    };
    addName(ctx.sessionName);
    addName(ctx.name);
    addName(ctx.username);
    const id = safeTrim(ctx.id);
    if(id) ids.add(String(id).toLowerCase());
    const idPart = id || safeTrim(ctx.name) || safeTrim(ctx.sessionName) || "agent";
    const userPart = safeTrim(ctx.username) || safeTrim(ctx.name) || safeTrim(ctx.sessionName) || "agent";
    keys.add(`${idPart}__${userPart}`.toLowerCase().replace(/\s+/g, "_"));
    return { names, ids, keys };
  }

  let _currentProfileCacheSig = "";
  let _currentProfileCache = null;
  function getCurrentAgentOwnershipProfile(){
    const sessionName = safeTrim(Auth?.current?.name);
    const curId = safeTrim(Auth?.current?.id);
    const sig = curId + "|" + sessionName
      + "|" + safeTrim(State.data?.meta?.updatedAt)
      + "|" + safeTrim(State.data?.meta?.revision?.stateVersion);
    if(_currentProfileCacheSig === sig && _currentProfileCache) return _currentProfileCache;
    const agent = findAgentRecordForSession();
    const profile = agent
      ? getAgentOwnershipProfileForAgent({
          ...agent,
          id: curId || safeTrim(agent?.id)
        }, { sessionName })
      : getAgentOwnershipProfile({
          sessionName,
          id: curId,
          name: sessionName,
          username: sessionName
        });
    _currentProfileCacheSig = sig;
    _currentProfileCache = profile;
    return profile;
  }

  function recordAgentNameCandidates(rec){
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    return [
      rec?.agentName,
      rec?.createdBy,
      payload?.createdBy,
      payload?.agentName,
      payload?.submittedBy
    ].map(safeTrim).filter(Boolean);
  }

  function recordAgentKeyCandidates(rec){
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    return [
      rec?.agentId,
      rec?.createdByKey,
      payload?.createdByKey,
      payload?.agentKey,
      payload?.agentId
    ].map((value) => safeTrim(value)).filter(Boolean).map((value) => String(value).toLowerCase());
  }

  function isAmbiguousSingleTokenAgentLabel(label){
    const tokens = agentLabelTokens(label);
    if(tokens.length !== 1) return false;
    const token = tokens[0];
    if(!token || token.length < 2) return true;
    const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
    let matches = 0;
    for(const agent of agents){
      if(agent?.active === false) continue;
      const candidates = [
        agent?.name,
        agent?.username
      ].map((v) => normalizeAgentLabelToken(v)).filter(Boolean);
      if(!candidates.length) continue;
      const hit = candidates.some((value) => {
        if(value === token) return true;
        const valueTokens = value.split(/\s+/).filter(Boolean);
        return valueTokens.some((t) => agentLabelTokenMatches(t, token));
      });
      if(hit){
        matches += 1;
        if(matches >= 2) return true;
      }
    }
    return false;
  }

  function recordExplicitlyAssignedToOtherActiveAgent(rec, sessionAgentId){
    const sid = safeTrim(sessionAgentId);
    if(!sid) return false;
    const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
    const isOtherActiveAgentId = (candidate) => {
      const cid = safeTrim(candidate);
      if(!cid || String(cid) === String(sid)) return false;
      return agents.some((a) => a?.active !== false && safeTrim(a?.id) === String(cid));
    };
    const recId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    if(isOtherActiveAgentId(recId)) return true;
    // createdByKey carries the true creator's agent id as its prefix ("<agentId>__<user>").
    // Honor it so a record created by another active agent is never claimed/leaked by name
    // alone (prevents e.g. "אביאל אלקיים" records being re-stamped onto "אביאל דהאן").
    const key = safeTrim(rec?.payload?.createdByKey) || safeTrim(rec?.createdByKey);
    if(key && key.includes("__")){
      const idFromKey = safeTrim(key.split("__")[0]);
      if(idFromKey && String(idFromKey) !== String(recId) && isOtherActiveAgentId(idFromKey)) return true;
    }
    return false;
  }

  function recordAgentNameMatchesOtherAgentExclusively(rec, sessionAgentId){
    const sid = safeTrim(sessionAgentId);
    if(!sid) return false;
    const recId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    // agent_id is authoritative — never second-guess a matching assignment by name alone.
    if(recId && String(recId) === String(sid)) return false;
    const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
    const sessionAgent = agents.find((a) => safeTrim(a?.id) === sid);
    if(!sessionAgent) return false;
    const names = recordAgentNameCandidates(rec);
    if(!names.length) return false;
    const sessionProfile = getAgentOwnershipProfileForAgent(sessionAgent);
    const matchesSession = names.some((name) => agentLabelMatchesProfile(name, sessionProfile));
    if(matchesSession) return false;
    return agents.some((agent) => {
      if(agent?.active === false) return false;
      const aid = safeTrim(agent?.id);
      if(!aid || aid === sid) return false;
      const profile = getAgentOwnershipProfileForAgent(agent);
      return names.some((name) => agentLabelMatchesProfile(name, profile));
    });
  }

  function agentLabelMatchesProfile(label, profile){
    const norm = normalizeAgentLabelToken(label);
    if(!norm || !profile?.names?.size) return false;
    if(profile.names.has(norm)) return true;
    const labelTokens = agentLabelTokens(label);
    if(!labelTokens.length) return false;
    for(const full of profile.names){
      const profileTokens = agentLabelTokens(full);
      if(!profileTokens.length) continue;
      // Never cross-match a lone first name against a fuller agent name (e.g. "אביאל" vs "אביאל דהן").
      if(labelTokens.length === 1 && profileTokens.length >= 2) continue;
      // Never match a multi-token record label to a single-token profile alias (e.g. "אביאל אלקיים" vs "אביאל").
      if(labelTokens.length >= 2 && profileTokens.length === 1) continue;
      if(profileTokens.length >= 2 && agentLabelTokensSubset(profileTokens, labelTokens)) return true;
      if(labelTokens.length >= 2 && profileTokens.length >= 2 && agentLabelTokensSubset(labelTokens, profileTokens)) return true;
      if(labelTokens.length >= 2 && profileTokens.length >= 2){
        let overlap = 0;
        for(const token of profileTokens){
          if(labelTokens.some((lt) => agentLabelTokenMatches(lt, token))) overlap += 1;
          if(overlap >= 2) return true;
        }
        continue;
      }
      if(labelTokens.length === 1 && profileTokens.length === 1){
        const token = labelTokens[0];
        if(token.length >= 3 && !isAmbiguousSingleTokenAgentLabel(token)
          && profileTokens.some((pt) => agentLabelTokenMatches(pt, token))) return true;
      }
    }
    return false;
  }

  function recordOwnedByAgent(rec, profile){
    if(!rec || !profile) return false;
    const recId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    if(recId){
      const rid = String(recId).toLowerCase();
      if(profile.ids?.has?.(rid)) return true;
      for(const id of profile.ids || []){
        if(String(id).toLowerCase() === rid) return true;
      }
    }
    for(const name of recordAgentNameCandidates(rec)){
      if(agentLabelMatchesProfile(name, profile)) return true;
    }
    const keyCandidates = recordAgentKeyCandidates(rec);
    if(!keyCandidates.length) return false;
    for(const key of keyCandidates){
      if(profile.keys?.has?.(key) || profile.ids?.has?.(key)) return true;
      for(const id of profile.ids || []){
        const idStr = String(id).toLowerCase();
        if(key === idStr || key.startsWith(idStr + "__")) return true;
      }
    }
    return false;
  }

  function customerOwnedByCurrentAgent(rec){
    if(!rec || !Auth?.current) return false;
    const agent = findAgentRecordForSession();
    const agentId = safeTrim(Auth?.current?.id) || safeTrim(agent?.id);
    const recId = safeTrim(rec?.agentId) || safeTrim(rec?.payload?.agentId);
    if(agentId && recId && String(agentId) === String(recId)) return true;
    const key = safeTrim(rec?.payload?.createdByKey) || safeTrim(rec?.createdByKey);
    if(agentId && key && key.toLowerCase().startsWith(String(agentId).toLowerCase() + "__")) return true;
    if((recId || key) && recordExplicitlyAssignedToOtherActiveAgent(rec, agentId)) return false;
    return recordOwnedByAgent(rec, getCurrentAgentOwnershipProfile());
  }

  function normalizeTeamManagerAssignmentsMap(raw){
    const out = {};
    if(!raw || typeof raw !== "object") return out;
    Object.entries(raw).forEach(([mgrId, ids]) => {
      const mid = safeTrim(mgrId);
      if(!mid) return;
      const list = Array.isArray(ids) ? ids.map((id) => safeTrim(id)).filter(Boolean) : [];
      if(list.length) out[mid] = [...new Set(list)];
    });
    return out;
  }

  function mergeTeamManagerAssignmentsMaps(localMap, remoteMap, options = {}){
    const loc = normalizeTeamManagerAssignmentsMap(localMap);
    const rem = normalizeTeamManagerAssignmentsMap(remoteMap);
    const localAt = safeTrim(options.localAt);
    const remoteAt = safeTrim(options.remoteAt);
    // BUG-FIX: use only teamManagerAssignmentsUpdatedAt (passed by callers).
    // Falling back to meta.updatedAt caused unrelated saves to overwrite team links.
    if(localAt && remoteAt){
      const localNewer = compareIsoStamps(localAt, remoteAt) >= 0;
      const winner = localNewer ? loc : rem;
      const loser = localNewer ? rem : loc;
      return normalizeTeamManagerAssignmentsMap({ ...loser, ...winner });
    }
    if(localAt && Object.keys(loc).length) return loc;
    if(remoteAt && Object.keys(rem).length) return rem;
    const out = { ...rem };
    Object.entries(loc).forEach(([mgrId, ids]) => {
      if(!Array.isArray(ids) || !ids.length) return;
      if(!Array.isArray(out[mgrId]) || !out[mgrId].length) out[mgrId] = ids.slice();
      else out[mgrId] = [...new Set([...out[mgrId], ...ids])];
    });
    return normalizeTeamManagerAssignmentsMap(out);
  }

  function hydrateTeamManagerLinksFromMeta(stateRef){
    const state = stateRef || State.data;
    if(!state || typeof state !== "object") return;
    reconcileTeamManagerAssignmentsFromAgents(state);
    applyTeamManagerAssignmentsToAgents(state);
  }

  function getTeamManagerAssignmentsMap(){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    return normalizeTeamManagerAssignmentsMap(State.data.meta.teamManagerAssignments);
  }

  function setTeamManagerAssignmentsMap(map){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    State.data.meta.teamManagerAssignments = normalizeTeamManagerAssignmentsMap(map);
    State.data.meta.teamManagerAssignmentsUpdatedAt = nowISO();
  }

  function syncAgentTeamManagerId(agentId, teamManagerId){
    const aid = safeTrim(agentId);
    if(!aid) return;
    const tid = safeTrim(teamManagerId);
    const map = getTeamManagerAssignmentsMap();
    Object.keys(map).forEach((mgrId) => {
      map[mgrId] = (map[mgrId] || []).filter((id) => String(id) !== String(aid));
      if(!map[mgrId].length) delete map[mgrId];
    });
    if(tid){
      map[tid] = map[tid] || [];
      if(!map[tid].includes(aid)) map[tid].push(aid);
    }
    setTeamManagerAssignmentsMap(map);
    const touchNow = nowISO();
    (Array.isArray(State.data?.agents) ? State.data.agents : []).forEach((a) => {
      if(safeTrim(a?.id) !== aid) return;
      const prevTid = safeTrim(a.teamManagerId);
      if(tid) a.teamManagerId = tid;
      else delete a.teamManagerId;
      if(String(prevTid) !== String(tid || "")){
        a.updatedAt = touchNow;
        a.updated_at = touchNow;
      }
    });
  }

  function setTeamManagerAgentIds(managerId, agentIds){
    const mid = safeTrim(managerId);
    if(!mid) return;
    const map = getTeamManagerAssignmentsMap();
    const prev = new Set((map[mid] || []).map(String));
    const next = new Set((Array.isArray(agentIds) ? agentIds : []).map((id) => safeTrim(id)).filter(Boolean));
    Object.keys(map).forEach((otherMgr) => {
      if(otherMgr === mid) return;
      map[otherMgr] = (map[otherMgr] || []).filter((id) => !next.has(String(id)));
      if(!map[otherMgr].length) delete map[otherMgr];
    });
    map[mid] = [...next];
    setTeamManagerAssignmentsMap(map);
    const touchNow = nowISO();
    (Array.isArray(State.data?.agents) ? State.data.agents : []).forEach((a) => {
      const id = safeTrim(a?.id);
      if(!id) return;
      const wasLinked = prev.has(String(id));
      const isLinked = next.has(id);
      if(isLinked) a.teamManagerId = mid;
      else if(wasLinked && safeTrim(a.teamManagerId) === mid) delete a.teamManagerId;
      if(isLinked !== wasLinked){
        a.updatedAt = touchNow;
        a.updated_at = touchNow;
      }
    });
  }

  function getAgentIdsForTeamManager(managerId){
    const mid = safeTrim(managerId);
    if(!mid) return [];
    const map = getTeamManagerAssignmentsMap();
    const fromMap = Array.isArray(map[mid]) ? map[mid].slice() : [];
    const fromAgents = (Array.isArray(State.data?.agents) ? State.data.agents : [])
      .filter((a) => safeTrim(a?.role) === "agent" && safeTrim(a.teamManagerId) === mid)
      .map((a) => safeTrim(a.id))
      .filter(Boolean);
    return [...new Set([...fromMap, ...fromAgents])];
  }

  function getManagedAgentRecordsForTeamManager(managerId){
    const ids = new Set(getAgentIdsForTeamManager(managerId).map(String));
    return (Array.isArray(State.data?.agents) ? State.data.agents : [])
      .filter((a) => a?.active !== false && ids.has(String(safeTrim(a?.id))));
  }

  let _managedProfilesCacheSig = "";
  let _managedProfilesCache = null;
  function getManagedAgentOwnershipProfiles(managerId){
    const mid = safeTrim(managerId)
      || safeTrim(Auth?.current?.id)
      || safeTrim(findAgentRecordForSession()?.id);
    const sig = mid
      + "|" + safeTrim(State.data?.meta?.updatedAt)
      + "|" + safeTrim(State.data?.meta?.revision?.stateVersion);
    if(_managedProfilesCacheSig === sig && _managedProfilesCache) return _managedProfilesCache;
    const profiles = getManagedAgentRecordsForTeamManager(mid)
      .map((a) => getAgentOwnershipProfile({ id: a.id, name: a.name, username: a.username }));
    _managedProfilesCacheSig = sig;
    _managedProfilesCache = profiles;
    return profiles;
  }

  function customerOwnedByManagedTeam(rec){
    if(!rec) return false;
    const profiles = getManagedAgentOwnershipProfiles();
    if(!profiles.length) return false;
    return profiles.some((profile) => recordOwnedByAgent(rec, profile));
  }

  function customerVisibleToTeamManager(rec){
    if(!rec) return false;
    return customerOwnedByCurrentAgent(rec) || customerOwnedByManagedTeam(rec);
  }

  function customerVisibleToCurrentUser(rec){
    if(!rec || !Auth?.current) return false;
    if(Auth.canViewAllCustomers()) return true;
    if(Auth.isTeamManager()) return customerVisibleToTeamManager(rec);
    return customerOwnedByCurrentAgent(rec);
  }

  function filterSessionStateForCurrentUserScope(state){
    const base = state && typeof state === "object" ? state : defaultState();
    if(!Auth?.current || Auth.canViewAllCustomers()) return base;
    const customers = (Array.isArray(base.customers) ? base.customers : []).filter((rec) => customerVisibleToCurrentUser(rec));
    const proposals = (Array.isArray(base.proposals) ? base.proposals : []).filter((rec) => customerVisibleToCurrentUser(rec));
    if(customers.length === (base.customers || []).length && proposals.length === (base.proposals || []).length) return base;
    return normalizeState({
      ...base,
      customers,
      proposals
    });
  }

  function agentSessionDataLooksEmpty(){
    if(!Auth?.current || Auth.canViewAllCustomers()) return false;
    const customers = Array.isArray(State.data?.customers) ? State.data.customers.length : 0;
    const proposals = Array.isArray(State.data?.proposals) ? State.data.proposals.length : 0;
    return customers === 0 && proposals === 0;
  }

  function agentSessionDataLooksSuspiciouslyEmpty(){
    if(!agentSessionDataLooksEmpty()) return false;
    try {
      const backup = Storage.loadBackup?.();
      if(!backup) return false;
      const profile = getCurrentAgentOwnershipProfile();
      const backupCustomers = Array.isArray(backup.customers) ? backup.customers : [];
      const backupProposals = Array.isArray(backup.proposals) ? backup.proposals : [];
      return backupCustomers.some((rec) => recordOwnedByAgent(rec, profile))
        || backupProposals.some((rec) => recordOwnedByAgent(rec, profile));
    } catch(_e) {
      return false;
    }
  }

  function prepSessionStateBeforeUserScopeFilter(state){
    const base = state && typeof state === "object" ? state : defaultState();
    if(!Auth?.current || Auth.canViewAllCustomers()) return base;
    try {
      const agent = findAgentRecordForSession();
      if(!agent) return base;
      const prevData = State.data;
      State.data = base;
      reconcileAgentOwnershipForAgent(agent, { sessionName: safeTrim(Auth.current?.name) });
      const repaired = State.data;
      State.data = prevData;
      return repaired;
    } catch(_e) {
      return base;
    }
  }

  // PERF phase 0: narrow Supabase reads to agent_name values the session may own (client filter remains as safety net).
  function collectAgentNameStringsForServerFilter(agentContext){
    const ctx = agentContext && typeof agentContext === "object" ? agentContext : {};
    const out = new Set();
    [ctx.sessionName, ctx.name, ctx.username].forEach((value) => {
      const trimmed = safeTrim(value);
      if(!trimmed) return;
      if(isAmbiguousSingleTokenAgentLabel(trimmed)) return;
      // Server name filter is exact-match: only full agent names (2+ tokens) when first name is shared.
      const tokens = agentLabelTokens(trimmed);
      if(tokens.length < 2 && isAmbiguousSingleTokenAgentLabel(tokens[0] || trimmed)) return;
      out.add(trimmed);
    });
    return [...out];
  }

  function collectAgentScopeNamesForServerFilter(agentContext){
    const ctx = agentContext && typeof agentContext === "object" ? agentContext : {};
    const out = new Set(collectAgentNameStringsForServerFilter(ctx));
    const agentId = safeTrim(ctx.id);
    getAgentNameHistory(agentId).forEach((name) => {
      collectAgentNameStringsForServerFilter({ sessionName: name, name, id: agentId }).forEach((n) => out.add(n));
    });
    getAgentReportAliases(agentId).forEach((alias) => {
      collectAgentNameStringsForServerFilter({ sessionName: alias, name: alias, id: agentId }).forEach((n) => out.add(n));
    });
    return [...out];
  }

  function getServerListAgentNamesFilter(){
    if(!Auth?.current || Auth.canViewAllCustomers()) return null;
    const names = new Set();
    const sessionAgent = findAgentRecordForSession();
    collectAgentNameStringsForServerFilter({
      sessionName: Auth.current.name,
      name: sessionAgent?.name,
      username: sessionAgent?.username
    }).forEach((name) => names.add(name));
    if(Auth.isTeamManager()){
      const managerId = safeTrim(Auth.current.id) || safeTrim(sessionAgent?.id);
      getManagedAgentRecordsForTeamManager(managerId).forEach((agent) => {
        collectAgentNameStringsForServerFilter(agent).forEach((name) => names.add(name));
      });
    }
    const list = [...names].filter(Boolean);
    return list.length ? list : null;
  }

  // PERF phase 0 (fix): scope reads by BOTH agent_id and agent_name. Records whose stored
  // agent_name drifted from the current session name (spelling variants, agent rename, or
  // stray whitespace) were previously excluded server-side and never reached the client-side
  // ownership "safety net" — so they appeared to vanish. Matching on agent_id as well keeps
  // those rows loading. This server filter is intentionally permissive (a superset); the
  // precise client-side ownership filter (customerVisibleToCurrentUser) remains the final gate.
  function getServerListAgentScopeFilter(){
    if(Storage?._skipServerAgentScope) return null;
    if(!Auth?.current || Auth.canViewAllCustomers()) return null;
    const names = new Set();
    const ids = new Set();
    const sessionAgent = findAgentRecordForSession();
    const addNames = (ctx) => collectAgentScopeNamesForServerFilter(ctx).forEach((name) => names.add(name));
    const addId = (value) => { const v = safeTrim(value); if(v) ids.add(v); };
    addNames({
      id: Auth.current.id || sessionAgent?.id,
      sessionName: Auth.current.name,
      name: sessionAgent?.name,
      username: sessionAgent?.username
    });
    addId(Auth.current.id);
    addId(sessionAgent?.id);
    if(Auth.isTeamManager()){
      const managerId = safeTrim(Auth.current.id) || safeTrim(sessionAgent?.id);
      getManagedAgentRecordsForTeamManager(managerId).forEach((agent) => {
        addNames({
          id: agent?.id,
          sessionName: agent?.name,
          name: agent?.name,
          username: agent?.username
        });
        addId(agent?.id);
      });
    }
    const nameList = [...names].filter(Boolean);
    const idList = [...ids].filter(Boolean);
    if(!nameList.length && !idList.length) return null;
    return { names: nameList, ids: idList };
  }

  // Wrap each value in double quotes (PostgREST-safe) for use inside or(...) / in.(...) filters,
  // so names containing spaces or punctuation are matched literally.
  function buildAgentScopeInValues(values){
    return values
      .map((v) => '"' + String(v).replace(/\\/g, "\\\\").replace(/"/g, '\\"') + '"')
      .join(",");
  }

  const GI_META_SYNC_SCOPE = Object.freeze({
    data: "dataUpdatedAt",
    referrals: "referralsUpdatedAt",
    campaignInbox: "campaignInboxUpdatedAt",
    proposalInbox: "proposalInboxUpdatedAt",
    settings: "settingsUpdatedAt"
  });

  function normalizeMetaSyncClocks(meta, fallbackAt){
    const m = meta && typeof meta === "object" ? meta : {};
    const base = safeTrim(fallbackAt) || safeTrim(m.updatedAt) || nowISO();
    return {
      dataUpdatedAt: safeTrim(m.dataUpdatedAt) || base,
      referralsUpdatedAt: safeTrim(m.referralsUpdatedAt) || base,
      campaignInboxUpdatedAt: safeTrim(m.campaignInboxUpdatedAt) || base,
      proposalInboxUpdatedAt: safeTrim(m.proposalInboxUpdatedAt) || base,
      settingsUpdatedAt: safeTrim(m.settingsUpdatedAt) || base
    };
  }

  function getMetaSyncAt(meta, scope){
    const key = GI_META_SYNC_SCOPE[scope] || scope;
    const clocks = normalizeMetaSyncClocks(meta);
    return safeTrim(clocks[key]) || safeTrim(meta?.updatedAt) || "";
  }

  function bumpMetaSyncClock(meta, scopes, at){
    const m = meta && typeof meta === "object" ? meta : {};
    const stamp = safeTrim(at) || nowISO();
    const scopeList = Array.isArray(scopes) ? scopes : [scopes];
    const clocks = normalizeMetaSyncClocks(m, stamp);
    scopeList.forEach((scope) => {
      const key = GI_META_SYNC_SCOPE[scope] || scope;
      if(key) clocks[key] = stamp;
    });
    m.updatedAt = stamp;
    m.dataUpdatedAt = clocks.dataUpdatedAt;
    m.referralsUpdatedAt = clocks.referralsUpdatedAt;
    m.campaignInboxUpdatedAt = clocks.campaignInboxUpdatedAt;
    m.proposalInboxUpdatedAt = clocks.proposalInboxUpdatedAt;
    m.settingsUpdatedAt = clocks.settingsUpdatedAt;
    return m;
  }

  function metaSyncIsNewer(remoteMeta, localMeta, scope){
    const remoteAt = getMetaSyncAt(remoteMeta, scope);
    const localAt = getMetaSyncAt(localMeta, scope);
    if(!remoteAt || !localAt) return false;
    return compareIsoStamps(remoteAt, localAt) > 0;
  }

  function applyRemoteMetaInboxScopes(remoteMeta){
    if(!remoteMeta || typeof remoteMeta !== "object") return false;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    let changed = false;
    if(metaSyncIsNewer(remoteMeta, State.data.meta, "proposalInbox")){
      State.data.meta.proposalAssignInbox = normalizeProposalAssignInboxList(remoteMeta.proposalAssignInbox || []);
      State.data.meta.proposalInboxUpdatedAt = getMetaSyncAt(remoteMeta, "proposalInbox");
      changed = true;
    }
    if(metaSyncIsNewer(remoteMeta, State.data.meta, "campaignInbox")){
      State.data.meta.campaignLeadAssignInbox = mergeCampaignLeadAssignInboxLists(
        State.data.meta.campaignLeadAssignInbox,
        remoteMeta.campaignLeadAssignInbox
      );
      State.data.meta.campaignInboxUpdatedAt = getMetaSyncAt(remoteMeta, "campaignInbox");
      changed = true;
      try { CampaignLeadAssignInbox.handleInboxMetaArrival(); } catch(_e) {}
    }
    if(changed){
      try { Storage.saveBackup(State.data); } catch(_e) {}
    }
    return changed;
  }

  function getDashboardScopeLabelHe(kind){
    const scope = Auth.getDashboardSalesScope();
    if(kind === "allAgents") return scope === "all" ? "כל הנציגים" : scope === "team" ? "הצוות שלך" : "";
    if(kind === "office") return scope === "all" ? "כל המשרד" : scope === "team" ? "הצוות" : "";
    if(kind === "goal") return scope === "all" ? "כל הנציגים" : scope === "team" ? "הצוות שלך" : "";
    return "";
  }

  function applyTeamManagerAssignmentsToAgents(stateRef){
    const state = stateRef || State.data;
    if(!state || typeof state !== "object") return;
    state.meta = state.meta && typeof state.meta === "object" ? state.meta : {};
    const map = normalizeTeamManagerAssignmentsMap(state.meta.teamManagerAssignments);
    const agents = Array.isArray(state.agents) ? state.agents : [];
    const assigned = new Map();
    Object.entries(map).forEach(([mgrId, ids]) => {
      const mid = safeTrim(mgrId);
      if(!mid || !Array.isArray(ids)) return;
      ids.forEach((rawId) => {
        const aid = safeTrim(rawId);
        if(aid) assigned.set(String(aid), mid);
      });
    });
    agents.forEach((agent) => {
      if(safeTrim(agent?.role) !== "agent") return;
      const aid = safeTrim(agent?.id);
      if(!aid) return;
      const mappedMgr = assigned.get(String(aid));
      if(mappedMgr) agent.teamManagerId = mappedMgr;
      else if(safeTrim(agent.teamManagerId)) delete agent.teamManagerId;
    });
  }

  function reconcileTeamManagerAssignmentsFromAgents(stateRef){
    const state = stateRef || State.data;
    if(!state || typeof state !== "object") return;
    state.meta = state.meta && typeof state.meta === "object" ? state.meta : {};
    const agents = Array.isArray(state.agents) ? state.agents : [];
    const map = normalizeTeamManagerAssignmentsMap(state.meta.teamManagerAssignments);
    let changed = false;
    agents.forEach((a) => {
      if(safeTrim(a?.role) !== "agent") return;
      const tid = safeTrim(a.teamManagerId);
      const aid = safeTrim(a.id);
      if(!tid || !aid) return;
      map[tid] = map[tid] || [];
      if(!map[tid].includes(aid)){
        map[tid].push(aid);
        changed = true;
      }
    });
    if(changed){
      state.meta.teamManagerAssignments = normalizeTeamManagerAssignmentsMap(map);
      if(state === State.data) setTeamManagerAssignmentsMap(map);
    }
  }

  function resolveAgentRoleCode(role){
    const r = safeTrim(role);
    if(r === "manager") return "manager";
    if(r === "ops") return "ops";
    if(r === "elementary") return "elementary";
    if(r === "referent") return "referent";
    if(r === "teamManager") return "teamManager";
    return "agent";
  }

  function generateOpsEventSlots(){
    const slots = [];
    for(let h=8; h<=20; h += 1){
      for(let m=0; m<60; m += 15){
        const hh = String(h).padStart(2,'0');
        const mm = String(m).padStart(2,'0');
        slots.push(`${hh}:${mm}`);
      }
    }
    return slots;
  }

  function normalizeAgentRecord(a, idx=0){
    const input = a && typeof a === "object" ? a : {};
    const name = safeTrim(input?.name) || "נציג";
    const username = safeTrim(input?.username) || safeTrim(input?.user) || name;
    const pin = safeTrim(input?.pin) || safeTrim(input?.pass) || "0000";
    const roleRaw = safeTrim(input?.role) || safeTrim(input?.type) || "";
    const role = (roleRaw === "manager" || roleRaw === "adminLite" || roleRaw === "admin" || roleRaw === "מנהל") ? "manager"
      : (roleRaw === "ops" || roleRaw === "operations" || roleRaw === "תפעול") ? "ops"
      : (roleRaw === "elementary" || roleRaw === "אלמנטרי") ? "elementary"
      : (roleRaw === "referent" || roleRaw === "רפרנטית") ? "referent"
      : (roleRaw === "teamManager" || roleRaw === "team_manager" || roleRaw === "מנהל צוות") ? "teamManager"
      : "agent";
    const teamManagerId = safeTrim(input?.teamManagerId || input?.team_manager_id);
    const createdAt = safeTrim(input?.createdAt || input?.created_at) || nowISO();
    const updatedAt = safeTrim(input?.updatedAt || input?.updated_at) || createdAt;
    return {
      id: safeTrim(input?.id) || ("a_" + idx),
      name,
      username,
      pin,
      birthDate: safeTrim(input?.birthDate || input?.birth_date),
      email: safeTrim(input?.email) || "",
      monthlySalesTarget: Number(String(input?.monthlySalesTarget ?? input?.monthly_sales_target ?? '').replace(/[^\d.-]/g, '')) || 0,
      role,
      teamManagerId: teamManagerId || "",
      active: input?.active === false ? false : true,
      createdAt,
      updatedAt,
      created_at: safeTrim(input?.created_at) || createdAt,
      updated_at: safeTrim(input?.updated_at) || updatedAt
    };
  }

