  function campaignLeadSourceLabel(source){
    const s = safeTrim(source);
    if(s === "landing_page") return "דף נחיתה";
    if(s === "call") return "שיחה";
    if(s === "manual") return "ידני";
    return s || "—";
  }

  const CAMPAIGN_LEAD_LANDING_MARKER = "---LANDING_PAYLOAD---";

  const LANDING_INSURANCE_TO_WIZARD = {
    life_risk: "ריסק",
    mortgage_risk: "ריסק משכנתא",
    health_private: "בריאות",
    critical_illness: "מחלות קשות",
    cancer: "סרטן",
    health_supplement: "מחלות קשות",
    disability: "אובדן כושר עבודה",
    consultation: ""
  };

  function parseCampaignLeadMetaFromDescription(description){
    const hit = findCampaignLeadMetaIndex(description);
    if(hit.idx < 0) return {};
    try {
      const jsonPart = hit.desc.slice(hit.idx + hit.tokenLen).replace(/^\n+/, "").trim();
      const parsed = JSON.parse(jsonPart);
      return parsed && typeof parsed === "object" ? parsed : {};
    } catch(_e){ return {}; }
  }

  function extractCampaignLeadIdFromText(text){
    const desc = safeTrim(text);
    if(!desc) return "";
    const patterns = [
      /ת\.?\s*ז\.?\s*[:\-]?\s*(\d{7,9})/,
      /תעודת\s*זהות\s*[:\-]?\s*(\d{7,9})/,
      /מספר\s*זהות\s*[:\-]?\s*(\d{7,9})/,
      /\bid\s*[:\-]?\s*(\d{7,9})/i
    ];
    for(const re of patterns){
      const m = desc.match(re);
      if(m && m[1]) return normalizeIdValue(m[1]);
    }
    return "";
  }

  function parseCampaignLeadLandingPayload(lead){
    const base = lead && typeof lead === "object" ? lead : {};
    const fromObj = base.landingPayload && typeof base.landingPayload === "object" ? base.landingPayload : null;
    if(fromObj) return fromObj;

    let desc = stripCampaignLeadMetaFromDescription(base.description);
    const markerIdx = desc.indexOf(CAMPAIGN_LEAD_LANDING_MARKER);
    if(markerIdx >= 0){
      try {
        const parsed = JSON.parse(desc.slice(markerIdx + CAMPAIGN_LEAD_LANDING_MARKER.length).trim());
        if(parsed && typeof parsed === "object") return parsed;
      } catch(_e) {}
    }

    const idMatch = desc.match(/ת\.?\s*ז\.?\s*[:\-]?\s*(\d{7,9})/) || desc.match(/תעודת\s*זהות\s*[:\-]?\s*(\d{7,9})/);
    const typesMatch = desc.match(/ביטוחים:\s*(.+)/);
    const notesMatch = desc.match(/הערות:\s*([\s\S]*?)(?:\n---|$)/);
    return {
      fullName: safeTrim(base.customerName),
      idNumber: idMatch ? idMatch[1] : "",
      phone: safeTrim(base.phone),
      insuranceTypes: [],
      insuranceTypeLabels: typesMatch ? typesMatch[1].split(/\s*·\s*|\s*,\s*/).map((x) => safeTrim(x)).filter(Boolean) : [],
      notes: notesMatch ? safeTrim(notesMatch[1]) : ""
    };
  }

  function enrichCampaignLeadFromDescription(lead){
    const base = lead && typeof lead === "object" ? lead : {};
    const meta = parseCampaignLeadMetaFromDescription(base.description);
    const p = parseCampaignLeadLandingPayload(base);
    const labels = Array.isArray(p.insuranceTypeLabels) ? p.insuranceTypeLabels : [];
    const types = Array.isArray(p.insuranceTypes) ? p.insuranceTypes : [];
    const idNumber = normalizeIdValue(base.idNumber)
      || normalizeIdValue(meta.idNumber)
      || normalizeIdValue(p.idNumber)
      || extractCampaignLeadIdFromText(base.description);
    return {
      ...base,
      idNumber,
      idIssueDate: safeTrim(base.idIssueDate) || safeTrim(meta.idIssueDate) || safeTrim(p.idIssueDate),
      birthDate: safeTrim(base.birthDate) || safeTrim(meta.birthDate) || safeTrim(p.birthDate),
      insuranceCompany: safeTrim(base.insuranceCompany) || safeTrim(meta.insuranceCompany),
      insuranceTypes: types,
      insuranceTypeLabels: labels.length ? labels : types.map((t) => LANDING_INSURANCE_TO_WIZARD[t] || t).filter(Boolean),
      landingPayload: p,
      descriptionDisplay: stripCampaignLeadPayloadMarker(base.description),
      additionalAgents: normalizeCampaignLeadAdditionalAgents(
        (Array.isArray(base.additionalAgents) && base.additionalAgents.length) ? base.additionalAgents : meta.additionalAgents
      )
    };
  }

  function stripCampaignLeadPayloadMarker(description){
    let desc = stripCampaignLeadMetaFromDescription(description);
    const idx = desc.indexOf(CAMPAIGN_LEAD_LANDING_MARKER);
    if(idx < 0) return desc;
    return desc.slice(0, idx).trim();
  }

  function mapLandingInsuranceToWizardTypes(payload){
    const types = Array.isArray(payload?.insuranceTypes) ? payload.insuranceTypes : [];
    const labels = Array.isArray(payload?.insuranceTypeLabels) ? payload.insuranceTypeLabels : [];
    const out = [];
    types.forEach((code) => {
      const w = LANDING_INSURANCE_TO_WIZARD[safeTrim(code)];
      if(w && !out.includes(w)) out.push(w);
    });
    if(!out.length && labels.length){
      (Wizard.insTypes || []).forEach((wt) => {
        if(labels.some((lb) => safeTrim(lb).includes(wt))) out.push(wt);
      });
    }
    return out.length ? out : ["ריסק"];
  }

  function agentCanOpenCampaignLead(lead){
    if(!lead || !Auth.current) return false;
    if(Auth.canAccessCampaignLeadsInbox()) return true;
    if(!Auth.canAccessCampaignMyLeads()) return false;
    return campaignLeadAgentAccess(lead, getCurrentAgentRecord());
  }

  function ensureBuiltinCampaignLines(list){
    const ids = new Set((list || []).map((l) => String(l.id)));
    const add = LANDING_LEAD_BUILTIN_CAMPAIGNS.filter((b) => !ids.has(b.id)).map((b, idx) =>
      normalizeCampaignLine(b, idx)
    );
    if(!add.length) return list;
    return [...add, ...list];
  }

  function normalizeCampaignLine(raw, idx = 0){
    const input = raw && typeof raw === "object" ? raw : {};
    const id = safeTrim(input.id) || ("cmp_" + idx + "_" + Math.random().toString(16).slice(2, 6));
    return {
      id,
      label: safeTrim(input.label) || "קמפיין",
      phoneLine: safeTrim(input.phoneLine || input.phone_line),
      topic: safeTrim(input.topic),
      active: input.active === false ? false : true,
      sortOrder: Number(input.sortOrder ?? input.sort_order ?? idx) || idx
    };
  }

  function normalizeCampaignLineList(raw){
    let list = Array.isArray(raw) ? raw.map((row, idx) => normalizeCampaignLine(row, idx)).filter((r) => safeTrim(r.label)) : [];
    list.sort((a, b) => (a.sortOrder - b.sortOrder) || a.label.localeCompare(b.label, "he"));
    if(!list.length){
      list = [normalizeCampaignLine({ id: "cmp_general", label: "כללי / לא משויך", active: true }, 0)];
    }
    return ensureBuiltinCampaignLines(list);
  }

  function getCampaignLines(){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    State.data.meta.campaignLines = normalizeCampaignLineList(State.data.meta.campaignLines);
    return State.data.meta.campaignLines;
  }

  function getDefaultCampaignLine(){
    const lines = getCampaignLines();
    return lines.find((l) => l.active) || lines[0] || normalizeCampaignLine({ id: "cmp_general", label: "כללי" }, 0);
  }

  function campaignLeadStatusLabel(key){
    return CAMPAIGN_LEAD_STATUS_LABELS[safeTrim(key)] || safeTrim(key) || "—";
  }

  function parseCampaignLeadStampMs(raw){
    const s = safeTrim(raw);
    if(!s) return 0;
    let d = new Date(s);
    if(isNaN(d.getTime()) && /^\d{4}-\d{2}-\d{2}/.test(s)){
      d = new Date(s.slice(0, 10) + "T12:00:00");
    }
    const ms = d.getTime();
    return Number.isFinite(ms) ? ms : 0;
  }

  function parseCampaignLeadStampDateIL(raw){
    const s = safeTrim(raw);
    if(!s) return "";
    const isoDay = /^(\d{4}-\d{2}-\d{2})$/.exec(s);
    if(isoDay) return isoDay[1];
    const ilDay = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s);
    if(ilDay) return `${ilDay[3]}-${ilDay[2]}-${ilDay[1]}`;
    const ms = parseCampaignLeadStampMs(raw);
    if(!ms){
      const prefix = /^(\d{4}-\d{2}-\d{2})/.exec(s);
      return prefix ? prefix[1] : "";
    }
    try {
      return new Date(ms).toLocaleDateString("en-CA", { timeZone: "Asia/Jerusalem" });
    } catch(_e) {
      const prefix = /^(\d{4}-\d{2}-\d{2})/.exec(s);
      return prefix ? prefix[1] : "";
    }
  }

  function campaignLeadStampMatchesDateIL(lead, dateStr){
    const target = safeTrim(dateStr);
    if(!target) return true;
    const stamps = [lead?.createdAt, lead?.updatedAt, lead?.lastModifiedAt];
    return stamps.some((raw) => parseCampaignLeadStampDateIL(raw) === target);
  }

  function parseCampaignLeadStampMonthIL(raw){
    const day = parseCampaignLeadStampDateIL(raw);
    return day ? day.slice(0, 7) : "";
  }

  function campaignLeadCreatedMonthIL(lead){
    return parseCampaignLeadStampMonthIL(lead?.createdAt);
  }

  function campaignLeadReportingStamp(lead){
    if(safeTrim(lead?.status) === "closed"){
      return safeTrim(lead?.closedAt) || safeTrim(lead?.updatedAt) || safeTrim(lead?.lastModifiedAt) || safeTrim(lead?.createdAt);
    }
    return safeTrim(lead?.createdAt);
  }

  function campaignLeadReportingMonthIL(lead){
    return parseCampaignLeadStampMonthIL(campaignLeadReportingStamp(lead));
  }

  function campaignLeadReportingDateIL(lead){
    return parseCampaignLeadStampDateIL(campaignLeadReportingStamp(lead));
  }

  function campaignLeadMatchesMonthIL(lead, monthStr){
    const target = safeTrim(monthStr);
    if(!target || target === "ALL") return true;
    return campaignLeadReportingMonthIL(lead) === target;
  }

  function currentCampaignLeadDateIL(){
    try {
      return new Date().toLocaleDateString("en-CA", { timeZone: "Asia/Jerusalem" });
    } catch(_e) {
      const d = new Date();
      return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
    }
  }

  function campaignLeadMatchesDateIL(lead, dateStr){
    const target = safeTrim(dateStr);
    if(!target) return true;
    return campaignLeadReportingDateIL(lead) === target;
  }

  function currentCampaignLeadMonthIL(){
    try {
      return new Date().toLocaleDateString("en-CA", { timeZone: "Asia/Jerusalem" }).slice(0, 7);
    } catch(_e) {
      const d = new Date();
      return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}`;
    }
  }

  function normalizeCampaignLeadAdditionalAgents(raw){
    const arr = Array.isArray(raw) ? raw : [];
    const out = [];
    const seen = new Set();
    arr.forEach((entry) => {
      const item = entry && typeof entry === "object" ? entry : {};
      const id = safeTrim(item.id || item.agentId);
      const name = safeTrim(item.name || item.agentName);
      if(!id && !name) return;
      const key = id ? String(id) : `name:${name}`;
      if(seen.has(key)) return;
      seen.add(key);
      out.push({
        id,
        name,
        assignedAt: safeTrim(item.assignedAt || item.assigned_at)
      });
    });
    return out;
  }

  function campaignLeadHasAdditionalAgentId(lead, agentId){
    const id = safeTrim(agentId);
    if(!id) return false;
    return normalizeCampaignLeadAdditionalAgents(lead?.additionalAgents).some((a) => String(a.id) === String(id));
  }

  function campaignLeadResolveAgentName(lead, agents){
    let name = safeTrim(lead?.assignedAgentName);
    const aid = safeTrim(lead?.assignedAgentId);
    if((!name || name === "—") && aid){
      const ag = (Array.isArray(agents) ? agents : []).find((a) => String(a?.id) === aid);
      name = safeTrim(ag?.name) || "";
    }
    return name || "—";
  }

  function campaignLeadAllAgentNames(lead, agents){
    const list = Array.isArray(agents) ? agents : [];
    const names = [];
    const primary = campaignLeadResolveAgentName(lead, list);
    if(primary && primary !== "—") names.push(primary);
    normalizeCampaignLeadAdditionalAgents(lead?.additionalAgents).forEach((a) => {
      let n = safeTrim(a.name);
      if(!n && a.id){
        const ag = list.find((x) => String(x?.id) === String(a.id));
        n = safeTrim(ag?.name);
      }
      if(n && !names.includes(n)) names.push(n);
    });
    return names;
  }

  function campaignLeadAgentAccess(lead, agentRec){
    if(!lead || !agentRec) return false;
    const meId = safeTrim(agentRec.id);
    const meName = safeTrim(agentRec.name);
    const meUser = safeTrim(agentRec.username);
    if(meId && String(lead.assignedAgentId) === String(meId)) return true;
    if(campaignLeadHasAdditionalAgentId(lead, meId)) return true;
    const assignedName = safeTrim(lead.assignedAgentName);
    if(assignedName && ((meName && assignedName === meName) || (meUser && assignedName === meUser))) return true;
    return normalizeCampaignLeadAdditionalAgents(lead?.additionalAgents).some((a) => {
      const n = safeTrim(a.name);
      return n && ((meName && n === meName) || (meUser && n === meUser));
    });
  }

  function campaignLeadMatchesAgentFilter(lead, agentName, agents){
    const target = safeTrim(agentName);
    if(!target) return true;
    return campaignLeadAllAgentNames(lead, agents).includes(target);
  }

  function formatCampaignLeadMonthLabel(monthStr){
    const raw = safeTrim(monthStr);
    if(!raw || raw === "ALL") return "כל הזמנים";
    try {
      const [y, m] = raw.split("-");
      return `${m}/${y}`;
    } catch(_e) {
      return raw;
    }
  }

  function formatCampaignLeadDayLabel(dateStr){
    const raw = safeTrim(dateStr);
    if(!raw) return "היום";
    try {
      const [y, m, d] = raw.split("-");
      if(!y || !m || !d) return raw;
      return `${d}/${m}/${y}`;
    } catch(_e) {
      return raw;
    }
  }

  function campaignLeadAgentsDisplay(lead, agents){
    const names = campaignLeadAllAgentNames(lead, agents);
    return names.length ? names.join(" · ") : "—";
  }

  function campaignLeadIsOpenInInbox(statusKey){
    return safeTrim(statusKey) !== "closed";
  }

  function normalizeCampaignLead(raw, idx = 0){
    const input = raw && typeof raw === "object" ? raw : {};
    const createdAt = safeTrim(input.createdAt || input.created_at) || nowISO();
    const updatedAt = safeTrim(input.updatedAt || input.updated_at) || createdAt;
    const statusRaw = safeTrim(input.status) || "new";
    const status = Object.prototype.hasOwnProperty.call(CAMPAIGN_LEAD_STATUS_LABELS, statusRaw) ? statusRaw : "new";
    return {
      id: safeTrim(input.id) || ("cl_" + idx + "_" + Date.now().toString(36)),
      phone: normalizePhoneValue(input.phone),
      customerName: safeTrim(input.customerName || input.customer_name),
      description: safeTrim(input.description),
      campaignId: safeTrim(input.campaignId || input.campaign_id),
      campaignLabel: safeTrim(input.campaignLabel || input.campaign_label) || "כללי",
      assignedAgentId: safeTrim(input.assignedAgentId || input.assigned_agent_id),
      assignedAgentName: safeTrim(input.assignedAgentName || input.assigned_agent_name),
      status,
      source: safeTrim(input.source) || "manual",
      createdByName: safeTrim(input.createdByName || input.created_by_name),
      updatedByName: safeTrim(input.updatedByName || input.updated_by_name),
      idNumber: normalizeIdValue(input.idNumber || input.id_number),
      idIssueDate: safeTrim(input.idIssueDate || input.id_issue_date),
      birthDate: safeTrim(input.birthDate || input.birth_date),
      insuranceCompany: safeTrim(input.insuranceCompany || input.insurance_company),
      insuranceTypes: Array.isArray(input.insuranceTypes) ? input.insuranceTypes : [],
      insuranceTypeLabels: Array.isArray(input.insuranceTypeLabels) ? input.insuranceTypeLabels : [],
      landingPayload: input.landingPayload && typeof input.landingPayload === "object" ? input.landingPayload : null,
      descriptionDisplay: safeTrim(input.descriptionDisplay),
      lastModifiedAt: safeTrim(input.lastModifiedAt || input.last_modified_at) || updatedAt,
      closedAt: safeTrim(input.closedAt || input.closed_at),
      closedNote: safeTrim(input.closedNote || input.closed_note),
      irrelevantNote: safeTrim(input.irrelevantNote || input.irrelevant_note),
      callNote: safeTrim(input.callNote || input.call_note),
      rowColor: safeTrim(input.rowColor || input.row_color),
      additionalAgents: normalizeCampaignLeadAdditionalAgents(input.additionalAgents || input.additional_agents),
      createdAt,
      updatedAt
    };
  }

  function mapCampaignLeadFromDb(row, idx = 0){
    if(!row || typeof row !== "object") return null;
    const leadMeta = parseCampaignLeadMetaFromDescription(row.description);
    const lead = normalizeCampaignLead({
      id: row.id,
      phone: row.phone,
      customerName: row.customer_name,
      description: row.description,
      campaignId: row.campaign_id,
      campaignLabel: row.campaign_label,
      assignedAgentId: row.assigned_agent_id,
      assignedAgentName: row.assigned_agent_name,
      status: row.status,
      source: row.source,
      createdByName: row.created_by_name,
      updatedByName: row.updated_by_name,
      idNumber: row.id_number || leadMeta.idNumber,
      idIssueDate: row.id_issue_date || leadMeta.idIssueDate,
      birthDate: row.birth_date || leadMeta.birthDate,
      insuranceCompany: leadMeta.insuranceCompany,
      lastModifiedAt: leadMeta.lastModifiedAt,
      closedAt: leadMeta.closedAt,
      closedNote: leadMeta.closedNote,
      irrelevantNote: leadMeta.irrelevantNote,
      callNote: leadMeta.callNote,
      additionalAgents: leadMeta.additionalAgents,
      rowColor: row.row_color,
      createdAt: row.created_at,
      updatedAt: row.updated_at
    }, idx);
    return lead ? enrichCampaignLeadFromDescription(lead) : null;
  }

  function mapCampaignLeadToDb(lead, options = {}){
    const l = normalizeCampaignLead(lead);
    let desc = stripCampaignLeadMetaFromDescription(l.description);
    const meta = {};
    if(l.closedAt) meta.closedAt = l.closedAt;
    if(l.closedNote) meta.closedNote = l.closedNote;
    if(l.irrelevantNote) meta.irrelevantNote = l.irrelevantNote;
    if(l.callNote) meta.callNote = l.callNote;
    if(l.lastModifiedAt) meta.lastModifiedAt = l.lastModifiedAt;
    if(safeTrim(l.idNumber)) meta.idNumber = normalizeIdValue(l.idNumber);
    if(safeTrim(l.idIssueDate)) meta.idIssueDate = safeTrim(l.idIssueDate);
    if(safeTrim(l.birthDate)) meta.birthDate = safeTrim(l.birthDate);
    if(safeTrim(l.insuranceCompany)) meta.insuranceCompany = safeTrim(l.insuranceCompany);
    const extraAgents = normalizeCampaignLeadAdditionalAgents(l.additionalAgents);
    if(extraAgents.length) meta.additionalAgents = extraAgents;
    if(Object.keys(meta).length){
      desc = desc + "\n---LEAD_META_JSON---\n" + JSON.stringify(meta);
    }
    const row = {
      id: l.id,
      phone: l.phone,
      customer_name: l.customerName,
      description: desc,
      campaign_id: l.campaignId,
      campaign_label: l.campaignLabel,
      assigned_agent_id: l.assignedAgentId,
      assigned_agent_name: l.assignedAgentName,
      status: l.status,
      source: l.source,
      created_by_name: l.createdByName,
      updated_by_name: l.updatedByName,
      created_at: l.createdAt,
      updated_at: l.updatedAt,
      row_color: safeTrim(l.rowColor) || null
    };
    const includeCustomerFields = options.includeCustomerFields !== false
      && CampaignLeadsStore.customerFieldsInDb !== false;
    if(includeCustomerFields){
      const idNum = normalizeIdValue(l.idNumber);
      if(idNum) row.id_number = idNum;
      if(safeTrim(l.idIssueDate)) row.id_issue_date = safeTrim(l.idIssueDate);
      if(safeTrim(l.birthDate)) row.birth_date = safeTrim(l.birthDate);
    }
    return row;
  }

  function getAssignableSalesAgents(){
    return (Array.isArray(State.data?.agents) ? State.data.agents : [])
      .filter((a) => a.active !== false)
      .sort((a, b) => safeTrim(a.name).localeCompare(safeTrim(b.name), "he"));
  }

  function getCampaignLeadReassignAgents(){
    return (Array.isArray(State.data?.agents) ? State.data.agents : [])
      .filter((a) => safeTrim(a?.name))
      .sort((a, b) => {
        const aRank = a.active === false ? 1 : 0;
        const bRank = b.active === false ? 1 : 0;
        if(aRank !== bRank) return aRank - bRank;
        return safeTrim(a.name).localeCompare(safeTrim(b.name), "he");
      });
  }

  function normalizeCustomerRecord(c, idx=0){
    let rawPayload = c?.payload;
    if(typeof rawPayload === "string"){
      try {
        const t = safeTrim(rawPayload);
        rawPayload = t ? JSON.parse(t) : {};
      } catch(_e) {
        rawPayload = {};
      }
    }
    const payload = rawPayload && typeof rawPayload === "object" ? rawPayload : {};
    if((!Array.isArray(payload.insureds) || !payload.insureds.length) && Array.isArray(payload?.operational?.insureds)){
      payload.insureds = perfCloneArray(payload.operational.insureds);
    }
    if((!Array.isArray(payload.newPolicies) || !payload.newPolicies.length) && Array.isArray(payload?.operational?.newPolicies)){
      payload.newPolicies = perfCloneArray(payload.operational.newPolicies);
    }
    const primary = payload?.primary || payload?.insureds?.[0]?.data || {};
    const fullName = safeTrim(c?.fullName) || safeTrim(((primary.firstName || "") + " " + (primary.lastName || "")).trim()) || "לקוח ללא שם";
    const idNumber = safeTrim(c?.idNumber) || safeTrim(primary.idNumber);
    const phone = safeTrim(c?.phone) || safeTrim(primary.phone);
    const email = safeTrim(c?.email) || safeTrim(primary.email);
    const city = safeTrim(c?.city) || safeTrim(primary.city);
    const agentName = safeTrim(c?.agentName) || safeTrim(c?.createdBy) || safeTrim(payload?.createdBy) || "";
    const createdAt = safeTrim(c?.createdAt) || nowISO();
    const updatedAt = safeTrim(c?.updatedAt) || createdAt;
    const insuredCount = Number(c?.insuredCount || payload?.insureds?.length || 0) || 0;
    const existingPoliciesCount = Number(c?.existingPoliciesCount || ((payload?.insureds || []).reduce((acc, ins) => acc + ((ins?.data?.existingPolicies || []).length), 0))) || 0;
    const newPoliciesCount = Number(c?.newPoliciesCount || (payload?.newPolicies || []).length) || 0;
    return {
      id: safeTrim(c?.id) || ("cust_" + idx + "_" + Math.random().toString(16).slice(2)),
      status: safeTrim(c?.status) || "חדש",
      fullName,
      idNumber,
      phone,
      email,
      city,
      agentName,
      agentId: safeTrim(c?.agentId) || safeTrim(payload?.agentId) || "",
      createdBy: safeTrim(c?.createdBy) || safeTrim(payload?.createdBy) || "",
      agentRole: safeTrim(c?.agentRole) || "",
      createdAt,
      updatedAt,
      insuredCount,
      existingPoliciesCount,
      newPoliciesCount,
      payload
    };
  }

  /** Customers marked inactive/archived on Supabase stay in the table but must not appear in active CRM lists. */
  function isServerArchivedCustomerRecord(c){
    if(!c || typeof c !== "object") return false;
    const raw = safeTrim(c.status);
    const s = raw.toLowerCase();
    if(s === "inactive" || s === "archived" || s === "purged") return true;
    if(raw === "גנוז") return true;
    return false;
  }

  /** Server row statuses allowed for permanent purge (never active/new). */
  function isSafePurgeCustomerServerStatus(statusRaw){
    const s = safeTrim(statusRaw).toLowerCase();
    return s === "inactive" || s === "archived" || s === "purged" || safeTrim(statusRaw) === "גנוז";
  }

  function formatServerDeleteError(rawErr, options = {}){
    const raw = safeTrim(rawErr) || "מחיקה מהשרת נכשלה";
    const entity = safeTrim(options.entityLabel) || "הרשומה";
    if(/delete is blocked/i.test(raw)){
      return "השרת חוסם מחיקת " + entity + ". יש להריץ את סקריפטי Supabase המתאימים (פעם אחת) ולנסות שוב.";
    }
    if(/customers_history/i.test(raw) && /row-level security|rls/i.test(raw)){
      return "המחיקה נחסמה בטבלת customers_history. הרץ את supabase/enable-safe-customer-delete.sql ב-Supabase.";
    }
    if(/proposals_history/i.test(raw) && /row-level security|rls/i.test(raw)){
      return "המחיקה נחסמה בטבלת proposals_history. הרץ את supabase/enable-safe-proposal-delete.sql ב-Supabase.";
    }
    if(raw === "DELETE_VERIFY_FAILED") return "המחיקה מהשרת לא אומתה — לא בוצע שינוי במערכת.";
    if(raw === "DELETE_NO_ROWS" || raw === "ROW_NOT_FOUND") return "הרשומה לא נמצאה בשרת (אולי כבר נמחקה). רענן את המסך.";
    return raw;
  }

  function getNewPoliciesFromCustomerPayload(payload = {}){
    const p = payload && typeof payload === "object" ? payload : {};
    const direct = Array.isArray(p.newPolicies) ? p.newPolicies : [];
    if(direct.length) return direct;
    const op = Array.isArray(p?.operational?.newPolicies) ? p.operational.newPolicies : [];
    return op;
  }

  function isCustomerPayloadValueEmpty(val){
    if(val === null || val === undefined) return true;
    if(Array.isArray(val)) return !val.length;
    if(typeof val === "object") return !Object.keys(val).length;
    return !safeTrim(val);
  }

  function mergeInsuredDataPreferNonEmpty(prevData, nextData){
    const out = JSON.parse(JSON.stringify(prevData && typeof prevData === "object" ? prevData : {}));
    Object.entries(nextData && typeof nextData === "object" ? nextData : {}).forEach(([key, val]) => {
      if(!isCustomerPayloadValueEmpty(val)) out[key] = val;
    });
    return out;
  }

  /** When saving elementary / car-click on an existing customer, keep health & risk policies and declarations. */
  function mergeElementarySaveWithExistingCustomerPayload(existingPayload, incomingPayload){
    if(!existingPayload || typeof existingPayload !== "object") return incomingPayload;
    const out = JSON.parse(JSON.stringify(incomingPayload && typeof incomingPayload === "object" ? incomingPayload : {}));
    const prev = JSON.parse(JSON.stringify(existingPayload));

    const prevNew = getNewPoliciesFromCustomerPayload(prev);
    const nextNew = getNewPoliciesFromCustomerPayload(out);
    if(!nextNew.length && prevNew.length){
      out.newPolicies = prevNew;
    } else if(nextNew.length && prevNew.length){
      const merged = [...prevNew];
      nextNew.forEach((policy) => {
        const pid = safeTrim(policy?.id);
        const idx = pid ? merged.findIndex((row) => String(row?.id) === String(pid)) : -1;
        if(idx >= 0) merged[idx] = policy;
        else merged.push(policy);
      });
      out.newPolicies = merged;
    }

    if(prev.mirrorFlow && typeof prev.mirrorFlow === "object"){
      out.mirrorFlow = { ...JSON.parse(JSON.stringify(prev.mirrorFlow)), ...(out.mirrorFlow && typeof out.mirrorFlow === "object" ? out.mirrorFlow : {}) };
    }
    if(prev.operational && typeof prev.operational === "object"){
      const prevOp = JSON.parse(JSON.stringify(prev.operational));
      const nextOp = out.operational && typeof out.operational === "object" ? out.operational : {};
      out.operational = { ...prevOp, ...nextOp };
      if(!getNewPoliciesFromCustomerPayload(out).length && Array.isArray(prevOp.newPolicies) && prevOp.newPolicies.length){
        out.operational.newPolicies = prevOp.newPolicies;
      }
    }

    const prevInsureds = Array.isArray(prev.insureds) ? prev.insureds : [];
    const nextInsureds = Array.isArray(out.insureds) ? out.insureds : [];
    const mergedInsureds = nextInsureds.map((ins, idx) => {
      const prevRow = prevInsureds[idx] || prevInsureds.find((row) => String(row?.id) === String(ins?.id)) || null;
      if(!prevRow) return ins;
      return {
        ...prevRow,
        ...ins,
        data: mergeInsuredDataPreferNonEmpty(prevRow.data, ins?.data)
      };
    });
    if(prevInsureds.length > mergedInsureds.length){
      mergedInsureds.push(...prevInsureds.slice(mergedInsureds.length).map((row) => JSON.parse(JSON.stringify(row))));
    }
    out.insureds = mergedInsureds;

    const prevPrimary = prev.primary && typeof prev.primary === "object" ? prev.primary : (prevInsureds[0]?.data || {});
    const nextPrimary = out.primary && typeof out.primary === "object" ? out.primary : (mergedInsureds[0]?.data || {});
    out.primary = mergeInsuredDataPreferNonEmpty(prevPrimary, nextPrimary);

    if(prevNew.length){
      const prevFlow = safeTrim(prev.flowType).toLowerCase();
      if(prevFlow === "health" || inferProposalFlowType(prev) === "health"){
        out.flowType = "health";
      }
    }

    const prevDocs = Array.isArray(prev.customerDocuments) ? prev.customerDocuments : [];
    const nextDocs = Array.isArray(out.customerDocuments) ? out.customerDocuments : [];
    if(prevDocs.length){
      const mergedDocs = prevDocs.slice();
      const seen = new Set(prevDocs.map((d) => safeTrim(d?.id)).filter(Boolean));
      nextDocs.forEach((doc) => {
        const id = safeTrim(doc?.id);
        if(id && seen.has(id)) return;
        mergedDocs.unshift(doc);
        if(id) seen.add(id);
      });
      out.customerDocuments = mergedDocs;
    }else if(nextDocs.length){
      out.customerDocuments = nextDocs.slice();
    }

    return out;
  }

  const CustomerDocuments = {
    TYPES: {
      healthOps: "operational_report_health",
      agentApptOps: "operational_report_agent_appointment",
      agentApptForm: "agent_appointment_form"
    },
    REPORT_SCOPES: {
      proposal: "health_proposal",
      purchase: "health_purchase"
    },
    listFromPayload(payload){
      return Array.isArray(payload?.customerDocuments) ? payload.customerDocuments.filter((doc) => doc && typeof doc === "object") : [];
    },
    sortByDateDesc(docs){
      return (Array.isArray(docs) ? docs.slice() : []).sort((a, b) => {
        const ta = new Date(safeTrim(a?.uploadedAt) || safeTrim(a?.createdAt) || 0).getTime();
        const tb = new Date(safeTrim(b?.uploadedAt) || safeTrim(b?.createdAt) || 0).getTime();
        return (Number.isFinite(tb) ? tb : 0) - (Number.isFinite(ta) ? ta : 0);
      });
    },
    newDocId(prefix){
      return prefix + Date.now().toString(16) + "_" + Math.random().toString(16).slice(2, 7);
    },
    formatDocDateLabel(value){
      if(!value) return "—";
      const d = new Date(value);
      if(Number.isNaN(d.getTime())) return String(value);
      return d.toLocaleString("he-IL");
    },
    getPrimaryInsuredLabel(payload){
      const data = (payload?.primary && typeof payload.primary === "object")
        ? payload.primary
        : (payload?.insureds?.[0]?.data && typeof payload.insureds[0].data === "object" ? payload.insureds[0].data : {});
      const fullName = safeTrim(((data.firstName || "") + " " + (data.lastName || "")).trim());
      if(fullName) return fullName;
      return safeTrim(payload?.insureds?.[0]?.label) || "מבוטח";
    },
    formatHealthReportDocName(scope, payload, uploadedAt){
      const insured = this.getPrimaryInsuredLabel(payload);
      const dateLabel = this.formatDocDateLabel(uploadedAt);
      if(safeTrim(scope) === this.REPORT_SCOPES.purchase){
        return `דוח תפעולי · רכישה חדשה · ${insured} · ${dateLabel}`;
      }
      return `דוח תפעולי · בריאות וסיכונים · הצעה לביטוח · ${insured} · ${dateLabel}`;
    },
    getDocumentDisplay(doc){
      const uploadedAt = safeTrim(doc?.uploadedAt) || safeTrim(doc?.createdAt) || "";
      const snapshot = doc?.payloadSnapshot && typeof doc.payloadSnapshot === "object" ? doc.payloadSnapshot : {};
      const scope = safeTrim(doc?.reportScope);
      const insured = safeTrim(doc?.insuredLabel) || this.getPrimaryInsuredLabel(snapshot);
      let title = safeTrim(doc?.name);
      if(safeTrim(doc?.type) === this.TYPES.healthOps){
        if(scope === this.REPORT_SCOPES.purchase || scope === this.REPORT_SCOPES.proposal){
          title = this.formatHealthReportDocName(scope, snapshot, uploadedAt);
        }else if(doc?.isLegacy || doc?.isMaterializedLegacy){
          title = this.formatHealthReportDocName(this.REPORT_SCOPES.proposal, snapshot, uploadedAt);
        }
      }
      if(!title) title = `מסמך · ${insured}`;
      return {
        title,
        dateLabel: this.formatDocDateLabel(uploadedAt),
        agentLabel: safeTrim(doc?.uploadedBy) || safeTrim(doc?.source) || ""
      };
    },
    relabelProposalHealthDocs(list, snapshotPayload){
      (Array.isArray(list) ? list : []).forEach((doc) => {
        if(safeTrim(doc?.type) !== this.TYPES.healthOps) return;
        if(safeTrim(doc?.reportScope) === this.REPORT_SCOPES.purchase) return;
        const snap = doc?.payloadSnapshot && typeof doc.payloadSnapshot === "object" ? doc.payloadSnapshot : snapshotPayload;
        doc.reportScope = this.REPORT_SCOPES.proposal;
        doc.insuredLabel = this.getPrimaryInsuredLabel(snap);
        doc.name = this.formatHealthReportDocName(this.REPORT_SCOPES.proposal, snap, doc.uploadedAt);
      });
    },
    hasProposalHealthDoc(list){
      return (Array.isArray(list) ? list : []).some((doc) => {
        if(safeTrim(doc?.type) !== this.TYPES.healthOps) return false;
        if(safeTrim(doc?.reportScope) === this.REPORT_SCOPES.purchase) return false;
        return true;
      });
    },
    preparePurchaseHealthDocuments(payload, existingPayload, options = {}){
      if(!payload || typeof payload !== "object" || !existingPayload || typeof existingPayload !== "object") return payload;
      const list = this.listFromPayload(payload);
      this.relabelProposalHealthDocs(list, existingPayload);
      if(this.hasProposalHealthDoc(list)){
        payload.customerDocuments = list;
        return payload;
      }
      const existingList = this.listFromPayload(existingPayload);
      const existingHealth = existingList.filter((doc) => safeTrim(doc?.type) === this.TYPES.healthOps);
      if(existingHealth.length){
        const seen = new Set(list.map((doc) => safeTrim(doc?.id)).filter(Boolean));
        existingHealth.forEach((doc) => {
          const id = safeTrim(doc?.id);
          if(id && seen.has(id)) return;
          const frozen = JSON.parse(JSON.stringify(doc));
          const snap = frozen.payloadSnapshot && typeof frozen.payloadSnapshot === "object" ? frozen.payloadSnapshot : existingPayload;
          frozen.reportScope = this.REPORT_SCOPES.proposal;
          frozen.insuredLabel = this.getPrimaryInsuredLabel(snap);
          frozen.name = this.formatHealthReportDocName(this.REPORT_SCOPES.proposal, snap, frozen.uploadedAt);
          list.unshift(frozen);
          if(id) seen.add(id);
        });
      }else if(this.qualifiesForHealthReport(existingPayload)){
        const uploadedAt = safeTrim(existingPayload?.operational?.createdAt)
          || safeTrim(existingPayload?.createdAt)
          || safeTrim(options.uploadedAt)
          || nowISO();
        const frozen = this.createHealthReportDoc(existingPayload, {
          uploadedAt,
          uploadedBy: safeTrim(options.uploadedBy),
          reportScope: this.REPORT_SCOPES.proposal
        });
        frozen.isMaterializedLegacy = true;
        list.unshift(frozen);
      }
      payload.customerDocuments = list;
      return payload;
    },
    qualifiesForHealthReport(payload){
      if(!payload || typeof payload !== "object") return false;
      const flow = safeTrim(payload.flowType).toLowerCase();
      if(flow === "elementary") return false;
      const newPol = getNewPoliciesFromCustomerPayload(payload);
      if(newPol.length) return true;
      const op = payload.operational && typeof payload.operational === "object" ? payload.operational : null;
      if(op){
        if(Array.isArray(op.newPolicies) && op.newPolicies.length) return true;
        if(op.primary || (Array.isArray(op.insureds) && op.insureds.length)) return true;
      }
      const insureds = Array.isArray(payload.insureds) ? payload.insureds : [];
      if(insureds.some((ins) => (ins?.data?.existingPolicies || []).length)) return true;
      if(flow === "health") return true;
      if(flow === "agent_appointment") return false;
      return !!(payload.primary || insureds.length);
    },
    createHealthReportDoc(payload, options = {}){
      const uploadedAt = safeTrim(options.uploadedAt) || nowISO();
      const reportScope = safeTrim(options.reportScope);
      let snapshot;
      try{ snapshot = JSON.parse(JSON.stringify(payload && typeof payload === "object" ? payload : {})); }catch(_e){ snapshot = {}; }
      const insuredLabel = this.getPrimaryInsuredLabel(snapshot);
      const name = reportScope
        ? this.formatHealthReportDocName(reportScope, snapshot, uploadedAt)
        : "דוח תפעולי — בריאות וסיכונים";
      return {
        id: this.newDocId("doc_ops_health_"),
        type: this.TYPES.healthOps,
        name,
        reportScope: reportScope || undefined,
        insuredLabel,
        source: "מערכת",
        uploadedAt,
        uploadedBy: safeTrim(options.uploadedBy) || safeTrim(Auth?.current?.name),
        payloadSnapshot: snapshot
      };
    },
    createAgentApptFormDoc(meta, options = {}){
      const coLabel = safeTrim(meta?.companyLabel) || safeTrim(getAgentApptCompany(meta?.companyId)?.label) || "חברה";
      const uploadedAt = safeTrim(options.uploadedAt) || safeTrim(meta?.savedAt) || nowISO();
      return {
        id: this.newDocId("doc_agent_appt_"),
        type: this.TYPES.agentApptForm,
        name: "טופס מקורי — מינוי סוכן · " + coLabel,
        companyId: safeTrim(meta?.companyId),
        metaSnapshot: JSON.parse(JSON.stringify(meta || {})),
        source: "מערכת",
        uploadedAt,
        uploadedBy: safeTrim(options.uploadedBy) || safeTrim(meta?.agent?.name) || safeTrim(Auth?.current?.name)
      };
    },
    createAgentApptReportDoc(meta, options = {}){
      const coLabel = safeTrim(meta?.companyLabel) || safeTrim(getAgentApptCompany(meta?.companyId)?.label) || "חברה";
      const uploadedAt = safeTrim(options.uploadedAt) || safeTrim(meta?.savedAt) || nowISO();
      return {
        id: this.newDocId("doc_ops_agent_"),
        type: this.TYPES.agentApptOps,
        name: "דוח תפעולי — מינוי סוכן · " + coLabel,
        source: "מערכת",
        uploadedAt,
        uploadedBy: safeTrim(options.uploadedBy) || safeTrim(meta?.agent?.name) || safeTrim(Auth?.current?.name),
        payloadSnapshot: { agentAppointmentMeta: JSON.parse(JSON.stringify(meta || {})) }
      };
    },
    append(payload, doc){
      if(!payload || typeof payload !== "object" || !doc || typeof doc !== "object") return payload;
      const list = this.listFromPayload(payload);
      list.unshift(doc);
      payload.customerDocuments = list;
      return payload;
    },
    upsertHealthEditReportDoc(payload, reportPayload, options = {}){
      if(!payload || typeof payload !== "object") return payload;
      const list = this.listFromPayload(payload);
      const idx = list.findIndex((doc) => {
        if(safeTrim(doc?.type) !== this.TYPES.healthOps) return false;
        return safeTrim(doc?.reportScope) !== this.REPORT_SCOPES.purchase;
      });
      const nextDoc = this.createHealthReportDoc(reportPayload, {
        uploadedAt: safeTrim(options.uploadedAt) || nowISO(),
        uploadedBy: safeTrim(options.uploadedBy),
        reportScope: ""
      });
      if(idx >= 0){
        const prev = list[idx];
        nextDoc.id = safeTrim(prev?.id) || nextDoc.id;
        nextDoc.uploadedAt = safeTrim(options.uploadedAt) || nowISO();
        list[idx] = nextDoc;
      } else {
        list.unshift(nextDoc);
      }
      payload.customerDocuments = list;
      return payload;
    },
    enrichPayloadWithSaveDocuments(payload, context = {}){
      if(!payload || typeof payload !== "object") return payload;
      const kind = safeTrim(context.kind);
      const options = { uploadedAt: safeTrim(context.uploadedAt) || nowISO(), uploadedBy: safeTrim(context.uploadedBy) || safeTrim(Auth?.current?.name) };
      if(kind === "agent_appointment"){
        const meta = payload.agentAppointmentMeta;
        if(meta && typeof meta === "object"){
          this.append(payload, this.createAgentApptFormDoc(meta, options));
          this.append(payload, this.createAgentApptReportDoc(meta, options));
        }
        return payload;
      }
      if(kind === "health_edit"){
        const reportPayload = context.reportPayloadOverride && typeof context.reportPayloadOverride === "object"
          ? context.reportPayloadOverride
          : payload;
        if(this.qualifiesForHealthReport(reportPayload)){
          this.upsertHealthEditReportDoc(payload, reportPayload, options);
        }
        return payload;
      }
      if(kind === "health_wizard"){
        if(context.isPurchaseFlow && context.existingPayload && typeof context.existingPayload === "object"){
          this.preparePurchaseHealthDocuments(payload, context.existingPayload, options);
        }
        const reportPayload = context.reportPayloadOverride && typeof context.reportPayloadOverride === "object"
          ? context.reportPayloadOverride
          : payload;
        if(this.qualifiesForHealthReport(reportPayload)){
          const reportScope = context.isPurchaseFlow
            ? this.REPORT_SCOPES.purchase
            : this.REPORT_SCOPES.proposal;
          this.append(payload, this.createHealthReportDoc(reportPayload, {
            ...options,
            reportScope
          }));
        }
        return payload;
      }
      return payload;
    },
    resolveListForCustomer(rec){
      const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
      const list = this.listFromPayload(payload);
      const hasHealthOps = list.some((d) => safeTrim(d?.type) === this.TYPES.healthOps);
      if(!hasHealthOps && this.qualifiesForHealthReport(payload)){
        const legacyUploadedAt = safeTrim(rec?.updatedAt) || safeTrim(rec?.updated_at) || safeTrim(rec?.createdAt) || safeTrim(rec?.created_at) || nowISO();
        list.unshift({
          id: "doc_legacy_health_ops",
          type: this.TYPES.healthOps,
          isLegacy: true,
          reportScope: this.REPORT_SCOPES.proposal,
          payloadSnapshot: JSON.parse(JSON.stringify(payload)),
          name: this.formatHealthReportDocName(this.REPORT_SCOPES.proposal, payload, legacyUploadedAt),
          insuredLabel: this.getPrimaryInsuredLabel(payload),
          source: "מערכת",
          uploadedAt: legacyUploadedAt,
          uploadedBy: safeTrim(rec?.agentName)
        });
      }
      const hasApptForm = list.some((d) => safeTrim(d?.type) === this.TYPES.agentApptForm);
      if(!hasApptForm && payload.agentAppointmentMeta){
        const meta = payload.agentAppointmentMeta;
        const coLabel = safeTrim(meta?.companyLabel) || "חברה";
        list.unshift({ id: "doc_agent_appt_legacy", type: this.TYPES.agentApptForm, isLegacy: true, name: "טופס מקורי — מינוי סוכן · " + coLabel, companyId: safeTrim(meta?.companyId), metaSnapshot: JSON.parse(JSON.stringify(meta)), source: "מערכת", uploadedAt: safeTrim(meta?.savedAt) || safeTrim(rec?.updatedAt) || safeTrim(rec?.createdAt), uploadedBy: safeTrim(meta?.agent?.name) || safeTrim(rec?.agentName) });
      }
      const hasAgentOps = list.some((d) => safeTrim(d?.type) === this.TYPES.agentApptOps);
      if(!hasAgentOps && payload.agentAppointmentMeta){
        const meta = payload.agentAppointmentMeta;
        const coLabel = safeTrim(meta?.companyLabel) || "חברה";
        list.unshift({ id: "doc_ops_agent_legacy", type: this.TYPES.agentApptOps, isLegacy: true, name: "דוח תפעולי — מינוי סוכן · " + coLabel, source: "מערכת", uploadedAt: safeTrim(meta?.savedAt) || safeTrim(rec?.updatedAt) || safeTrim(rec?.createdAt), uploadedBy: safeTrim(meta?.agent?.name) || safeTrim(rec?.agentName), payloadSnapshot: { agentAppointmentMeta: JSON.parse(JSON.stringify(meta)) } });
      }
      return this.sortByDateDesc(list.filter((doc) => {
        if(!doc || typeof doc !== "object") return false;
        const type = safeTrim(doc.type);
        if(type === this.TYPES.healthOps || type === this.TYPES.agentApptOps || type === this.TYPES.agentApptForm) return true;
        return !!(safeTrim(doc.name) || safeTrim(doc.url) || safeTrim(doc.dataUrl) || safeTrim(doc.fileName));
      }));
    },
    findDoc(rec, docId){
      const id = safeTrim(docId);
      if(!id) return null;
      return this.resolveListForCustomer(rec).find((doc) => String(doc?.id) === String(id)) || null;
    }
  };

  function scoreHealthPoliciesRecoverySource(newPolicies){
    const list = Array.isArray(newPolicies) ? newPolicies : [];
    if(!list.length) return 0;
    let score = list.length * 1000;
    list.forEach((policy) => {
      const prem = Number(String(policy?.premiumAfterDiscountValue ?? policy?.premiumValue ?? policy?.monthlyPremium ?? policy?.premiumMonthly ?? policy?.premium ?? 0).replace(/[^\d.\-]/g, ""));
      if(Number.isFinite(prem) && prem > 0) score += prem;
      if(safeTrim(policy?.company)) score += 50;
      if(safeTrim(policy?.type)) score += 25;
    });
    return score;
  }

  function customerRecordMatchesIdNumber(rec, idNumber){
    const target = normalizeIdValue(idNumber);
    if(!target || !rec) return false;
    if(normalizeIdValue(rec.idNumber) === target) return true;
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    const primary = payload?.primary || payload?.insureds?.[0]?.data || {};
    return normalizeIdValue(primary.idNumber) === target;
  }

  function findCustomerHealthPoliciesRecoverySources(idNumber){
    const target = normalizeIdValue(idNumber);
    if(!target) return [];
    const sources = [];
    const pushSource = (label, payload, meta = {}) => {
      if(!payload || typeof payload !== "object") return;
      const newPolicies = getNewPoliciesFromCustomerPayload(payload);
      const score = scoreHealthPoliciesRecoverySource(newPolicies);
      if(score <= 0) return;
      sources.push({
        label,
        score,
        meta,
        newPolicies: JSON.parse(JSON.stringify(newPolicies)),
        payload: JSON.parse(JSON.stringify(payload))
      });
    };

    const scanCustomers = (customers, labelPrefix) => {
      (Array.isArray(customers) ? customers : []).forEach((rec) => {
        if(!customerRecordMatchesIdNumber(rec, target)) return;
        pushSource(`${labelPrefix}: לקוח ${safeTrim(rec.fullName) || safeTrim(rec.id)}`, rec.payload, { customerId: rec.id, kind: "customer" });
      });
    };

    try {
      const raw = sessionStorage.getItem(GI_SERVER_CACHE_KEY);
      if(raw){
        const cached = JSON.parse(raw);
        scanCustomers(cached?.payload?.customers, "מטמון דפדפן (session)");
      }
    } catch(_e){}
    try {
      const raw = localStorage.getItem(LS_BACKUP_KEY);
      if(raw){
        const cached = JSON.parse(raw);
        scanCustomers(cached?.customers || cached?.payload?.customers, "גיבוי מקומי (local)");
      }
    } catch(_e){}

    scanCustomers(State.data?.customers, "מאגר נוכחי");
    (State.data?.proposals || []).forEach((prop) => {
      if(!customerRecordMatchesIdNumber(prop, target)) return;
      pushSource(`הצעה ${safeTrim(prop.id) || ""}`.trim(), prop.payload, { proposalId: prop.id, kind: "proposal" });
    });
    getElementaryReferrals().forEach((ref) => {
      if(!customerRecordMatchesIdNumber(ref, target)) return;
      pushSource(`הפניה אלמנטרי ${safeTrim(ref.id) || ""}`.trim(), ref.payload, { referralId: ref.id, kind: "referral" });
    });
    const archived = normalizeArchivedCustomersList(State.data?.meta?.archivedCustomers || []);
    archived.forEach((entry) => {
      const rec = entry?.customer || entry;
      if(!customerRecordMatchesIdNumber(rec, target)) return;
      pushSource(`ארכיון ${safeTrim(rec.fullName) || ""}`.trim(), rec.payload, { archived: true, kind: "archived" });
    });

    sources.sort((a, b) => b.score - a.score);
    const seen = new Set();
    return sources.filter((src) => {
      const key = JSON.stringify((src.newPolicies || []).map((p) => [
        safeTrim(p.id),
        safeTrim(p.company),
        safeTrim(p.type),
        safeTrim(p.monthlyPremium),
        safeTrim(p.premiumValue)
      ]));
      if(seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }

  function summarizeHealthPoliciesForRecovery(newPolicies){
    return (Array.isArray(newPolicies) ? newPolicies : []).map((policy) => {
      const monthly = safeTrim(policy?.monthlyPremium || policy?.premiumMonthly || policy?.premiumValue || policy?.premium || "");
      const annual = safeTrim(policy?.annualPremium || policy?.premiumAnnual || "");
      return {
        company: safeTrim(policy?.company) || "—",
        type: safeTrim(policy?.type) || "—",
        monthlyPremium: monthly || "—",
        annualPremium: annual || "—",
        premiumAfterDiscount: safeTrim(policy?.premiumAfterDiscount || policy?.premiumAfterDiscountValue || monthly) || monthly || "—"
      };
    });
  }

  async function recoverCustomerHealthPolicies(idNumberOrCustomerId, options = {}){
    const needle = safeTrim(idNumberOrCustomerId);
    if(!needle){
      return { ok: false, error: "חסר מזהה לקוח" };
    }
    if(!(Auth.isAdmin() || Auth.isManager())){
      return { ok: false, error: "שחזור פרמיה זמין למנהל מערכת / מנהל בלבד" };
    }
    const customer = (State.data?.customers || []).find((rec) => {
      return String(rec?.id) === String(needle) || customerRecordMatchesIdNumber(rec, needle);
    });
    if(!customer){
      return { ok: false, error: "לקוח לא נמצא ברשימה הפעילה" };
    }
    const idNumber = normalizeIdValue(customer.idNumber) || normalizeIdValue(needle);
    const sources = findCustomerHealthPoliciesRecoverySources(idNumber);
    if(!sources.length){
      return { ok: false, error: "לא נמצא מקור שחזור לפרמיית בריאות/סיכונים (בדוק גיבוי בדפדפן אחר או הצעה ישנה)", idNumber };
    }
    const best = sources[0];
    const existingPayload = customer.payload && typeof customer.payload === "object" ? customer.payload : {};
    const mergedPayload = mergeElementarySaveWithExistingCustomerPayload(existingPayload, {
      ...JSON.parse(JSON.stringify(existingPayload)),
      newPolicies: best.newPolicies
    });
    const record = normalizeCustomerRecord({
      ...customer,
      payload: mergedPayload,
      newPoliciesCount: best.newPolicies.length,
      updatedAt: nowISO()
    });
    const directRow = Storage.buildCustomerRows({ customers: [record] })[0];
    const directSave = await Storage.upsertSingleRow(SUPABASE_TABLES.customers, directRow);
    if(!directSave?.ok){
      return { ok: false, error: safeTrim(directSave?.error) || "שמירה לשרת נכשלה", idNumber, preview: summarizeHealthPoliciesForRecovery(best.newPolicies) };
    }
    const idx = (State.data?.customers || []).findIndex((row) => String(row?.id) === String(record.id));
    if(idx >= 0) State.data.customers[idx] = record;
    else State.data.customers.unshift(record);
    State.data.meta.updatedAt = nowISO();
    refreshStateShadows();
    appendAuditLog({
      type: "customer_health_premium_recovered",
      entity: "customer",
      entityId: safeTrim(record.id),
      label: "שוחזרה פרמיית בריאות/סיכונים לתיק לקוח",
      actorName: safeTrim(Auth?.current?.name),
      details: { idNumber, source: best.label, policies: summarizeHealthPoliciesForRecovery(best.newPolicies) }
    });
    try { await App.persist("שוחזרה פרמיית בריאות לתיק לקוח"); } catch(_e){}
    try { CustomersUI.render(); } catch(_e){}
    if(CustomersUI?.currentId && String(CustomersUI.currentId) === String(record.id)){
      try { CustomersUI.refreshOpenCustomerPreservingState(); } catch(_e){}
    }
    return {
      ok: true,
      idNumber,
      customerId: record.id,
      source: best.label,
      policies: summarizeHealthPoliciesForRecovery(best.newPolicies),
      allSources: sources.map((src) => ({ label: src.label, score: src.score, policies: summarizeHealthPoliciesForRecovery(src.newPolicies) }))
    };
  }

  function inferProposalFlowType(payload = {}){
    const raw = safeTrim(payload?.flowType).toLowerCase();
    if(raw === "elementary" || raw === "health") return raw;
    const insureds = Array.isArray(payload?.insureds) ? payload.insureds : [];
    if(Array.isArray(payload?.elementaryPolicies) && payload.elementaryPolicies.length) return "elementary";
    const hasElementaryVehicleData = insureds.some((ins) => {
      const d = ins && typeof ins === "object" ? (ins.data || {}) : {};
      if(Array.isArray(d.elementaryProductPricing) && d.elementaryProductPricing.some((r) => {
        const prem = String(r?.premium ?? "").replace(/[^\d.,\-]/g, "");
        return prem && Number(String(prem).replace(",", ".")) > 0;
      })) return true;
      return (Array.isArray(d.elementaryVehiclePolicies) && d.elementaryVehiclePolicies.length)
        || safeTrim(d?.elementaryHarImport?.fileName)
        || Number(d?.elementaryHarImport?.count || 0) > 0;
    });
    return hasElementaryVehicleData ? "elementary" : "health";
  }

  function inferProposalElementaryProduct(payload = {}){
    const explicit = safeTrim(payload?.elementaryProduct);
    if(explicit) return explicit;
    const insureds = Array.isArray(payload?.insureds) ? payload.insureds : [];
    const hasVehicleData = insureds.some((ins) => {
      const d = ins && typeof ins === "object" ? (ins.data || {}) : {};
      return (Array.isArray(d.elementaryVehiclePolicies) && d.elementaryVehiclePolicies.length)
        || safeTrim(d?.elementaryHarImport?.fileName)
        || Number(d?.elementaryHarImport?.count || 0) > 0;
    });
    return hasVehicleData ? "vehicle" : "";
  }

  /** מקסימום id שלב באשף (בריאות: עד 8 אחרי סינון 41; אלמנטרי: עד 6) — לשימוש בנרמול/שמירה ל-DB */
  function getMaxProposalWizardStepIdFromPayload(payload){
    try {
      const p = payload && typeof payload === "object" ? payload : {};
      const flow = inferProposalFlowType(p);
      if(flow === "elementary") return 6;
      if(typeof Wizard !== "undefined" && Wizard && Array.isArray(Wizard.steps)){
        const ids = Wizard.steps
          .filter((s) => Number(s?.id) !== 41)
          .map((s) => Number(s.id))
          .filter((n) => Number.isFinite(n) && n > 0);
        if(ids.length) return Math.max(...ids);
      }
      return 8;
    } catch(_e){
      return 8;
    }
  }

  function normalizeProposalRecord(p, idx=0){
    const payload = p?.payload && typeof p.payload === "object" ? p.payload : {};
    const operational = payload?.operational && typeof payload.operational === "object" ? payload.operational : {};
    const primary = operational?.primary || payload?.insureds?.[0]?.data || {};
    const fullName = safeTrim(p?.fullName) || safeTrim(((primary.firstName || "") + " " + (primary.lastName || "")).trim()) || "הצעה ללא שם";
    const idNumber = safeTrim(p?.idNumber) || safeTrim(primary.idNumber);
    const phone = safeTrim(p?.phone) || safeTrim(primary.phone);
    const email = safeTrim(p?.email) || safeTrim(primary.email);
    const city = safeTrim(p?.city) || safeTrim(primary.city);
    const agentName = safeTrim(p?.agentName) || safeTrim(p?.createdBy) || "";
    const createdAt = safeTrim(p?.createdAt) || nowISO();
    const updatedAt = safeTrim(p?.updatedAt) || createdAt;
    const stepMax = getMaxProposalWizardStepIdFromPayload(payload);
    const currentStep = Math.max(1, Math.min(stepMax, Number(p?.currentStep || payload?.currentStep || 1) || 1));
    const insuredCount = Number(p?.insuredCount || payload?.insureds?.length || 0) || 0;
    payload.flowType = inferProposalFlowType(payload);
    payload.elementaryProduct = payload.flowType === "elementary" ? inferProposalElementaryProduct(payload) : "";
    return {
      id: safeTrim(p?.id) || ("prop_" + idx + "_" + Math.random().toString(16).slice(2)),
      status: safeTrim(p?.status) || "פתוחה",
      fullName,
      idNumber,
      phone,
      email,
      city,
      agentName,
      agentId: safeTrim(p?.agentId) || safeTrim(p?.createdByKey) || safeTrim(payload?.agentId) || "",
      createdBy: safeTrim(p?.createdBy) || safeTrim(payload?.createdBy) || "",
      agentRole: safeTrim(p?.agentRole) || "",
      createdAt,
      updatedAt,
      currentStep,
      insuredCount,
      payload
    };
  }

  function normalizeElementaryReferral(raw, idx = 0){
    const input = raw && typeof raw === "object" ? raw : {};
    const payload = input?.payload && typeof input.payload === "object" ? input.payload : {};
    const primary = payload?.primary || payload?.insureds?.[0]?.data || {};
    const fullName = safeTrim(input?.fullName)
      || safeTrim(((primary.firstName || "") + " " + (primary.lastName || "")).trim())
      || "לקוח ללא שם";
    const statusRaw = safeTrim(input?.status).toLowerCase();
    const status = (statusRaw === "done" || statusRaw === "handled" || statusRaw === "טופל") ? "done" : "pending";
    const submittedAt = safeTrim(input?.submittedAt) || safeTrim(input?.createdAt) || nowISO();
    return {
      id: safeTrim(input?.id) || ("elemref_" + idx + "_" + Math.random().toString(16).slice(2)),
      status,
      customerId: safeTrim(input?.customerId),
      fullName,
      idNumber: safeTrim(input?.idNumber) || normalizeIdValue(primary.idNumber),
      phone: safeTrim(input?.phone) || normalizePhoneValue(primary.phone),
      city: safeTrim(input?.city) || safeTrim(primary.city),
      agentName: safeTrim(input?.agentName) || safeTrim(input?.submittedBy) || "",
      agentId: safeTrim(input?.agentId) || "",
      elementaryProduct: safeTrim(input?.elementaryProduct) || safeTrim(payload?.elementaryProduct) || inferProposalElementaryProduct(payload),
      submittedAt,
      updatedAt: safeTrim(input?.updatedAt) || submittedAt,
      handledAt: safeTrim(input?.handledAt) || "",
      handledBy: safeTrim(input?.handledBy) || "",
      continueFromStep: Math.max(0, Number(input?.continueFromStep || payload?.elementaryReferralMeta?.continueFromStep || 0) || 0),
      sourceFlow: safeTrim(input?.sourceFlow) || safeTrim(payload?.elementaryReferralMeta?.sourceFlow) || "",
      requestedCoverageType: safeTrim(input?.requestedCoverageType) || getRequestedCoverageFromPayload(payload),
      agentTrackStatus: safeTrim(input?.agentTrackStatus) || "waiting_ops",
      opsTouchedAt: safeTrim(input?.opsTouchedAt) || "",
      opsTouchedBy: safeTrim(input?.opsTouchedBy) || "",
      elementaryHandlerName: safeTrim(input?.elementaryHandlerName) || "",
      elementaryHandlerAt: safeTrim(input?.elementaryHandlerAt) || "",
      issuedAt: safeTrim(input?.issuedAt) || "",
      issuedBy: safeTrim(input?.issuedBy) || "",
      proposalReadyAt: safeTrim(input?.proposalReadyAt) || "",
      proposalReadyBy: safeTrim(input?.proposalReadyBy) || "",
      elementaryPriceQuotes: normalizeElementaryPriceQuotes(input?.elementaryPriceQuotes),
      quoteSentAt: safeTrim(input?.quoteSentAt) || "",
      quoteSentBy: safeTrim(input?.quoteSentBy) || "",
      agentSetupCompletedAt: safeTrim(input?.agentSetupCompletedAt) || "",
      agentSetupCompletedBy: safeTrim(input?.agentSetupCompletedBy) || "",
      selectedAgentQuoteId: safeTrim(input?.selectedAgentQuoteId) || "",
      elementaryPolicyFiles: Array.isArray(input?.elementaryPolicyFiles) ? input.elementaryPolicyFiles : [],
      payload
    };
  }

  function applyElementaryQuoteVariantToInsuredData(insData, quote){
    const d = insData && typeof insData === "object" ? insData : {};
    const variant = quote && typeof quote === "object" ? quote : null;
    if(!variant) return false;
    const want = getElementaryCoverageProductRowsFromPayload({ insureds: [{ data: d }], primary: d });
    const lineMap = {};
    (variant.products || []).forEach((line) => {
      const key = safeTrim(line?.productKey);
      if(key) lineMap[key] = line;
    });
    const svc = variant.additionalServices && typeof variant.additionalServices === "object"
      ? variant.additionalServices
      : { details: "" };
    d.elementaryProductPricing = want.map((w) => {
      const hit = lineMap[w.key];
      return {
        productKey: w.key,
        label: w.label,
        premium: safeTrim(hit?.premium) || "",
        installments: safeTrim(hit?.installments) || "",
        company: safeTrim(hit?.company) || ""
      };
    });
    d._elementaryQuoteAdditionalDetails = safeTrim(svc.details);
    d._agentSelectedQuoteId = safeTrim(variant.id);
    d._agentSelectedQuoteLabel = safeTrim(variant.label);
    d._elemPoliciesLifecycle = "pending_underwriting";
    return true;
  }

  function getElementaryPolicyLifecyclePresentation(lifecycleRaw){
    const key = safeTrim(lifecycleRaw).toLowerCase();
    if(key === "issued"){
      return { badgeText: "הופקה", badgeClass: "is-elementary-issued" };
    }
    if(key === "active"){
      return { badgeText: "פעילה", badgeClass: "is-elementary-active" };
    }
    if(key === "pending_underwriting" || key === "pending"){
      return { badgeText: "ממתינה לאישור חיתום", badgeClass: "is-pending-underwriting" };
    }
    return { badgeText: "אלמנטרי · חדש", badgeClass: "is-elementary" };
  }

  async function touchElementaryReferralAgentSetupComplete(referralRef, options = {}){
    const rec = typeof referralRef === "string" ? findElementaryReferralById(referralRef) : referralRef;
    if(!rec || rec.status !== "pending") return null;
    const nextPayload = options.payload && typeof options.payload === "object"
      ? options.payload
      : rec.payload;
    const updated = patchElementaryReferral(rec.id, {
      agentTrackStatus: "agent_setup_complete",
      agentSetupCompletedAt: nowISO(),
      agentSetupCompletedBy: safeTrim(options.by) || safeTrim(Auth?.current?.name),
      selectedAgentQuoteId: safeTrim(options.selectedQuoteId) || safeTrim(nextPayload?.primary?._agentSelectedQuoteId) || safeTrim(rec.selectedAgentQuoteId),
      customerId: safeTrim(options.customerId) || safeTrim(rec.customerId),
      payload: nextPayload
    });
    await persistElementaryReferralsQuiet("הנציג השלים הקמת הצעה — ממתין להפקה");
    try { ProposalsUI.render(); } catch(_e){}
    try { AgentElementaryTrackingUI.render(); } catch(_e){}
    try { ElementaryPendingUI.render(); } catch(_e){}
    try { ElementaryDashboardUI.refreshAfterReferralChange(); } catch(_e){}
    try { CustomersUI.render(); } catch(_e){}
    return updated;
  }

  function normalizeDeletedElementaryReferralIds(raw){
    const seen = new Set();
    const out = [];
    (Array.isArray(raw) ? raw : []).forEach((value) => {
      const id = safeTrim(value);
      if(!id || seen.has(id)) return;
      seen.add(id);
      out.push(id);
    });
    return out.slice(-400);
  }

  function getDeletedElementaryReferralIdSet(){
    return new Set(normalizeDeletedElementaryReferralIds(State.data?.meta?.deletedElementaryReferralIds));
  }

  function tombstoneElementaryReferralId(referralId){
    const id = safeTrim(referralId);
    if(!id) return;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const list = normalizeDeletedElementaryReferralIds(State.data.meta.deletedElementaryReferralIds);
    if(!list.includes(id)) list.push(id);
    State.data.meta.deletedElementaryReferralIds = normalizeDeletedElementaryReferralIds(list);
  }

  function findProposalsLinkedToElementaryReferral(rec){
    if(!rec) return [];
    const idNumber = normalizeIdValue(rec.idNumber);
    return (Array.isArray(State.data?.proposals) ? State.data.proposals : []).filter((prop) => {
      if(idNumber && normalizeIdValue(prop?.idNumber) === idNumber && inferProposalFlowType(prop?.payload) === "elementary") return true;
      return false;
    });
  }

  function removeProposalAssignInboxForProposalIds(proposalIds){
    const idSet = new Set((Array.isArray(proposalIds) ? proposalIds : []).map((value) => String(value)).filter(Boolean));
    if(!idSet.size) return;
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const list = normalizeProposalAssignInboxList(State.data.meta.proposalAssignInbox || []);
    State.data.meta.proposalAssignInbox = list.filter((entry) => !idSet.has(String(entry.proposalId)));
  }

  function getElementaryReferrals(){
    const tombstones = getDeletedElementaryReferralIdSet();
    const rows = Array.isArray(State.data?.meta?.elementaryReferrals) ? State.data.meta.elementaryReferrals : [];
    return rows
      .map((row, idx) => normalizeElementaryReferral(row, idx))
      .filter((row) => row && !tombstones.has(String(row.id)));
  }

  function setElementaryReferrals(list){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    State.data.meta.elementaryReferrals = (Array.isArray(list) ? list : [])
      .map((row, idx) => normalizeElementaryReferral(row, idx))
      .filter(Boolean);
    State.data.meta.updatedAt = nowISO();
  }

  function findPendingElementaryReferralByCustomerId(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    return getElementaryReferrals().find((rec) => safeTrim(rec.customerId) === cid && rec.status === "pending") || null;
  }

  function findPendingElementaryReferralByIdNumber(idNumber){
    const id = normalizeIdValue(idNumber);
    if(!id) return null;
    return getElementaryReferrals().find((rec) => {
      if(rec.status !== "pending") return false;
      return normalizeIdValue(rec.idNumber) === id;
    }) || null;
  }

  function findCustomerByIdNumber(idNumber){
    const id = normalizeIdValue(idNumber);
    if(!id) return null;
    return (Array.isArray(State.data?.customers) ? State.data.customers : []).find((rec) => normalizeIdValue(rec.idNumber) === id) || null;
  }

  function findArchivedCustomerRecordById(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    const archived = normalizeArchivedCustomersList(State.data?.meta?.archivedCustomers || []);
    const entry = archived.find((row) => String(row?.id) === String(cid) || String(row?.customer?.id) === String(cid));
    return entry?.customer || null;
  }

  function findCustomerShadowRecordById(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    const shadow = Array.isArray(State.data?.meta?.customersShadow) ? State.data.meta.customersShadow : [];
    return shadow.find((rec) => String(rec?.id) === String(cid)) || null;
  }

  /** תיק לקוח לפי מזהה — פעיל, גנוז או shadow */
  function findCustomerRecordById(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    const active = (Array.isArray(State.data?.customers) ? State.data.customers : [])
      .find((rec) => String(rec?.id) === String(cid));
    if(active) return active;
    const archived = findArchivedCustomerRecordById(cid);
    if(archived) return archived;
    return findCustomerShadowRecordById(cid);
  }

  function findArchivedCustomerByIdNumber(idNumber){
    const id = normalizeIdValue(idNumber);
    if(!id) return null;
    const archived = normalizeArchivedCustomersList(State.data?.meta?.archivedCustomers || []);
    for(const entry of archived){
      const rec = entry?.customer;
      if(rec && normalizeIdValue(rec.idNumber) === id) return rec;
    }
    return null;
  }

  /** מאתר תיק לקוח להפקת אלמנטרי — כולל הפניה בלבד / ארכיון / התאמה לפי ת״ז */
  function resolveCustomerForElementaryReferral(referral){
    const rec = referral && typeof referral === "object" ? referral : null;
    if(!rec) return null;
    let customer = findCustomerRecordById(rec.customerId);
    if(!customer && rec.idNumber){
      customer = findCustomerByIdNumber(rec.idNumber) || findArchivedCustomerByIdNumber(rec.idNumber);
    }
    if(!customer){
      const payload = rec.payload && typeof rec.payload === "object" ? rec.payload : {};
      const hasPayload = !!(
        (Array.isArray(payload.insureds) && payload.insureds.length)
        || (payload.primary && typeof payload.primary === "object")
        || (Array.isArray(payload.elementaryPolicies) && payload.elementaryPolicies.length)
      );
      if(hasPayload){
        customer = normalizeCustomerRecord({
          id: safeTrim(rec.customerId) || ("cust_elemref_" + safeTrim(rec.id)),
          fullName: rec.fullName,
          idNumber: rec.idNumber,
          phone: rec.phone,
          email: safeTrim(rec.email),
          city: rec.city,
          agentName: rec.agentName,
          payload: JSON.parse(JSON.stringify(payload))
        }, 0);
      }
    }
    if(customer && safeTrim(rec.customerId) && String(customer.id) !== String(rec.customerId)){
      customer = normalizeCustomerRecord({ ...customer, id: safeTrim(rec.customerId) }, 0);
    }
    return customer;
  }

  function ensureCustomerInActiveList(customer){
    const record = customer && typeof customer === "object" ? normalizeCustomerRecord(customer, 0) : null;
    if(!record?.id) return null;
    State.data.customers = Array.isArray(State.data.customers) ? State.data.customers : [];
    const idx = State.data.customers.findIndex((row) => String(row?.id) === String(record.id));
    if(idx >= 0){
      State.data.customers[idx] = record;
    } else {
      State.data.customers.unshift(record);
    }
    refreshStateShadows();
    return record;
  }

  function ingestCustomerRowFromServer(row){
    if(!row || typeof row !== "object") return null;
    const customer = Storage.mapCustomerRow(row, 0);
    if(!customer?.id) return null;
    if(isServerArchivedCustomerRecord(customer)){
      State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
      const prevArchived = normalizeArchivedCustomersList(State.data.meta.archivedCustomers || []);
      State.data.meta.archivedCustomers = mergeArchivedCustomerLists(prevArchived, [normalizeArchivedCustomerEntry({
        customer,
        archivedAt: safeTrim(row?.updated_at || customer.updatedAt) || nowISO(),
        archivedBy: safeTrim(row?.updated_by) || "שרת"
      })]);
      refreshStateShadows();
      return customer;
    }
    return ensureCustomerInActiveList(customer);
  }

  async function fetchCustomerRecordFromServer(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    try {
      const connection = await Storage.waitForConnection({ retries: 2, delayMs: 800 });
      if(!connection?.ok) return null;
    } catch(_e){}
    try {
      const res = await Storage.loadSingleRow(SUPABASE_TABLES.customers, cid);
      if(!res?.ok || !res.data) return null;
      return ingestCustomerRowFromServer(res.data);
    } catch(err){
      try { console.warn("[fetchCustomerRecordFromServer]", cid, err); } catch(_e){}
      return null;
    }
  }

  async function fetchCustomerRecordFromServerByIdNumber(idNumber){
    const id = normalizeIdValue(idNumber);
    if(!id) return null;
    try {
      const connection = await Storage.waitForConnection({ retries: 2, delayMs: 800 });
      if(!connection?.ok) return null;
    } catch(_e){}
    try {
      const client = Storage.getClient();
      const { data, error } = await Storage.withRetry(
        () => client.from(SUPABASE_TABLES.customers).select("*").eq("id_number", id).order("updated_at", { ascending: false }).limit(1).maybeSingle(),
        "טעינת לקוח לפי ת״ז"
      );
      if(error) throw error;
      if(data) return ingestCustomerRowFromServer(data);
    } catch(primaryErr){
      try {
        const rows = await Storage.restRequest(
          SUPABASE_TABLES.customers + "?id_number=eq." + encodeURIComponent(id) + "&select=*&order=updated_at.desc&limit=1",
          { method: "GET" }
        );
        const row = Array.isArray(rows) ? (rows[0] || null) : (rows || null);
        if(row) return ingestCustomerRowFromServer(row);
      } catch(restErr){
        try { console.warn("[fetchCustomerRecordFromServerByIdNumber]", id, primaryErr, restErr); } catch(_e){}
      }
    }
    return null;
  }

  /** מאתר תיק לקוח להפקה — מקומי ואז מהשרת בזמן הלחיצה */
  async function ensureCustomerForElementaryReferral(referral){
    const rec = referral && typeof referral === "object" ? referral : null;
    if(!rec) return null;
    let customer = resolveCustomerForElementaryReferral(rec);
    if(customer){
      if(isServerArchivedCustomerRecord(customer)) return customer;
      return ensureCustomerInActiveList(customer) || customer;
    }
    const customerId = safeTrim(rec.customerId);
    if(customerId){
      customer = await fetchCustomerRecordFromServer(customerId);
      if(customer) return customer;
    }
    if(rec.idNumber){
      customer = await fetchCustomerRecordFromServerByIdNumber(rec.idNumber);
      if(customer) return customer;
    }
    return resolveCustomerForElementaryReferral(rec);
  }

  function findElementaryReferralById(referralId){
    const id = safeTrim(referralId);
    if(!id) return null;
    return getElementaryReferrals().find((rec) => String(rec.id) === String(id)) || null;
  }

  function findElementaryReferralByCustomerId(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    return getElementaryReferrals().find((rec) => safeTrim(rec.customerId) === cid) || null;
  }

  function getElementaryReferralSourceFlow(rec){
    const row = rec && typeof rec === "object" ? rec : {};
    return safeTrim(row.sourceFlow) || safeTrim(row.payload?.elementaryReferralMeta?.sourceFlow) || "";
  }

  function isCarInsuranceClickReferral(rec){
    return getElementaryReferralSourceFlow(rec) === "carInsuranceClick";
  }

  /** תווית מקור בטבלאות — רכב בקליק (מוצג גם בממתינים לטיפול וגם בדשבורד אלמנטרי) */
  function elementaryReferralUsesDashboardPendingOnly(rec){
    return isCarInsuranceClickReferral(rec);
  }

  const GI_ELEM_REFERRAL_PIN_MS = 120000;
  const _elemReferralPinUntil = new Map();

  function pinElementaryReferralLocally(referralId, ms = GI_ELEM_REFERRAL_PIN_MS){
    const id = safeTrim(referralId);
    if(!id) return;
    _elemReferralPinUntil.set(id, Date.now() + Math.max(30000, Number(ms) || GI_ELEM_REFERRAL_PIN_MS));
  }

  function getPinnedElementaryReferralIdSet(){
    const now = Date.now();
    _elemReferralPinUntil.forEach((until, id) => {
      if(until <= now) _elemReferralPinUntil.delete(id);
    });
    return new Set(_elemReferralPinUntil.keys());
  }

  function mergeMetaElementaryReferralsIntoState(localState, serverMeta){
    if(!localState?.meta) return;
    const remote = serverMeta && typeof serverMeta === "object" ? serverMeta : {};
    const localRefs = Array.isArray(localState.meta.elementaryReferrals) ? localState.meta.elementaryReferrals : [];
    const serverRefs = Array.isArray(remote.elementaryReferrals) ? remote.elementaryReferrals : [];
    const mergedTombstones = normalizeDeletedElementaryReferralIds([
      ...(localState.meta.deletedElementaryReferralIds || []),
      ...(remote.deletedElementaryReferralIds || [])
    ]);
    localState.meta.deletedElementaryReferralIds = mergedTombstones;
    localState.meta.elementaryReferrals = mergeElementaryReferralsListsByRecency(localRefs, serverRefs, {
      tombstones: new Set(mergedTombstones),
      pinnedIds: getPinnedElementaryReferralIdSet()
    });
  }

  function focusElementaryDashboardPendingTab(){
    if(!Auth.isElementary()) return;
    ElementaryDashboardUI._tab = "pending";
  }

  function focusElementaryDashboardAwaitingIssueTab(){
    if(!Auth.isElementary()) return;
    ElementaryDashboardUI._tab = "awaiting_issue";
  }

  /** נציג סיים הקמת הצעה — האלמנטרי עדיין צריך להפיק לפני ירידה מממתינים לטיפול */
  function referralAwaitingElementaryIssue(referral){
    const rec = referral && typeof referral === "object" ? referral : null;
    if(!rec || rec.status !== "pending") return false;
    const track = safeTrim(rec.agentTrackStatus);
    if(track === "agent_setup_complete") return true;
    if(track === "waiting_elementary"){
      // הגשה ראשונית (ללא תיק לקוח) — עדיין ממתין לטיפול אלמנטרי, לא להפקה
      if(safeTrim(rec.customerId) && safeTrim(rec.agentSetupCompletedAt)) return true;
      const src = getElementaryReferralSourceFlow(rec);
      // נתון ישן: נציג סיים הקמה אך סטטוס לא עודכן (רכב בקליק) — רק אחרי סיום הקמה בפועל
      if(src === "carInsuranceClick" && safeTrim(rec.customerId) && safeTrim(rec.agentSetupCompletedAt)) return true;
    }
    if(track === "proposal_submitting" && safeTrim(rec.customerId)){
      if(safeTrim(rec.agentSetupCompletedAt)) return true;
      const src = getElementaryReferralSourceFlow(rec);
      if(src === "carInsuranceClick" && safeTrim(rec.customerId) && safeTrim(rec.agentSetupCompletedAt)) return true;
      if(safeTrim(rec.quoteSentAt) && safeTrim(rec.proposalReadyAt)) return true;
    }
    return false;
  }

  function elementaryReferralShouldCompleteAgentSetupOnFinish(rec, options = {}){
    if(!rec || rec.status !== "pending") return false;
    if(referralAwaitingElementaryIssue(rec)) return true;
    const track = safeTrim(rec.agentTrackStatus);
    if(track === "issued" || track === "done") return false;
    if(track === "quote_ready") return true;
    const savedCustomerId = safeTrim(options.customerId);
    if(savedCustomerId && safeTrim(rec.customerId) && safeTrim(rec.customerId) !== savedCustomerId) return false;
    const src = getElementaryReferralSourceFlow(rec);
    if(src === "carInsuranceClick"){
      return track === "quote_ready" || track === "proposal_submitting" || !!safeTrim(rec.quoteSentAt);
    }
    return !!safeTrim(rec.quoteSentAt);
  }

  function elementaryReferralIsTerminal(rec){
    if(!rec) return true;
    if(safeTrim(rec.issuedAt)) return true;
    if(safeTrim(rec.agentTrackStatus) === "issued") return true;
    const statusRaw = safeTrim(rec.status).toLowerCase();
    if(statusRaw === "done" || statusRaw === "handled" || statusRaw === "טופל") return true;
    return false;
  }

  function mergeElementaryReferralsListsByRecency(localList, remoteList, options = {}){
    const tombstones = options?.tombstones instanceof Set
      ? options.tombstones
      : getDeletedElementaryReferralIdSet();
    const pinnedIds = options?.pinnedIds instanceof Set ? options.pinnedIds : getPinnedElementaryReferralIdSet();
    const map = new Map();
    const consider = (row, idx) => {
      const normalized = normalizeElementaryReferral(row, idx);
      if(!normalized?.id) return;
      if(tombstones.has(String(normalized.id))) return;
      const key = String(normalized.id);
      const existing = map.get(key);
      if(!existing){
        map.set(key, normalized);
        return;
      }
      const existingTerminal = elementaryReferralIsTerminal(existing);
      const incomingTerminal = elementaryReferralIsTerminal(normalized);
      if(incomingTerminal && !existingTerminal){
        if(pinnedIds.has(key)) return;
        map.set(key, normalized);
        return;
      }
      if(existingTerminal && !incomingTerminal) return;
      if(compareIsoStamps(normalized.updatedAt, existing.updatedAt) >= 0){
        map.set(key, normalized);
      }
    };
    (Array.isArray(remoteList) ? remoteList : []).forEach(consider);
    (Array.isArray(localList) ? localList : []).forEach(consider);
    (Array.isArray(localList) ? localList : []).forEach((row, idx) => {
      const normalized = normalizeElementaryReferral(row, idx);
      if(!normalized?.id) return;
      const key = String(normalized.id);
      if(!pinnedIds.has(key) || tombstones.has(key)) return;
      map.set(key, normalized);
    });
    return normalizeElementaryReferralsList(Array.from(map.values()));
  }

  function elementaryReferralShowsInPendingQueue(rec){
    if(!rec || elementaryReferralIsTerminal(rec)) return false;
    if(rec.status !== "pending") return false;
    if(referralAwaitingElementaryIssue(rec)) return true;
    if(safeTrim(rec.agentTrackStatus) === "proposal_submitting") return false;
    return true;
  }

  /** הצעות פעילות אצל נציג — לאחר הפקה יורדות מהרשימה; מעקב מלא נשאר בתיק הלקוח */
  function elementaryReferralShowsInAgentActiveQueue(rec){
    return !!(rec && !elementaryReferralIsTerminal(rec));
  }

  function removeElementaryReferralFromActiveViews(referralId){
    const id = safeTrim(referralId);
    if(!id) return;
    try { ElementaryPendingUI.removeReferralRow(id); } catch(_e){}
    try { ProposalsUI.removeReferralRow(id); } catch(_e){}
    try { AgentElementaryTrackingUI.removeReferralRow(id); } catch(_e){}
    try { ElementaryDashboardUI.removeReferralCard(id); } catch(_e){}
  }

  /** מתקן הפניות רכב-בקליק שנשמרו בטעות כ-proposal_submitting אחרי סיום הקמת הצעה */
  function repairStuckElementaryReferralsAwaitingIssue(){
    const list = getElementaryReferrals();
    let changed = false;
    const next = list.map((rec, idx) => {
      if(rec.status !== "pending" || safeTrim(rec.agentTrackStatus) !== "proposal_submitting") return rec;
      if(!referralAwaitingElementaryIssue(rec)) return rec;
      changed = true;
      return normalizeElementaryReferral({
        ...rec,
        agentTrackStatus: "agent_setup_complete",
        agentSetupCompletedAt: safeTrim(rec.agentSetupCompletedAt) || safeTrim(rec.proposalReadyAt) || nowISO(),
        agentSetupCompletedBy: safeTrim(rec.agentSetupCompletedBy) || safeTrim(rec.proposalReadyBy) || safeTrim(rec.agentName) || ""
      }, idx);
    });
    if(changed) setElementaryReferrals(next);
    return changed;
  }

  function normalizeProposalAssignInboxEntry(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    return {
      id: safeTrim(input.id) || ("pbinv_" + Math.random().toString(16).slice(2) + "_" + Date.now().toString(16)),
      targetAgentId: safeTrim(input.targetAgentId),
      targetAgentName: safeTrim(input.targetAgentName),
      fromName: safeTrim(input.fromName),
      proposalId: safeTrim(input.proposalId),
      proposalLabel: safeTrim(input.proposalLabel),
      at: safeTrim(input.at) || nowISO()
    };
  }

  function normalizeProposalAssignInboxList(raw){
    const arr = (Array.isArray(raw) ? raw : [])
      .map(normalizeProposalAssignInboxEntry)
      .filter((e) => safeTrim(e.targetAgentId) && safeTrim(e.proposalId));
    return arr.slice(-120);
  }

  function pushProposalAssignInboxEntry(entry){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const list = normalizeProposalAssignInboxList(State.data.meta.proposalAssignInbox || []);
    const next = normalizeProposalAssignInboxEntry(entry);
    if(!safeTrim(next.targetAgentId) || !safeTrim(next.proposalId)) return false;
    list.push(next);
    State.data.meta.proposalAssignInbox = normalizeProposalAssignInboxList(list);
    bumpMetaSyncClock(State.data.meta, "proposalInbox");
    return true;
  }

  function proposalAssignInboxMatchesCurrentUser(entry){
    if(!entry || !Auth.current) return false;
    const myId = safeTrim(Auth.current.id);
    const tid = safeTrim(entry.targetAgentId);
    if(myId && tid && myId === tid) return true;
    const myName = safeTrim(Auth.current.name);
    const tname = safeTrim(entry.targetAgentName);
    return !!(myName && tname && myName === tname);
  }

  const ProposalAssignInbox = {
    _flushBusy: false,
    async flushForCurrentUser(){
      if(this._flushBusy || !Auth.current) return;
      State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
      const inbox = normalizeProposalAssignInboxList(State.data.meta.proposalAssignInbox || []);
      const mine = inbox.filter((e) => proposalAssignInboxMatchesCurrentUser(e));
      if(!mine.length) return;
      this._flushBusy = true;
      try {
        const rest = inbox.filter((e) => !proposalAssignInboxMatchesCurrentUser(e));
        State.data.meta.proposalAssignInbox = normalizeProposalAssignInboxList(rest);
        bumpMetaSyncClock(State.data.meta, "proposalInbox");
        mine.forEach((ev) => {
          const from = safeTrim(ev.fromName) || "נציג";
          const label = safeTrim(ev.proposalLabel) || "הצעה";
          try {
            window.showToast?.({
              title: "התקבלה הצעה חדשה",
              text: `מאת: ${from} · ${label}`,
              variant: "info",
              durationMs: 7200
            });
          } catch(_e){}
          try {
            void DesktopNotifications?.notify?.("התקבלה הצעה חדשה", { body: `מאת: ${from} · ${label}`, tag: `gi-proposal-assign-${safeTrim(ev.id)}` });
          } catch(_e){}
        });
        try {
          await App.persist("נקה התראות שיוך הצעה", { skipProposalsSync: true, metaOnly: true, metaSyncScopes: ["proposalInbox"], silent: true });
        } catch(_e){}
      } finally {
        this._flushBusy = false;
      }
    }
  };

  function normalizeCampaignLeadAssignInboxEntry(raw){
    const input = raw && typeof raw === "object" ? raw : {};
    return {
      id: safeTrim(input.id) || ("clinv_" + Math.random().toString(16).slice(2) + "_" + Date.now().toString(16)),
      targetAgentId: safeTrim(input.targetAgentId),
      targetAgentName: safeTrim(input.targetAgentName),
      fromName: safeTrim(input.fromName),
      leadId: safeTrim(input.leadId),
      customerName: safeTrim(input.customerName),
      phone: safeTrim(input.phone),
      campaignLabel: safeTrim(input.campaignLabel),
      at: safeTrim(input.at) || nowISO()
    };
  }

  function normalizeCampaignLeadAssignInboxList(raw){
    const arr = (Array.isArray(raw) ? raw : [])
      .map(normalizeCampaignLeadAssignInboxEntry)
      .filter((e) => safeTrim(e.targetAgentId) && safeTrim(e.leadId));
    return arr.slice(-120);
  }

  function mergeCampaignLeadAssignInboxLists(localRaw, serverRaw){
    const map = new Map();
    [...(Array.isArray(serverRaw) ? serverRaw : []), ...(Array.isArray(localRaw) ? localRaw : [])].forEach((row, idx) => {
      const normalized = normalizeCampaignLeadAssignInboxEntry(row);
      const key = safeTrim(normalized.id) || ("clinv_merge_" + idx);
      const existing = map.get(key);
      if(!existing || compareIsoStamps(normalized.at, existing.at) >= 0) map.set(key, normalized);
    });
    return normalizeCampaignLeadAssignInboxList(Array.from(map.values()));
  }

  function campaignLeadAssignInboxMatchesCurrentUser(entry){
    if(!entry || !Auth.current) return false;
    const myIds = getCampaignLeadSessionAgentIds();
    const tid = safeTrim(entry.targetAgentId);
    if(tid && myIds.has(tid)) return true;
    const myName = safeTrim(Auth.current.name);
    const tname = safeTrim(entry.targetAgentName);
    if(myName && tname && myName === tname) return true;
    const agentName = safeTrim(findAgentRecordForSession()?.name);
    if(agentName && tname && agentName === tname) return true;
    const agentUsername = safeTrim(findAgentRecordForSession()?.username);
    if(agentUsername && tname && agentUsername === tname) return true;
    return false;
  }

  function campaignLeadRowMatchesCurrentAgent(row){
    if(!row || !Auth.current) return false;
    const lead = row.assignedAgentId !== undefined || row.assigned_agent_id !== undefined
      ? normalizeCampaignLead({
          assignedAgentId: row.assigned_agent_id || row.assignedAgentId,
          assignedAgentName: row.assigned_agent_name || row.assignedAgentName,
          description: row.description,
          additionalAgents: parseCampaignLeadMetaFromDescription(row.description).additionalAgents
        })
      : row;
    return campaignLeadAgentAccess(lead, findAgentRecordForSession());
  }

  function pushCampaignLeadAssignInboxEntry(entry){
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    const list = normalizeCampaignLeadAssignInboxList(State.data.meta.campaignLeadAssignInbox || []);
    const next = normalizeCampaignLeadAssignInboxEntry(entry);
    if(!safeTrim(next.targetAgentId) || !safeTrim(next.leadId)) return false;
    list.push(next);
    State.data.meta.campaignLeadAssignInbox = normalizeCampaignLeadAssignInboxList(list);
    bumpMetaSyncClock(State.data.meta, "campaignInbox");
    return true;
  }

  const GI_CAMPAIGN_LEAD_INBOX_NOTIFY_MAX_AGE_MS = 20 * 60 * 1000;
  const GI_CAMPAIGN_LEADS_INBOX_CACHE_KEY = "GI_CAMPAIGN_LEADS_INBOX_V1";
  const GI_CAMPAIGN_LEADS_INBOX_CACHE_MAX_AGE_MS = 14 * 24 * 60 * 60 * 1000;
  const GI_CAMPAIGN_LEADS_INBOX_CACHE_MAX_ROWS = 2500;

  const CampaignLeadAssignInbox = {
    _flushBusy: false,
    _syncChain: Promise.resolve(),
    _deliveredAssignKeys: (() => {
      try {
        const raw = localStorage.getItem("GI_DELIVERED_LEAD_ASSIGN_KEYS_V1");
        return new Set(raw ? JSON.parse(raw) : []);
      } catch(_e) { return new Set(); }
    })(),
    _persistDeliveredKeys(){
      try {
        const keys = Array.from(this._deliveredAssignKeys);
        localStorage.setItem("GI_DELIVERED_LEAD_ASSIGN_KEYS_V1", JSON.stringify(keys));
      } catch(_e) {}
    },
    assignNoticeKey(leadId, agentId){
      return `${safeTrim(leadId)}::${safeTrim(agentId)}`;
    },
    wasDelivered(leadId, agentId){
      return this._deliveredAssignKeys.has(this.assignNoticeKey(leadId, agentId));
    },
    markDelivered(leadId, agentId){
      const key = this.assignNoticeKey(leadId, agentId);
      this._deliveredAssignKeys.add(key);
      if(this._deliveredAssignKeys.size > 240){
        this._deliveredAssignKeys = new Set(Array.from(this._deliveredAssignKeys).slice(-120));
      }
      this._persistDeliveredKeys();
    },
    shouldNotifyInboxEntry(ev){
      const leadId = safeTrim(ev?.leadId);
      const agentId = safeTrim(ev?.targetAgentId);
      if(!leadId || !agentId) return false;
      if(this.wasDelivered(leadId, agentId)) return false;
      const at = safeTrim(ev?.at);
      if(!at) return false;
      const atMs = new Date(at).getTime();
      if(!Number.isFinite(atMs)) return false;
      const ageMs = Date.now() - atMs;
      return ageMs >= 0 && ageMs <= GI_CAMPAIGN_LEAD_INBOX_NOTIFY_MAX_AGE_MS;
    },
    notifyPendingInboxEntries(entries){
      (Array.isArray(entries) ? entries : []).forEach((ev) => {
        const leadId = safeTrim(ev?.leadId);
        const agentId = safeTrim(ev?.targetAgentId);
        if(!leadId || !agentId) return;
        if(this.shouldNotifyInboxEntry(ev)){
          this.notifyAssigned(ev);
          return;
        }
        if(!this.wasDelivered(leadId, agentId)){
          this.markDelivered(leadId, agentId);
        }
      });
    },
    openLead(leadId){
      const id = safeTrim(leadId);
      if(!id) return;
      try { CampaignMyLeadsUI.pendingHighlightId = id; } catch(_e) {}
      try { UI.goView("campaignMyLeads"); } catch(_e) {}
      try { void CampaignMyLeadsUI.render?.(); } catch(_e) {}
    },
    notifyAssigned(ev){
      const customerName = safeTrim(ev?.customerName) || "לקוח";
      const phone = safeTrim(ev?.phone) || "";
      const campaignLabel = safeTrim(ev?.campaignLabel) || "";
      const fromName = safeTrim(ev?.fromName) || "מערכת";
      const leadId = safeTrim(ev?.leadId);
      const agentId = safeTrim(ev?.targetAgentId);
      const noticeKey = this.assignNoticeKey(leadId, agentId);
      if(leadId && agentId && this.wasDelivered(leadId, agentId)) return;
      if(leadId && agentId) this.markDelivered(leadId, agentId);
      try {
        void AgentActivityLog.logLead("lead_assigned", {
          id: leadId,
          customerName,
          phone,
          assignedAgentId: agentId,
          assignedAgentName: safeTrim(ev?.targetAgentName)
        }, {
          agent: { id: agentId, name: safeTrim(ev?.targetAgentName) },
          detailText: `שויך על ידי ${fromName}`
        });
      } catch(_e) {}
      const detailParts = [customerName, phone, campaignLabel].filter(Boolean);
      const text = detailParts.join(" · ");
      const tag = `gi-campaign-lead-assign-${safeTrim(ev?.id) || noticeKey || leadId}`;
      try { playGiLeadNotifySequence(); } catch(_e) {}
      try {
        window.showToast?.({
          title: "קבלת ליד חדש לטיפול",
          text: text || fromName,
          variant: "info",
          durationMs: 8000,
          singletonKey: tag,
          actions: [{ label: "פתח ליד", onClick: () => this.openLead(leadId) }]
        });
      } catch(_e) {}
      try {
        void DesktopNotifications?.notify?.("קבלת ליד חדש לטיפול", {
          body: text || fromName,
          tag,
          onClick: () => this.openLead(leadId)
        });
      } catch(_e) {}
    },
    notifyLeadRow(row, options = {}){
      if(!row || !campaignLeadRowMatchesCurrentAgent(row)) return false;
      const leadId = safeTrim(row.id);
      const agentId = safeTrim(row.assigned_agent_id || row.assignedAgentId);
      if(!leadId || !agentId) return false;
      const status = safeTrim(row.status);
      if(status === "closed" || status === "irrelevant") return false;
      this.notifyAssigned({
        id: safeTrim(options.id) || `rt-${leadId}`,
        targetAgentId: agentId,
        targetAgentName: safeTrim(row.assigned_agent_name || row.assignedAgentName),
        fromName: safeTrim(options.fromName) || safeTrim(row.created_by_name || row.createdByName) || "מערכת",
        leadId,
        customerName: safeTrim(row.customer_name || row.customerName),
        phone: safeTrim(row.phone),
        campaignLabel: safeTrim(row.campaign_label || row.campaignLabel)
      });
      return true;
    },
    forgetDelivered(leadId, agentId){
      const key = this.assignNoticeKey(leadId, agentId);
      if(!this._deliveredAssignKeys.has(key)) return;
      this._deliveredAssignKeys.delete(key);
      this._persistDeliveredKeys();
    },
    applyLocalLeadRow(row){
      if(!row || !campaignLeadRowMatchesCurrentAgent(row)) return false;
      const lead = mapCampaignLeadFromDb(row, 0);
      if(!lead) return false;
      CampaignLeadsStore.applyLocal(lead);
      try { CampaignMyLeadsUI.renderList(); } catch(_e) {}
      return true;
    },
    async refreshMyLeadsAfterAssign(){
      if(!Auth.canAccessCampaignMyLeads()) return;
      try {
        const r = await CampaignLeadsStore.fetchAll({ scope: "mine" });
        if(r.ok) CampaignMyLeadsUI.renderList();
      } catch(_e) {}
    },
    handleRealtimeDbRow(row, options = {}){
      if(!row || !safeTrim(row.assigned_agent_id || row.assignedAgentId)) return;
      if(!campaignLeadRowMatchesCurrentAgent(row)) return;
      const leadId = safeTrim(row.id);
      const agentId = safeTrim(row.assigned_agent_id || row.assignedAgentId);
      const prevAgentId = safeTrim(options.prevAgentId);
      if(prevAgentId && prevAgentId !== agentId) this.forgetDelivered(leadId, agentId);
      this.applyLocalLeadRow(row);
      this.notifyLeadRow(row, options);
    },
    handleInboxMetaArrival(){
      if(!Auth.canAccessCampaignMyLeads()) return;
      void (async () => {
        try {
          await this.flushForCurrentUser();
          await CampaignLeadsStore.fetchAll({ scope: "mine" });
          CampaignMyLeadsUI.renderList();
        } catch(_e) {}
      })();
    },
    syncAssignNotice(entry){
      const normalized = normalizeCampaignLeadAssignInboxEntry(entry);
      const target = resolveCampaignLeadTargetAgent({
        id: normalized.targetAgentId,
        name: normalized.targetAgentName
      });
      normalized.targetAgentId = target.id;
      normalized.targetAgentName = target.name;
      const pushed = pushCampaignLeadAssignInboxEntry(normalized);
      if(!pushed) return this._syncChain;
      this._syncChain = this._syncChain.then(async () => {
        try {
          const metaRes = await Storage.loadMetaRow();
          if(metaRes?.ok){
            const remoteMeta = Storage.mapMeta(metaRes.data || {});
            State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
            State.data.meta.campaignLeadAssignInbox = mergeCampaignLeadAssignInboxLists(
              State.data.meta.campaignLeadAssignInbox,
              remoteMeta.campaignLeadAssignInbox
            );
          }
          bumpMetaSyncClock(State.data.meta, "campaignInbox");
          await Storage.upsertMeta(State.data);
          try { Storage.saveBackup(State.data); } catch(_e) {}
        } catch(err) {
          console.warn("CAMPAIGN_LEAD_ASSIGN_NOTIFY_FAILED:", err);
        }
      });
      return this._syncChain;
    },
    async flushForCurrentUser(){
      if(this._flushBusy || !Auth.current) return;
      if(!Auth.canAccessCampaignMyLeads()) return;
      State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
      const inbox = normalizeCampaignLeadAssignInboxList(State.data.meta.campaignLeadAssignInbox || []);
      const mine = inbox.filter((e) => campaignLeadAssignInboxMatchesCurrentUser(e));
      if(!mine.length) return;
      this._flushBusy = true;
      try {
        const rest = inbox.filter((e) => !campaignLeadAssignInboxMatchesCurrentUser(e));
        this.notifyPendingInboxEntries(mine);
        State.data.meta.campaignLeadAssignInbox = normalizeCampaignLeadAssignInboxList(rest);
        bumpMetaSyncClock(State.data.meta, "campaignInbox");
        try {
          await App.persist("נקה התראות שיוך ליד קמפיין", {
            skipProposalsSync: true,
            metaOnly: true,
            metaSyncScopes: ["campaignInbox"],
            silent: true
          });
        } catch(_e) {}
      } finally {
        this._flushBusy = false;
      }
    }
  };

  function canElementaryMarkIssuedForReferral(rec){
    if(!rec) return false;
    if(safeTrim(rec.issuedAt) || safeTrim(rec.agentTrackStatus) === "issued") return false;
    if(safeTrim(rec.agentTrackStatus) === "agent_setup_complete") return true;
    if(safeTrim(rec.agentTrackStatus) === "proposal_submitting") return true;
    return !!safeTrim(rec.proposalReadyAt);
  }

  function findElementaryReferralIssuableByCustomerId(customerId){
    const cid = safeTrim(customerId);
    if(!cid) return null;
    return getElementaryReferrals().find((rec) => {
      if(safeTrim(rec.customerId) !== cid) return false;
      if(rec.status !== "pending") return false;
      return canElementaryMarkIssuedForReferral(rec);
    }) || null;
  }

  function getElementaryInsuredDataFromCustomer(rec){
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    const ins0 = Array.isArray(payload.insureds) ? payload.insureds[0] : null;
    return (ins0?.data && typeof ins0.data === "object" ? ins0.data : (payload.primary || {}));
  }

  function elementaryCoverageTypeLabelHe(ctRaw){
    const m = {
      third: "צד ג׳",
      comprehensive: "מקיף",
      mandatory_third: "חובה + צד ג׳",
      mandatory_comprehensive: "חובה + מקיף"
    };
    const ct = safeTrim(ctRaw);
    return m[ct] || ct || "—";
  }

  const VEHICLE_INSURANCE_COMPANIES = [
    "איילון", "הראל", "כלל", "מגדל", "מנורה", "הפניקס", "הכשרה", "ליברה",
    "ביטוח ישיר", "שומרה", "שלמה", "חקלאי", "AIG", "9 מיליון", "שירביט",
    "ווישור", "אלטשולר שחם", "פסגות", "דקלה", "WeSure"
  ];

  function getVehicleInsuranceCompanies(){
    const seen = new Set();
    const out = [];
    const push = (name) => {
      const n = safeTrim(name);
      if(!n || seen.has(n)) return;
      seen.add(n);
      out.push(n);
    };
    VEHICLE_INSURANCE_COMPANIES.forEach(push);
    try {
      if(typeof Wizard !== "undefined" && Wizard && typeof Wizard._harHistoryCompanyEntries === "function"){
        Wizard._harHistoryCompanyEntries().forEach((entry) => push(entry?.label));
      }
    } catch(_e){}
    return out.sort((a, b) => a.localeCompare(b, "he"));
  }

  function getCampaignLeadInsuranceCompanies(){
    const seen = new Set();
    const out = [];
    const push = (name) => {
      const n = safeTrim(name);
      if(!n || seen.has(n)) return;
      seen.add(n);
      out.push(n);
    };
    try {
      if(typeof Wizard !== "undefined" && Wizard){
        (Wizard.companies || []).forEach(push);
        (Wizard.existingCompanies || []).forEach(push);
      }
    } catch(_e){}
    getVehicleInsuranceCompanies().forEach(push);
    ["הראל", "מנורה מבטחים", "ש. שלמה", "מדיקר"].forEach(push);
    return out.sort((a, b) => a.localeCompare(b, "he"));
  }

  const CampaignLeadInsuranceDropdown = {
    els: {},
    _bound: false,
    _companies: null,
    _search: "",

    getCompanies(){
      if(!this._companies) this._companies = getCampaignLeadInsuranceCompanies();
      return this._companies;
    },

    _filteredCompanies(){
      const q = safeTrim(this._search).toLowerCase();
      const list = this.getCompanies();
      if(!q) return list;
      return list.filter((c) => safeTrim(c).toLowerCase().includes(q));
    },

    init(){
      this.els.wrap = document.getElementById("clInsuranceCoDdWrap");
      this.els.trigger = document.getElementById("clInsuranceCoDdTrigger");
      this.els.menu = document.getElementById("clInsuranceCoDdMenu");
      this.els.logoSlot = document.getElementById("clInsuranceCoDdLogo");
      this.els.label = document.getElementById("clInsuranceCoDdLabel");
      this.els.hidden = document.getElementById("clInsuranceCompany");
      if(!this.els.trigger || !this.els.menu) return;
      this._renderMenu();
      if(!this._bound) this._bind();
    },

    _placeholderLogo(){
      return `<span class="lcNpCoDd__logoPlaceholder" aria-hidden="true">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" width="18" height="18"><path d="M12 2l7 4v6c0 5-3 8.5-7 10-4-1.5-7-5-7-10V6l7-4z"/></svg>
      </span>`;
    },

    _checkSvg(){
      return `<svg class="lcNpCoDd__check" viewBox="0 0 20 20" fill="none" width="16" height="16"><circle cx="10" cy="10" r="10" fill="#2563eb"/><path d="M5.5 10l3 3 5-5" stroke="#fff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
    },

    _renderMenu(){
      if(!this.els.menu) return;
      const selected = this.getValue();
      const filtered = this._filteredCompanies();
      const searchVal = escapeHtml(this._search || "");
      const itemsHtml = filtered.length
        ? filtered.map((c) => {
          const logoEl = renderCompanyLogoHtmlForCompany(c, "dd");
          return `<button type="button" class="lcNpCoDd__item${selected === c ? " is-selected" : ""}" data-cl-ins-co="${escapeHtml(c)}">
          ${logoEl}
          <span class="lcNpCoDd__itemLabel">${escapeHtml(c)}</span>
          ${selected === c ? this._checkSvg() : ""}
        </button>`;
        }).join("")
        : `<div class="lcNpCoDd__empty muted small">לא נמצאה חברה תואמת</div>`;
      this.els.menu.innerHTML = `
        <div class="lcNpCoDd__searchWrap">
          <input class="input lcNpCoDd__searchInput" type="search" dir="rtl" placeholder="הקלד שם חברה…" value="${searchVal}" autocomplete="off"/>
        </div>
        <div class="lcNpCoDd__items">${itemsHtml}</div>`;
      const searchInput = this.els.menu.querySelector(".lcNpCoDd__searchInput");
      if(searchInput){
        on(searchInput, "input", () => {
          this._search = safeTrim(searchInput.value);
          this._renderMenu();
          const nextInput = this.els.menu.querySelector(".lcNpCoDd__searchInput");
          if(nextInput){
            nextInput.focus();
            try { nextInput.setSelectionRange(nextInput.value.length, nextInput.value.length); } catch(_e) {}
          }
        });
        on(searchInput, "click", (ev) => ev.stopPropagation());
        on(searchInput, "keydown", (ev) => {
          if(ev.key === "Escape"){
            ev.stopPropagation();
            this._close();
          }
        });
      }
    },

    getValue(){
      return safeTrim(this.els.hidden?.value);
    },

    setValue(company){
      const co = safeTrim(company);
      if(this.els.hidden) this.els.hidden.value = co;
      if(this.els.label) this.els.label.textContent = co || "— בחר חברת ביטוח —";
      if(this.els.logoSlot) this.els.logoSlot.innerHTML = co ? renderCompanyLogoHtmlForCompany(co, "dd") : this._placeholderLogo();
      if(this.els.trigger) this.els.trigger.classList.toggle("has-value", !!co);
      this._renderMenu();
    },

    clear(){
      this.setValue("");
    },

    _positionMenu(){
      if(!this.els.trigger || !this.els.menu) return;
      const rect = this.els.trigger.getBoundingClientRect();
      this.els.menu.style.top = (rect.bottom + 6) + "px";
      this.els.menu.style.left = rect.left + "px";
      this.els.menu.style.width = rect.width + "px";
    },

    _open(){
      if(!this.els.menu || !this.els.trigger) return;
      this._search = "";
      this._renderMenu();
      if(this.els.menu.parentElement !== document.body) document.body.appendChild(this.els.menu);
      this._positionMenu();
      this.els.trigger.setAttribute("aria-expanded", "true");
      this.els.menu.classList.add("is-open");
      this.els.menu.hidden = false;
      const searchInput = this.els.menu.querySelector(".lcNpCoDd__searchInput");
      if(searchInput){
        window.setTimeout(() => {
          try { searchInput.focus(); } catch(_e) {}
        }, 30);
      }
    },

    _close(){
      if(!this.els.menu || !this.els.trigger) return;
      this._search = "";
      this.els.trigger.setAttribute("aria-expanded", "false");
      this.els.menu.classList.remove("is-open");
      this.els.menu.hidden = true;
    },

    _bind(){
      const self = this;
      on(this.els.trigger, "click", (ev) => {
        ev.stopPropagation();
        const isOpen = self.els.menu.classList.contains("is-open");
        isOpen ? self._close() : self._open();
      });
      on(this.els.menu, "click", (ev) => {
        const item = ev.target.closest("[data-cl-ins-co]");
        if(!item) return;
        self.setValue(item.getAttribute("data-cl-ins-co") || "");
        self._close();
      });
      if(!this._bound){
        document.addEventListener("click", (ev) => {
          if(!self.els.wrap?.contains(ev.target) && !self.els.menu?.contains(ev.target)) self._close();
        });
        this._bound = true;
      }
    }
  };

  function getElementaryCoverageProductRowsFromPayload(payload){
    const p = payload && typeof payload === "object" ? payload : {};
    const d = Array.isArray(p.insureds) && p.insureds[0]?.data ? p.insureds[0].data : (p.primary || {});
    const ct = safeTrim(d.coverageType);
    const bundles = {
      third: [{ key:"third", label:"צד ג׳" }],
      comprehensive: [{ key:"comprehensive", label:"מקיף" }],
      mandatory_third: [{ key:"mandatory", label:"חובה" }, { key:"third", label:"צד ג׳" }],
      mandatory_comprehensive: [{ key:"mandatory", label:"חובה" }, { key:"comprehensive", label:"מקיף" }]
    };
    return bundles[ct] || [];
  }

  function normalizeElementaryQuoteAdditionalServices(raw, productsRaw){
    const input = raw && typeof raw === "object" ? raw : {};
    const products = Array.isArray(productsRaw) ? productsRaw : [];
    let premium = safeTrim(input.premium);
    let installments = safeTrim(input.installments);
    const details = safeTrim(input.details);
    if(!premium){
      const hit = products.find((row) => safeTrim(row?.premium));
      if(hit) premium = safeTrim(hit.premium);
    }
    if(!installments){
      const hit = products.find((row) => safeTrim(row?.installments));
      if(hit) installments = safeTrim(hit.installments);
    }
    return { premium, installments, details };
  }

  function normalizeElementaryPriceQuoteVariant(raw, idx = 0){
    const input = raw && typeof raw === "object" ? raw : {};
    const productsRaw = Array.isArray(input.products) ? input.products : [];
    const additionalServices = normalizeElementaryQuoteAdditionalServices(input.additionalServices, productsRaw);
    const products = productsRaw.map((row, rowIdx) => {
      let premium = safeTrim(row?.premium);
      let installments = safeTrim(row?.installments);
      if(!premium && additionalServices.premium && productsRaw.length === 1) premium = additionalServices.premium;
      if(!installments && additionalServices.installments && productsRaw.length === 1) installments = additionalServices.installments;
      if(!premium && additionalServices.premium && rowIdx === 0 && productsRaw.length > 1) premium = additionalServices.premium;
      if(!installments && additionalServices.installments && rowIdx === 0 && productsRaw.length > 1) installments = additionalServices.installments;
      return {
        productKey: safeTrim(row?.productKey),
        label: safeTrim(row?.label),
        company: safeTrim(row?.company),
        premium,
        installments,
        deductibleThirdParty: safeTrim(row?.deductibleThirdParty),
        deductibleComprehensiveArranged: safeTrim(row?.deductibleComprehensiveArranged),
        deductibleComprehensiveNotArranged: safeTrim(row?.deductibleComprehensiveNotArranged)
      };
    }).filter((row) => row.productKey || row.label);
    const hebLetter = String.fromCharCode(0x05D0 + (Number(idx) % 22));
    return {
      id: safeTrim(input.id) || ("elemquote_" + idx + "_" + Math.random().toString(16).slice(2)),
      label: safeTrim(input.label) || ("הצעה " + hebLetter),
      products,
      additionalServices: { premium: "", installments: "", details: additionalServices.details }
    };
  }

  function normalizeElementaryPriceQuotes(raw){
    return (Array.isArray(raw) ? raw : [])
      .map((row, idx) => normalizeElementaryPriceQuoteVariant(row, idx))
      .filter((row) => row.products.length);
  }

  function buildDefaultElementaryPriceQuotesFromReferral(rec){
    const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
    const productRows = getElementaryCoverageProductRowsFromPayload(payload);
    if(!productRows.length) return [];
    return [normalizeElementaryPriceQuoteVariant({
      label: "הצעה א",
      products: productRows.map((w) => ({
        productKey: w.key,
        label: w.label,
        company: "",
        premium: "",
        installments: "",
        deductibleThirdParty: "",
        deductibleComprehensiveArranged: "",
        deductibleComprehensiveNotArranged: ""
      })),
      additionalServices: { premium: "", installments: "", details: "" }
    }, 0)];
  }

  function getReferralElementaryPriceQuotes(rec){
    const existing = normalizeElementaryPriceQuotes(rec?.elementaryPriceQuotes);
    if(existing.length) return existing;
    return buildDefaultElementaryPriceQuotesFromReferral(rec);
  }

  function getRequestedCoverageFromPayload(payload){
    const p = payload && typeof payload === "object" ? payload : {};
    const d = Array.isArray(p.insureds) && p.insureds[0]?.data ? p.insureds[0].data : (p.primary || {});
    return safeTrim(d.requestedCoverageType) || safeTrim(d.coverageType) || "";
  }

  function patchElementaryReferral(referralId, patch = {}){
    const id = safeTrim(referralId);
    if(!id) return null;
    const list = getElementaryReferrals();
    const idx = list.findIndex((rec) => String(rec.id) === String(id));
    if(idx < 0) return null;
    const merged = { ...list[idx], ...(patch && typeof patch === "object" ? patch : {}), updatedAt: nowISO() };
    if(patch?.payload && typeof patch.payload === "object"){
      merged.payload = patch.payload;
    }
    list[idx] = normalizeElementaryReferral(merged, idx);
    setElementaryReferrals(list);
    refreshStateShadows({ skipNormalize: true, lightShadows: true });
    return list[idx];
  }

  let _elemReferralPersistTimer = null;
  function schedulePersistElementaryReferralsQuiet(label){
    if(_elemReferralPersistTimer) window.clearTimeout(_elemReferralPersistTimer);
    _elemReferralPersistTimer = window.setTimeout(() => {
      _elemReferralPersistTimer = null;
      void persistElementaryReferralsQuiet(label);
    }, 350);
  }

  async function persistElementaryReferralsQuiet(label){
    try {
      const res = await App.persist(label || "עודכן מעקב הפניה אלמנטרי", {
        metaOnly: true,
        metaSyncScopes: ["referrals"],
        silent: true
      });
      if(res?.ok) notifyElementaryReferralsChannel();
      return res;
    } catch(_e){ return { ok: false }; }
  }

  function getAgentElementaryTrackPresentation(rec){
    const row = rec && typeof rec === "object" ? rec : {};
    const handler = safeTrim(row.elementaryHandlerName);
    const opsBy = safeTrim(row.opsTouchedBy);
    const requested = elementaryCoverageTypeLabelHe(row.requestedCoverageType || getRequestedCoverageFromPayload(row.payload));
    let key = safeTrim(row.agentTrackStatus);
    if(referralAwaitingElementaryIssue(row) && key === "proposal_submitting"){
      key = "agent_setup_complete";
    }
    if(!key){
      if(row.status === "done") key = "done";
      else if(safeTrim(row.issuedAt)) key = "issued";
      else if(handler) key = "elementary_handling";
      else if(safeTrim(row.proposalReadyAt)) key = "proposal_submitting";
      else if(safeTrim(row.opsTouchedAt)) key = "with_insurer";
      else key = "waiting_ops";
    }
    const map = {
      waiting_elementary: { label: "ממתין לטיפול אלמנטרי", tone: "info", sub: requested ? `מוצר מבוקש: ${requested}` : "", badgeClass: "lcProposalBadge--waiting" },
      waiting_ops: { label: "הועבר למחלקת תפעול · ממתין לטיפול", tone: "info", sub: requested ? `מוצר מבוקש: ${requested}` : "", badgeClass: "lcProposalBadge--waiting" },
      with_insurer: { label: "הועבר לטיפול מול חברת הביטוח והפקה", tone: "warn", sub: opsBy ? `תפעול: ${opsBy}` : (requested ? `מוצר מבוקש: ${requested}` : ""), badgeClass: "lcProposalBadge--mid" },
      elementary_handling: { label: handler ? `ההצעה בטיפול על ידי: ${handler}` : "בטיפול אלמנטרי", tone: "warn", sub: requested ? `מוצר מבוקש: ${requested}` : "", badgeClass: "lcProposalBadge--handling" },
      quote_ready: { label: "הצעת ביטוח מוכנה", tone: "success", sub: requested ? `מוצר: ${requested}` : "", badgeClass: "lcProposalBadge--quoteReady" },
      agent_setup_complete: { label: "הצעה הוקמה — ממתין להפקה מאלמנטרי", tone: "success", sub: requested ? `מוצר: ${requested}` : "הנציג סיים הקמת לקוח", badgeClass: "lcProposalBadge--quoteReady" },
      proposal_submitting: { label: "הוקמה הצעה — כעת בתהליך הגשה לחברת הביטוח", tone: "warn", sub: requested ? `מוצר: ${requested}` : "", badgeClass: "lcProposalBadge--mid" },
      issued: { label: "לקוח הופק", tone: "success", sub: "", badgeClass: "lcProposalBadge--quoteReady" },
      done: { label: "הטיפול הושלם", tone: "neutral", sub: "", badgeClass: "lcProposalBadge--done" }
    };
    const hit = map[key] || map.waiting_ops;
    return { ...hit, key, requestedCoverageLabel: requested };
  }

  /** סיווג הפניה לדשבורד אלמנטרי חי */
  function getElementaryDashBucket(rec){
    if(!rec) return "handled";
    if(safeTrim(rec.issuedAt) || safeTrim(rec.agentTrackStatus) === "issued") return "issued";
    const statusRaw = safeTrim(rec.status).toLowerCase();
    if(statusRaw === "done" || statusRaw === "handled" || statusRaw === "טופל") return "handled";
    if(referralAwaitingElementaryIssue(rec)) return "awaiting_issue";
    const track = safeTrim(rec.agentTrackStatus);
    if(track === "elementary_handling" || safeTrim(rec.elementaryHandlerAt)) return "in_treatment";
    if(["with_insurer", "quote_ready", "proposal_submitting"].includes(track)) return "in_treatment";
    if(elementaryReferralShowsInPendingQueue(rec)) return "pending";
    if(rec.status === "pending") return "in_treatment";
    return "handled";
  }

  function elementaryDashBucketMeta(bucket){
    const map = {
      pending: { label: "ממתין לטיפול", tone: "pending", tabLabel: "ממתינים" },
      in_treatment: { label: "בטיפול", tone: "active", tabLabel: "בטיפול" },
      awaiting_issue: { label: "ממתין להפקה", tone: "awaiting_issue", tabLabel: "ממתינים להפקה" },
      issued: { label: "הופק", tone: "issued", tabLabel: "הופקו" },
      handled: { label: "טופל", tone: "handled", tabLabel: "טופלו" }
    };
    return map[bucket] || map.handled;
  }

  function isIsoToday(iso){
    const d = new Date(safeTrim(iso));
    if(Number.isNaN(d.getTime())) return false;
    const now = new Date();
    return d.getFullYear() === now.getFullYear()
      && d.getMonth() === now.getMonth()
      && d.getDate() === now.getDate();
  }

  function formatRelativeTimeHe(iso){
    const d = new Date(safeTrim(iso));
    if(Number.isNaN(d.getTime())) return "";
    const sec = Math.floor((Date.now() - d.getTime()) / 1000);
    if(sec < 45) return "עכשיו";
    const min = Math.floor(sec / 60);
    if(min < 60) return `לפני ${min} דק׳`;
    const hr = Math.floor(min / 60);
    if(hr < 24) return `לפני ${hr} שע׳`;
    const day = Math.floor(hr / 24);
    if(day < 7) return `לפני ${day} ימים`;
    return d.toLocaleDateString("he-IL", { day: "2-digit", month: "2-digit", hour: "2-digit", minute: "2-digit" });
  }

  function elementaryDashReferralsSorted(){
    const cutoff = Date.now() - (60 * 24 * 60 * 60 * 1000);
    return getElementaryReferrals()
      .filter((rec) => {
        if(!elementaryReferralIsTerminal(rec)) return true;
        const t = new Date(safeTrim(rec.updatedAt) || safeTrim(rec.handledAt) || safeTrim(rec.issuedAt) || safeTrim(rec.submittedAt)).getTime();
        return Number.isFinite(t) && t >= cutoff;
      })
      .sort((a, b) => {
        const cmp = compareIsoStamps(safeTrim(b.updatedAt) || safeTrim(b.submittedAt), safeTrim(a.updatedAt) || safeTrim(a.submittedAt));
        if(cmp !== 0) return cmp;
        return new Date(b.submittedAt || 0) - new Date(a.submittedAt || 0);
      });
  }

  function buildElementaryDashCardQuietSig(rec){
    const bucket = getElementaryDashBucket(rec);
    const quoteCount = Array.isArray(rec?.elementaryPriceQuotes) ? rec.elementaryPriceQuotes.length : 0;
    return [
      bucket,
      safeTrim(rec.status),
      safeTrim(rec.agentTrackStatus),
      safeTrim(rec.fullName),
      safeTrim(rec.idNumber),
      safeTrim(rec.phone),
      safeTrim(rec.agentName),
      safeTrim(rec.elementaryHandlerName),
      safeTrim(rec.customerId),
      safeTrim(rec.updatedAt),
      safeTrim(rec.handledAt),
      safeTrim(rec.issuedAt),
      safeTrim(rec.quoteSentAt),
      safeTrim(rec.proposalReadyAt),
      safeTrim(rec.agentSetupCompletedAt),
      String(quoteCount),
      referralAwaitingElementaryIssue(rec) ? "1" : "0"
    ].join("\x1e");
  }

  function buildReferralTrackQuietSig(rec){
    const row = rec && typeof rec === "object" ? rec : {};
    const pres = getAgentElementaryTrackPresentation(row);
    const requested = elementaryCoverageTypeLabelHe(row.requestedCoverageType || getRequestedCoverageFromPayload(row.payload));
    return [
      safeTrim(row.status),
      safeTrim(row.agentTrackStatus),
      pres.label,
      pres.sub || "",
      pres.tone || "",
      pres.badgeClass || "",
      requested,
      safeTrim(row.updatedAt),
      safeTrim(row.quoteSentAt),
      safeTrim(row.agentSetupCompletedAt),
      safeTrim(row.selectedAgentQuoteId),
      safeTrim(row.customerId),
      safeTrim(row.elementaryHandlerName),
      safeTrim(row.opsTouchedBy)
    ].join("\x1e");
  }

  function activateElementaryPoliciesInPayload(payload, options = {}){
    const p = payload && typeof payload === "object" ? payload : {};
    const onlyIds = Array.isArray(options.onlyPolicyIds) && options.onlyPolicyIds.length
      ? new Set(options.onlyPolicyIds.map((id) => String(id)))
      : null;
    const filesByPolicy = options.policyFilesByPolicyId && typeof options.policyFilesByPolicyId === "object"
      ? options.policyFilesByPolicyId
      : {};
    const globalFiles = Array.isArray(options.policyFiles) ? options.policyFiles : [];
    const markInsured = (data, active) => {
      if(!data || typeof data !== "object") return;
      data._elemPoliciesLifecycle = active ? "issued" : (safeTrim(data._elemPoliciesLifecycle) || "pending_underwriting");
    };
    const activePres = getElementaryPolicyLifecyclePresentation("issued");
    const pendingPres = getElementaryPolicyLifecyclePresentation("pending_underwriting");
    let anyActive = false;
    if(Array.isArray(p.elementaryPolicies)){
      p.elementaryPolicies = p.elementaryPolicies.map((row) => {
        const base = row && typeof row === "object" ? { ...row } : {};
        const rid = String(base.id || "");
        const shouldActivate = !onlyIds || onlyIds.has(rid);
        if(!shouldActivate){
          return {
            ...base,
            lifecycleStatus: safeTrim(base.lifecycleStatus) || "pending_underwriting",
            badgeText: safeTrim(base.badgeText) || pendingPres.badgeText,
            badgeClass: safeTrim(base.badgeClass) || pendingPres.badgeClass
          };
        }
        anyActive = true;
        const rowFiles = Array.isArray(filesByPolicy[rid]) && filesByPolicy[rid].length
          ? filesByPolicy[rid]
          : globalFiles;
        return {
          ...base,
          lifecycleStatus: "issued",
          badgeText: activePres.badgeText,
          badgeClass: activePres.badgeClass,
          policyFiles: rowFiles.length ? rowFiles : (Array.isArray(base.policyFiles) ? base.policyFiles : [])
        };
      });
    }
    if(anyActive || !onlyIds){
      markInsured(p.primary, true);
      (Array.isArray(p.insureds) ? p.insureds : []).forEach((ins) => markInsured(ins?.data, true));
    }
    return p;
  }

  async function persistCustomerPayloadRecord(customerId, payload, label){
    const cid = safeTrim(customerId);
    if(!cid || !payload) return false;
    State.data.customers = Array.isArray(State.data.customers) ? State.data.customers : [];
    const idx = State.data.customers.findIndex((row) => String(row?.id) === String(cid));
    if(idx < 0) return false;
    const prev = State.data.customers[idx];
    const nextPayload = JSON.parse(JSON.stringify(payload));
    State.data.customers[idx] = {
      ...prev,
      payload: nextPayload,
      updatedAt: nowISO(),
      insuredCount: Array.isArray(nextPayload.insureds) ? nextPayload.insureds.length : prev.insuredCount,
      newPoliciesCount: Array.isArray(nextPayload.newPolicies) ? nextPayload.newPolicies.length : prev.newPoliciesCount
    };
    refreshStateShadows();
    try {
      const directRow = Storage.buildCustomerRows({ customers: [State.data.customers[idx]] })[0];
      await Storage.upsertSingleRow(SUPABASE_TABLES.customers, directRow);
    } catch(_e){}
    try { await App.persist(label || "עודכן תיק לקוח"); } catch(_e){}
    return true;
  }

  function preserveTableWrapScroll(tbody, fn){
    const wrap = tbody?.closest?.(".tableWrap");
    const scrollTop = wrap?.scrollTop ?? 0;
    fn();
    if(wrap) wrap.scrollTop = scrollTop;
  }

  function buildElementaryReferralsListSig(list){
    return (Array.isArray(list) ? list : []).map((rec) => {
      const row = rec && typeof rec === "object" ? rec : {};
      const quotes = Array.isArray(row.elementaryPriceQuotes) ? row.elementaryPriceQuotes : [];
      return [
        safeTrim(row.id),
        safeTrim(row.status),
        safeTrim(row.agentTrackStatus),
        safeTrim(row.updatedAt),
        safeTrim(row.quoteSentAt),
        safeTrim(row.elementaryHandlerName),
        safeTrim(row.handledAt),
        String(quotes.length)
      ].join("|");
    }).sort().join("\n");
  }

  function normalizeElementaryReferralsList(list){
    return (Array.isArray(list) ? list : [])
      .map((row, idx) => normalizeElementaryReferral(row, idx))
      .filter(Boolean);
  }

  function elementaryReferralsDiffer(remoteList, localList){
    const remote = normalizeElementaryReferralsList(remoteList);
    const local = normalizeElementaryReferralsList(localList);
    if(remote.length !== local.length) return true;
    const localMap = new Map(local.map((rec) => [String(rec.id), buildReferralTrackQuietSig(rec)]));
    for(const rec of remote){
      const id = String(rec.id);
      if(localMap.get(id) !== buildReferralTrackQuietSig(rec)) return true;
    }
    return false;
  }

  const GI_ELEM_REFERRALS_TICK_KEY = "GI_ELEM_REFERRALS_TICK_V1";

  function notifyElementaryReferralsChannel(){
    try { sessionStorage.setItem(GI_ELEM_REFERRALS_TICK_KEY, String(Date.now())); } catch(_e) {}
    try { localStorage.setItem(GI_ELEM_REFERRALS_TICK_KEY, String(Date.now())); } catch(_e) {}
    try { void ReferralQuietRefresh?.tick?.(); } catch(_e) {}
  }

  async function verifyElementaryReferralPersisted(referralId, options = {}){
    const id = safeTrim(referralId);
    if(!id) return { ok: false, error: "REFERRAL_ID_MISSING" };
    const retries = Math.max(1, Number(options.retries || SUPABASE_SAVE_VERIFY_RETRY_COUNT) || SUPABASE_SAVE_VERIFY_RETRY_COUNT);
    const delayMs = Math.max(0, Number(options.delayMs || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS) || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS);
    for(let attempt = 0; attempt < retries; attempt++){
      try {
        const metaRes = await Storage.loadMetaRow();
        if(metaRes?.ok){
          const remoteMeta = Storage.mapMeta(metaRes.data || {});
          const remoteList = Array.isArray(remoteMeta.elementaryReferrals) ? remoteMeta.elementaryReferrals : [];
          if(remoteList.some((row) => String(row?.id) === String(id))) return { ok: true };
        }
      } catch(_e){}
      if(attempt < retries - 1) await new Promise((resolve) => window.setTimeout(resolve, delayMs));
    }
    return { ok: false, error: "REFERRAL_VERIFY_FAILED" };
  }

  function scheduleBackgroundElementaryReferralVerify(referralId){
    const id = safeTrim(referralId);
    if(!id) return;
    pinElementaryReferralLocally(id);
    window.setTimeout(async () => {
      try {
        const verifyRes = await verifyElementaryReferralPersisted(id, { retries: 10, delayMs: 1200 });
        if(verifyRes?.ok) return;
        console.warn("ELEMENTARY_REFERRAL_BG_VERIFY_STILL_MISSING", id, verifyRes?.error);
      } catch(_e){}
    }, 1500);
  }

  function applyRemoteElementaryReferralsFromMeta(remoteMeta){
    const meta = remoteMeta && typeof remoteMeta === "object" ? remoteMeta : {};
    State.data.meta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
    State.data.meta.deletedElementaryReferralIds = normalizeDeletedElementaryReferralIds([
      ...(State.data.meta.deletedElementaryReferralIds || []),
      ...(meta.deletedElementaryReferralIds || [])
    ]);
    const localList = getElementaryReferrals();
    const remoteList = Array.isArray(meta.elementaryReferrals) ? meta.elementaryReferrals : [];
    State.data.meta.elementaryReferrals = mergeElementaryReferralsListsByRecency(localList, remoteList, {
      tombstones: getDeletedElementaryReferralIdSet(),
      pinnedIds: getPinnedElementaryReferralIdSet()
    });
    const remoteAt = safeTrim(meta.updatedAt);
    if(remoteAt) State.data.meta.updatedAt = remoteAt;
    if(meta.revision) State.data.meta.revision = normalizeRevisionMeta(meta.revision, State.data.meta.updatedAt);
    refreshStateShadows();
    try {
      App._lastServerAt = safeTrim(State.data.meta.updatedAt) || App._lastServerAt;
      App._lastServerRevision = normalizeRevisionMeta(State.data.meta.revision, App._lastServerAt);
    } catch(_e) {}
    try { Storage.saveBackup(State.data); } catch(_e) {}
  }

  function referralBelongsToAgent(rec, agent){
    if(!rec || !agent) return false;
    return recordOwnedByAgent(rec, getAgentOwnershipProfile({
      sessionName: safeTrim(agent?.name),
      id: safeTrim(agent?.id),
      name: safeTrim(agent?.name),
      username: safeTrim(agent?.username)
    }));
  }

  function touchElementaryReferralOps(referralRef){
    const rec = typeof referralRef === "string" ? findElementaryReferralById(referralRef) : referralRef;
    if(!rec || rec.status !== "pending") return null;
    if(["issued", "done"].includes(safeTrim(rec.agentTrackStatus))) return rec;
    if(safeTrim(rec.agentTrackStatus) === "proposal_submitting") return rec;
    const updated = patchElementaryReferral(rec.id, {
      agentTrackStatus: "with_insurer",
      opsTouchedAt: nowISO(),
      opsTouchedBy: safeTrim(Auth?.current?.name)
    });
    void persistElementaryReferralsQuiet("תפעול נגע בהפניה");
    try { ProposalsUI.render(); } catch(_e){}
    try { ElementaryPendingUI.render(); } catch(_e){}
    return updated;
  }

  async function touchElementaryReferralProposalReady(referralRef, options = {}){
    const rec = typeof referralRef === "string" ? findElementaryReferralById(referralRef) : referralRef;
    if(!rec || rec.status !== "pending") return null;
    if(safeTrim(rec.agentTrackStatus) === "issued" || safeTrim(rec.issuedAt)) return rec;
    const nextPayload = options.payload && typeof options.payload === "object"
      ? options.payload
      : rec.payload;
    const updated = patchElementaryReferral(rec.id, {
      agentTrackStatus: "proposal_submitting",
      proposalReadyAt: nowISO(),
      proposalReadyBy: safeTrim(options.by) || safeTrim(Auth?.current?.name),
      payload: nextPayload
    });
    await persistElementaryReferralsQuiet("הצעה הוכנה — בתהליך הגשה לחברה");
    try { ProposalsUI.render(); } catch(_e){}
    try { ElementaryPendingUI.render(); } catch(_e){}
    try { CustomersUI.render(); } catch(_e){}
    return updated;
  }

  function touchElementaryReferralElementary(referralRef, options = {}){
    const rec = typeof referralRef === "string" ? findElementaryReferralById(referralRef) : referralRef;
    if(!rec || rec.status !== "pending") return null;
    if(safeTrim(rec.agentTrackStatus) === "issued") return rec;
    if(safeTrim(rec.agentTrackStatus) === "proposal_submitting") return rec;
    if(safeTrim(rec.agentTrackStatus) === "elementary_handling") return rec;
    const updated = patchElementaryReferral(rec.id, {
      agentTrackStatus: "elementary_handling",
      elementaryHandlerName: safeTrim(Auth?.current?.name),
      elementaryHandlerAt: nowISO()
    });
    schedulePersistElementaryReferralsQuiet("אלמנטרי התחיל טיפול");
    if(options.skipRender !== true){
      try { ProposalsUI.render(); } catch(_e){}
      try { ElementaryPendingUI.render(); } catch(_e){}
      try { ElementaryDashboardUI.refreshAfterReferralChange(); } catch(_e){}
    }
    return updated;
  }

  async function sendElementaryReferralQuotesToAgent(referralRef, quotesRaw){
    const rec = typeof referralRef === "string" ? findElementaryReferralById(referralRef) : referralRef;
    if(!rec || rec.status !== "pending") return { ok: false, msg: "הפניה לא זמינה לשליחה" };
    // נקודת מעבר טיפול אלמנטרי: מסומן רק בזמן שליחה לנציג (ולא בפתיחה/צפייה).
    touchElementaryReferralElementary(rec, { skipRender: true });
    const liveRec = findElementaryReferralById(rec.id) || rec;
    const quotes = normalizeElementaryPriceQuotes(quotesRaw);
    if(!quotes.length) return { ok: false, msg: "יש להוסיף לפחות הצעת מחיר אחת עם פרמיות" };
    for(const q of quotes){
      let hasPremium = false;
      for(const line of q.products){
        const prem = safeTrim(line.premium).replace(/[^\d.,]/g, "");
        if(prem) hasPremium = true;
        if(!safeTrim(line.company)) return { ok: false, msg: `יש לבחור חברה ל־${safeTrim(line.label) || "מוצר"} (${safeTrim(q.label)})` };
        if(!prem) return { ok: false, msg: `חסרה פרמיה ל־${safeTrim(line.label) || "מוצר"} (${safeTrim(q.label)})` };
      }
      if(!hasPremium) return { ok: false, msg: `חסרה פרמיה (${safeTrim(q.label) || "הצעה"})` };
    }
    const updated = patchElementaryReferral(liveRec.id, {
      elementaryPriceQuotes: quotes,
      agentTrackStatus: "quote_ready",
      quoteSentAt: nowISO(),
      quoteSentBy: safeTrim(Auth?.current?.name),
      updatedAt: nowISO()
    });
    appendAuditLog({
      type: "elementary_quote_sent",
      entity: "elementary_referral",
      entityId: rec.id,
      label: "נשלחה הצעת מחיר לנציג",
      actorName: safeTrim(Auth?.current?.name),
      details: { agentName: rec.agentName, quoteCount: quotes.length }
    });
    await persistElementaryReferralsQuiet("נשלחה הצעת מחיר לנציג");
    try { ProposalsUI.render(); } catch(_e){}
    try { ElementaryPendingUI.render(); } catch(_e){}
    try { ElementaryDashboardUI.refreshAfterReferralChange(); } catch(_e){}
    return { ok: true, rec: updated };
  }

  // ---------- Storage (Supabase) ----------
  const Storage = {
    supabaseUrl: SUPABASE_URL,
    publishableKey: SUPABASE_PUBLISHABLE_KEY,
    client: null,
    keepAliveTimer: null,
    _memoryCache: null,
    _rowHashes: { agents:{}, customers:{}, proposals:{} },
    _lastMetaUpdatedAt: "",
    networkTimeoutMs: GI_NETWORK_TIMEOUT_MS,
    networkRetryCount: GI_NETWORK_RETRY_COUNT,
    networkRetryDelayMs: GI_NETWORK_RETRY_DELAY_MS,
    connectionStatus: { ok:false, checkedAt:"", error:"" },
    _skipServerAgentScope: false,

    session(){
      try{
        const name = safeTrim(Auth?.current?.name);
        const role = safeTrim(Auth?.current?.role);
        return { name, role };
      }catch(_e){
        return { name:"", role:"" };
      }
    },

    setConnectionState(ok, error=""){
      this.connectionStatus = {
        ok: !!ok,
        checkedAt: nowISO(),
        error: safeTrim(error)
      };
      return this.connectionStatus;
    },

    describeError(err){
      return safeTrim(err?.message || err || '');
    },

    sleep(ms){
      return new Promise((resolve) => window.setTimeout(resolve, Math.max(0, Number(ms) || 0)));
    },

    async withTimeout(promise, label = 'פעולת שרת', timeoutMs = this.networkTimeoutMs){
      let timer = null;
      try {
        return await Promise.race([
          Promise.resolve(promise),
          new Promise((_, reject) => {
            timer = window.setTimeout(() => reject(new Error('TIMEOUT: ' + label)), Math.max(3000, Number(timeoutMs) || this.networkTimeoutMs));
          })
        ]);
      } finally {
        if(timer) window.clearTimeout(timer);
      }
    },

    async withRetry(operation, label = 'פעולת שרת', options = {}){
      const retries = Math.max(1, Number(options.retries || this.networkRetryCount) || this.networkRetryCount);
      const delayMs = Math.max(0, Number(options.delayMs || this.networkRetryDelayMs) || this.networkRetryDelayMs);
      let lastErr = null;
      for(let attempt = 1; attempt <= retries; attempt += 1){
        try {
          return await this.withTimeout(operation(attempt), label, options.timeoutMs || this.networkTimeoutMs);
        } catch(err){
          lastErr = err;
          if(attempt < retries) await this.sleep(delayMs * attempt);
        }
      }
      throw lastErr || new Error(label + ' failed');
    },

    getServerCacheMaxAge(options = {}){
      return Math.max(0, Number(options.cacheMaxAgeMs || GI_SERVER_CACHE_TTL_MS) || GI_SERVER_CACHE_TTL_MS);
    },

    buildLightCachePayload(st){
      const src = st && typeof st === "object" ? st : defaultState();
      const stripCustomer = (c) => ({
        id: c?.id,
        status: c?.status,
        fullName: c?.fullName,
        idNumber: c?.idNumber,
        phone: c?.phone,
        email: c?.email,
        city: c?.city,
        agentName: c?.agentName,
        agentId: c?.agentId,
        agentRole: c?.agentRole,
        createdBy: c?.createdBy,
        createdAt: c?.createdAt,
        updatedAt: c?.updatedAt,
        insuredCount: c?.insuredCount,
        existingPoliciesCount: c?.existingPoliciesCount,
        newPoliciesCount: c?.newPoliciesCount,
        payload: {}
      });
      const stripProposal = (p) => ({
        id: p?.id,
        status: p?.status,
        fullName: p?.fullName,
        idNumber: p?.idNumber,
        phone: p?.phone,
        agentName: p?.agentName,
        agentId: p?.agentId,
        agentRole: p?.agentRole,
        currentStep: p?.currentStep,
        createdAt: p?.createdAt,
        updatedAt: p?.updatedAt,
        insuredCount: p?.insuredCount,
        payload: {}
      });
      return {
        meta: src.meta && typeof src.meta === "object" ? src.meta : {},
        agents: Array.isArray(src.agents) ? src.agents : [],
        customers: (Array.isArray(src.customers) ? src.customers : []).map(stripCustomer),
        proposals: (Array.isArray(src.proposals) ? src.proposals : []).map(stripProposal),
        _lightCache: true
      };
    },

    _lightCacheFingerprint(light){
      const m = light?.meta || {};
      return [
        safeTrim(m.updatedAt),
        safeTrim(m.revision?.stateVersion),
        (light.customers || []).length,
        (light.proposals || []).length,
        (light.agents || []).length
      ].join("|");
    },

    saveServerCache(st, options = {}){
      const payload = options.skipNormalize === true
        ? (st || State.data || defaultState())
        : normalizeState(st || State.data || defaultState());
      this._memoryCache = { at: Date.now(), payload };
      this._scheduleServerCacheFlush();
      return payload;
    },

    _scheduleServerCacheFlush(){
      if(this._serverCacheFlushHandle) return;
      const flush = () => {
        this._serverCacheFlushHandle = null;
        try {
          const entry = this._memoryCache;
          if(!entry?.payload) return;
          const light = this.buildLightCachePayload(entry.payload);
          const fp = this._lightCacheFingerprint(light);
          if(fp === this._lastLightCacheFingerprint) return;
          this._lastLightCacheFingerprint = fp;
          GiPerf.mark("saveBackup");
          sessionStorage.setItem(GI_SERVER_CACHE_KEY, JSON.stringify({ at: entry.at, payload: light }));
          GiPerf.mark("saveBackup:end");
          GiPerf.measure("saveBackup", "saveBackup");
        } catch(_e) {}
      };
      if(typeof requestIdleCallback === "function"){
        this._serverCacheFlushHandle = requestIdleCallback(flush, { timeout: 2000 });
      } else {
        this._serverCacheFlushHandle = window.setTimeout(flush, 50);
      }
    },

    loadServerCache(maxAgeMs = GI_SERVER_CACHE_TTL_MS){
      const isFresh = (entry) => entry && entry.payload && (!maxAgeMs || (Date.now() - Number(entry.at || 0)) <= maxAgeMs);
      if(isFresh(this._memoryCache)) return normalizeState(this._memoryCache.payload);
      try {
        const raw = sessionStorage.getItem(GI_SERVER_CACHE_KEY);
        if(!raw) return null;
        const parsed = JSON.parse(raw);
        if(isFresh(parsed)){
          const payload = normalizeState(parsed.payload);
          this._memoryCache = { at: Number(parsed.at || Date.now()), payload };
          return payload;
        }
      } catch(_e) {}
      return null;
    },

    stableStringify(value){
      const seen = new WeakSet();
      const sortValue = (v) => {
        if(v && typeof v === 'object'){
          if(seen.has(v)) return null;
          seen.add(v);
          if(Array.isArray(v)) return v.map(sortValue);
          return Object.keys(v).sort().reduce((acc, key) => { acc[key] = sortValue(v[key]); return acc; }, {});
        }
        return v;
      };
      try { return JSON.stringify(sortValue(value)); } catch(_e) { return JSON.stringify(value || {}); }
    },

    rowHash(row){
      const r = row || {};
      const payload = r.payload;
      const hasPayload = payload && (typeof payload === "object" || typeof payload === "string");
      if(hasPayload){
        let payloadTag = "0";
        if(typeof payload === "string") payloadTag = "s:" + payload.length;
        else if(isCustomerPayloadTooHeavyForSyncMetrics({ payload })) payloadTag = "h";
        else {
          try { payloadTag = "l:" + estimateRecordPayloadBytes({ payload }); } catch(_e) { payloadTag = "h"; }
        }
        return [
          safeTrim(r.id),
          safeTrim(r.updated_at || r.updatedAt),
          safeTrim(r.status),
          Number(r.new_policies_count ?? r.newPoliciesCount ?? 0) || 0,
          Number(r.existing_policies_count ?? r.existingPoliciesCount ?? 0) || 0,
          Number(r.insured_count ?? r.insuredCount ?? 0) || 0,
          Number(r.current_step ?? r.currentStep ?? 0) || 0,
          safeTrim(r.full_name || r.fullName),
          safeTrim(r.agent_name || r.agentName),
          payloadTag
        ].join("|");
      }
      const clean = { ...r };
      delete clean.updated_at;
      delete clean.created_at;
      return this.stableStringify(clean);
    },

    rememberRows(tableName, rows){
      const key = this.getHashBucketKey(tableName);
      if(!key) return;
      this._rowHashes[key] = this._rowHashes[key] || {};
      (Array.isArray(rows) ? rows : []).forEach((row) => {
        const id = safeTrim(row?.id);
        if(id) this._rowHashes[key][id] = this.rowHash(row);
      });
    },

    getHashBucketKey(tableName){
      const t = safeTrim(tableName);
      if(t === SUPABASE_TABLES.agents) return 'agents';
      if(t === SUPABASE_TABLES.customers) return 'customers';
      if(t === SUPABASE_TABLES.proposals) return 'proposals';
      return '';
    },

    getChangedRows(tableName, rows){
      const key = this.getHashBucketKey(tableName);
      if(!key) return Array.isArray(rows) ? rows : [];
      const bucket = this._rowHashes[key] || {};
      return (Array.isArray(rows) ? rows : []).filter((row) => {
        const id = safeTrim(row?.id);
        if(!id) return false;
        return bucket[id] !== this.rowHash(row);
      });
    },

    isMissingChatSqlError(err){
      const msg = this.describeError(err).toLowerCase();
      return !!msg && (
        msg.includes(String(SUPABASE_CHAT.messagesTable || '').toLowerCase()) ||
        msg.includes('relation') ||
        msg.includes('does not exist') ||
        msg.includes('schema cache')
      );
    },

    async probeConnection(){
      if(!this.supabaseUrl || !this.publishableKey) return { ok:false, error:'חסרים פרטי חיבור ל-Supabase' };
      try {
        const client = this.getClient();
        const { error } = await this.withRetry(
          () => client.from(SUPABASE_TABLES.meta).select('key').eq('key', 'global').limit(1),
          'בדיקת חיבור Supabase',
          { retries: 1, timeoutMs: 7000 }
        );
        if(error) throw error;
        this.setConnectionState(true, '');
        return { ok:true, at: nowISO() };
      } catch(err){
        const message = this.describeError(err) || 'בעיה זמנית בחיבור ל-Supabase';
        this.setConnectionState(false, message);
        return { ok:false, error: message };
      }
    },

    async waitForConnection(options = {}){
      const retries = Math.max(1, Number(options.retries || SUPABASE_CONNECTION_RETRY_COUNT));
      const delayMs = Math.max(250, Number(options.delayMs || SUPABASE_CONNECTION_RETRY_DELAY_MS));
      let last = null;
      for(let attempt = 1; attempt <= retries; attempt += 1){
        const result = await this.probeConnection();
        if(result.ok) return { ok:true, at: result.at, attempts: attempt };
        last = result;
        if(attempt < retries) await new Promise((resolve) => setTimeout(resolve, delayMs));
      }
      return { ok:false, error: safeTrim(last?.error) || 'בעיה זמנית בחיבור לשרת', attempts: retries };
    },

    startKeepAlive(){
      clearInterval(this.keepAliveTimer);
      this.keepAliveTimer = setInterval(async () => {
        try {
          if(document.body.classList.contains('lcAuthLock')) return;
          await this.probeConnection();
        } catch(_e) {}
      }, SUPABASE_KEEPALIVE_MS);
    },

    stopKeepAlive(){
      clearInterval(this.keepAliveTimer);
      this.keepAliveTimer = null;
    },

    loadBackup(){
      // גיבוי חירום קצר בלבד: לא מחליף שרת, רק מונע קריסה/תקיעה כש-Supabase לא עונה.
      return this.loadServerCache(1000 * 60 * 10);
    },
    getFastCacheKey(){
      return LS_FAST_CACHE_KEY;
    },
    getTableCacheKey(tableName){
      return LS_TABLE_CACHE_PREFIX + safeTrim(tableName || '').toLowerCase();
    },
    buildFastCachePayload(st){
      return null;
    },
    saveFastCache(st){
      return;
    },
    loadFastCache(maxAgeMs = FAST_CACHE_MAX_AGE_MS){
      return null;
    },
    loadFastCacheAnyAge(){
      return null;
    },
    loadTableCache(tableName){
      return null;
    },
    buildStateFromTableCaches(){
      return null;
    },
    saveBackup(st){
      try { this.saveServerCache(st, { skipNormalize: true }); } catch(_e) {}
      return;
    },
    clearLegacyCaches(options = {}){
      try { localStorage.removeItem(this.getFastCacheKey()); } catch(_) {}
      ['meta','agents','customers','proposals'].forEach((name) => {
        try { localStorage.removeItem(this.getTableCacheKey(name)); } catch(_) {}
      });
      try { localStorage.removeItem(LS_BACKUP_KEY); } catch(_) {}
    },

    restoreUrl(){ return this.supabaseUrl; },
    setUrl(){ return this.supabaseUrl; },

    getClient(){
      if(this.client) return this.client;
      if(!window.supabase || typeof window.supabase.createClient !== "function") {
        throw new Error("SUPABASE_CLIENT_NOT_LOADED");
      }
      this.client = window.supabase.createClient(this.supabaseUrl, this.publishableKey, {
        auth: {
          // Keep Supabase Auth JWT across refresh (MFA / signInWithPassword).
          // Row-level policies on proposals/customers often require authenticated;
          // persistSession:false caused requests to fall back to anon after reload.
          persistSession: true,
          autoRefreshToken: true,
          detectSessionInUrl: false,
          storageKey: "gemel_invest_sb_auth_v1"
        }
      });
      // DevTools: מה-CDN זה רק ה-SDK (למשל createClient), לא לקוח עם .auth — השתמשו ב־gemelInvestSupabaseClient לאחר טעינת האפליקציה (למשל await gemelInvestSupabaseClient?.auth?.getUser()).
      if (!window.__giSupabaseConsoleClientHook) {
        window.__giSupabaseConsoleClientHook = true;
        try {
          Object.defineProperty(window, "gemelInvestSupabaseClient", {
            configurable: true,
            enumerable: false,
            get() {
              return Storage.client;
            }
          });
        } catch (_e) {}
      }
      return this.client;
    },

    async ping(){
      if(!this.supabaseUrl || !this.publishableKey) return { ok:false, error:"חסרים פרטי חיבור ל-Supabase" };
      try {
        const res = await fetch(this.supabaseUrl + "/auth/v1/settings", {
          method:"GET",
          cache:"no-store",
          headers: {
            apikey: this.publishableKey,
            Authorization: "Bearer " + this.publishableKey
          }
        });
        if(!res.ok) return { ok:false, error:"PING_FAILED_" + res.status };
        return { ok:true, at: nowISO() };
      } catch(e) {
        return { ok:false, error: String(e?.message || e) };
      }
    },

    buildMetaRow(state){
      const meta = state?.meta || {};
      const clocks = normalizeMetaSyncClocks(meta);
      const updatedAt = safeTrim(meta.updatedAt) || clocks.dataUpdatedAt;
      return {
        key: "global",
        payload: {
          adminAuth: state?.meta?.adminAuth || defaultState().meta.adminAuth,
          opsEvents: Array.isArray(state?.meta?.opsEvents) ? state.meta.opsEvents.map((ev, idx) => normalizeOpsEvent(ev, idx)).filter(Boolean) : [],
          chatAvatars: normalizeChatAvatarMap(state?.meta?.chatAvatars),
          usersManagementAccess: normalizeUsersManagementAccess(state?.meta?.usersManagementAccess),
          // BUG-FIX: resolve monthlySalesTarget from agentTargets store (authoritative source).
          agentsShadow: (() => {
            const metaT = (state?.meta?.agentTargets && typeof state.meta.agentTargets === 'object') ? state.meta.agentTargets : {};
            return (state?.agents || []).map((a, idx) => {
              const aid = safeTrim(a?.id) || ("a_" + idx);
              const se = metaT[aid];
              const storeT = se ? (Number(String(se.monthlySalesTarget ?? '').replace(/[^\d.-]/g, '')) || 0) : 0;
              const recT = Number(String(a?.monthlySalesTarget ?? a?.monthly_sales_target ?? '').replace(/[^\d.-]/g, '')) || 0;
              return {
                id: aid,
                name: safeTrim(a?.name) || "נציג",
                username: safeTrim(a?.username) || safeTrim(a?.name) || "נציג",
                pin: safeTrim(a?.pin) || "0000",
                birthDate: safeTrim(a?.birthDate || a?.birth_date),
                email: safeTrim(a?.email) || null,
                monthlySalesTarget: storeT > 0 ? storeT : recT,
                role: safeTrim(a?.role) || "agent",
                teamManagerId: safeTrim(a?.teamManagerId || a?.team_manager_id) || null,
                active: a?.active === false ? false : true,
                createdAt: safeTrim(a?.createdAt || a?.created_at) || nowISO(),
                updatedAt: safeTrim(a?.updatedAt || a?.updated_at) || nowISO()
              };
            });
          })(),
          // Egress Guard v2: do not duplicate full customers/proposals payloads inside app_meta.
          customersShadow: [],
          proposalsShadow: [],
          elementaryReferrals: getElementaryReferrals(),
          teamManagerAssignments: normalizeTeamManagerAssignmentsMap(state?.meta?.teamManagerAssignments),
          teamManagerAssignmentsUpdatedAt: safeTrim(state?.meta?.teamManagerAssignmentsUpdatedAt) || null,
          agentReportAliases: normalizeAgentReportAliasesMap(state?.meta?.agentReportAliases),
          agentReportAliasesUpdatedAt: safeTrim(state?.meta?.agentReportAliasesUpdatedAt) || null,
          ...clocks,
          updatedAt
        },
        updated_at: updatedAt
      };
    },

    buildAgentRows(state){
      // BUG-FIX: resolve monthly_sales_target from the agentTargets store when available.
      // The store is the authoritative source — a.monthlySalesTarget on the agent record
      // can lag behind or be 0 if it was set via setAgentMonthlyTarget after the last
      // normalizeAgentRecord call (e.g. during a save cycle).
      const metaTargets = (state?.meta?.agentTargets && typeof state.meta.agentTargets === 'object') ? state.meta.agentTargets : {};
      return (state?.agents || []).map((a, idx) => {
        const agentId = safeTrim(a?.id) || ("a_" + idx);
        const storeEntry = metaTargets[agentId];
        const storeTarget = storeEntry ? (Number(String(storeEntry.monthlySalesTarget ?? '').replace(/[^\d.-]/g, '')) || 0) : 0;
        const recordTarget = Number(String(a?.monthlySalesTarget ?? a?.monthly_sales_target ?? '').replace(/[^\d.-]/g, '')) || 0;
        const monthly_sales_target = storeTarget > 0 ? storeTarget : recordTarget;
        return {
          id: agentId,
          name: safeTrim(a?.name) || "נציג",
          username: safeTrim(a?.username) || safeTrim(a?.name) || "נציג",
          pin: safeTrim(a?.pin) || "0000",
          role: safeTrim(a?.role) || "agent",
          active: a?.active === false ? false : true,
          birth_date: safeTrim(a?.birthDate) || null,
          email: safeTrim(a?.email) || null,
          monthly_sales_target,
          team_manager_id: safeTrim(a?.teamManagerId || a?.team_manager_id) || null,
          created_at: safeTrim(a?.created_at) || nowISO(),
          updated_at: safeTrim(a?.updatedAt || a?.updated_at) || nowISO()
        };
      });
    },

    buildCustomerRows(state){
      return (state?.customers || []).map((c, idx) => ({
        id: safeTrim(c?.id) || ("cust_" + idx),
        status: safeTrim(c?.status) || "חדש",
        full_name: safeTrim(c?.fullName) || "לקוח ללא שם",
        id_number: safeTrim(c?.idNumber),
        phone: safeTrim(c?.phone),
        email: safeTrim(c?.email),
        city: safeTrim(c?.city),
        agent_name: safeTrim(c?.agentName),
        agent_id: safeTrim(c?.agentId) || safeTrim(c?.payload?.agentId) || "",
        agent_role: safeTrim(c?.agentRole),
        insured_count: Number(c?.insuredCount || 0) || 0,
        existing_policies_count: Number(c?.existingPoliciesCount || 0) || 0,
        new_policies_count: Number(c?.newPoliciesCount || 0) || 0,
        created_at: safeTrim(c?.createdAt) || nowISO(),
        updated_at: safeTrim(c?.updatedAt || c?.updated_at) || nowISO(),
        payload: c?.payload && typeof c.payload === "object" ? c.payload : {}
      }));
    },

    buildProposalRows(state){
      return (state?.proposals || []).map((p, idx) => ({
        id: safeTrim(p?.id) || ("prop_" + idx),
        status: safeTrim(p?.status) || "פתוחה",
        full_name: safeTrim(p?.fullName) || "הצעה ללא שם",
        id_number: safeTrim(p?.idNumber),
        phone: safeTrim(p?.phone),
        email: safeTrim(p?.email),
        city: safeTrim(p?.city),
        agent_name: safeTrim(p?.agentName),
        agent_id: safeTrim(p?.agentId) || safeTrim(p?.payload?.agentId) || "",
        agent_role: safeTrim(p?.agentRole),
        current_step: Math.max(1, Math.min(getMaxProposalWizardStepIdFromPayload(p?.payload), Number(p?.currentStep || 1) || 1)),
        insured_count: Number(p?.insuredCount || 0) || 0,
        created_at: safeTrim(p?.createdAt) || nowISO(),
        updated_at: safeTrim(p?.updatedAt || p?.updated_at) || nowISO(),
        payload: p?.payload && typeof p.payload === "object" ? p.payload : {}
      }));
    },

    async upsertSingleRow(tableName, row, options = {}){
      const payload = row && typeof row === 'object' ? row : {};
      const retryOptions = {
        retries: options.retries,
        timeoutMs: options.timeoutMs,
        delayMs: options.delayMs
      };
      try {
        const client = this.getClient();
        const { error } = await this.withRetry(
          () => client.from(tableName).upsert([payload], { onConflict: 'id' }),
          'שמירת רשומה ' + tableName,
          retryOptions
        );
        if(error) throw error;
        return { ok:true, at: nowISO() };
      } catch(primaryErr) {
        try {
          await this.restRequest(tableName, {
            method: 'POST',
            body: payload,
            headers: { Prefer: 'resolution=merge-duplicates,return=minimal' },
            timeoutMs: options.timeoutMs
          });
          return { ok:true, at: nowISO() };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    async loadSingleRow(tableName, id, selectExpr='*'){
      const safeId = safeTrim(id);
      if(!safeId) return { ok:false, error:'MISSING_ID' };
      try {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => client.from(tableName).select(selectExpr).eq('id', safeId).maybeSingle(),
          'טעינת רשומה ' + tableName
        );
        if(error) throw error;
        return { ok:true, data: data || null };
      } catch(primaryErr) {
        try {
          const data = await this.restRequest(tableName + '?id=eq.' + encodeURIComponent(safeId) + '&select=' + encodeURIComponent(selectExpr), { method:'GET' });
          return { ok:true, data: Array.isArray(data) ? (data[0] || null) : (data || null) };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    rowMatchesExpected(actualRow, expected = {}){
      const actual = actualRow && typeof actualRow === 'object' ? actualRow : {};
      const normalizedExpected = expected && typeof expected === 'object' ? expected : {};
      return Object.entries(normalizedExpected).every(([key, expectedValue]) => {
        const actualValue = actual[key];
        if(typeof expectedValue === 'function'){
          try { return !!expectedValue(actualValue, actual); } catch(_e) { return false; }
        }
        if(expectedValue && typeof expectedValue === 'object' && !Array.isArray(expectedValue)){
          if(Object.prototype.hasOwnProperty.call(expectedValue, 'equals')){
            return safeTrim(actualValue) === safeTrim(expectedValue.equals);
          }
          if(Object.prototype.hasOwnProperty.call(expectedValue, 'includes')){
            return safeTrim(actualValue).includes(safeTrim(expectedValue.includes));
          }
        }
        return safeTrim(actualValue) === safeTrim(expectedValue);
      });
    },

    async verifySavedRow(tableName, id, expected = {}, options = {}){
      const retries = Math.max(1, Number(options.retries || SUPABASE_SAVE_VERIFY_RETRY_COUNT) || SUPABASE_SAVE_VERIFY_RETRY_COUNT);
      const delayMs = Math.max(0, Number(options.delayMs || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS) || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS);
      const selectExpr = safeTrim(options.selectExpr || '*') || '*';
      let lastResult = null;
      for(let attempt = 1; attempt <= retries; attempt += 1){
        lastResult = await this.loadSingleRow(tableName, id, selectExpr);
        if(lastResult?.ok && lastResult?.data && this.rowMatchesExpected(lastResult.data, expected)){
          return { ok:true, data:lastResult.data, attempt, at: nowISO() };
        }
        if(attempt < retries && delayMs > 0){
          await new Promise((resolve) => window.setTimeout(resolve, delayMs));
        }
      }
      return {
        ok:false,
        error: safeTrim(lastResult?.error) || 'VERIFY_FAILED',
        data: lastResult?.data || null,
        at: nowISO()
      };
    },

    async getAuthAccessToken(){
      try {
        const { data } = await this.getClient().auth.getSession();
        return safeTrim(data?.session?.access_token);
      } catch(_e) {
        return "";
      }
    },

    async restHeaders(extra = {}){
      const token = await this.getAuthAccessToken();
      const bearer = token || this.publishableKey;
      return {
        apikey: this.publishableKey,
        Authorization: "Bearer " + bearer,
        "Content-Type": "application/json",
        Prefer: "return=minimal",
        ...extra
      };
    },

    async restRequest(path, options = {}){
      const method = String(options.method || "GET").toUpperCase();
      return this.withRetry(async () => {
        const controller = new AbortController();
        const timer = window.setTimeout(() => controller.abort(), Math.max(3000, Number(options.timeoutMs || this.networkTimeoutMs) || this.networkTimeoutMs));
        try {
          const res = await fetch(this.supabaseUrl + "/rest/v1/" + String(path || ""), {
            method,
            cache:"no-store",
            signal: controller.signal,
            headers: await this.restHeaders(options.headers || {}),
            body: options.body == null ? undefined : JSON.stringify(options.body)
          });
          let payload = null;
          try { payload = await res.json(); } catch(_e) {}
          if(!res.ok){
            const msg = payload?.message || payload?.error_description || payload?.hint || ("HTTP_" + res.status);
            throw new Error(msg);
          }
          return payload;
        } finally {
          window.clearTimeout(timer);
        }
      }, 'REST ' + method + ' ' + String(path || '').slice(0, 80), options);
    },

    async upsertMeta(state){
      const row = this.buildMetaRow(state);
      try {
        const client = this.getClient();
        const { error } = await this.withRetry(
          () => client.from(SUPABASE_TABLES.meta).upsert([row], { onConflict: "key" }),
          'שמירת הגדרות מערכת'
        );
        if(error) throw error;
        this.invalidateMetaRowCache();
        return { ok:true, at: nowISO() };
      } catch(primaryErr) {
        try {
          const existing = await this.restRequest(SUPABASE_TABLES.meta + "?key=eq.global&select=key", {
            method: "GET"
          });
          if(Array.isArray(existing) && existing.length){
            await this.restRequest(SUPABASE_TABLES.meta + "?key=eq.global", {
              method: "PATCH",
              body: row,
              headers: { Prefer: "return=minimal" }
            });
          } else {
            await this.restRequest(SUPABASE_TABLES.meta, {
              method: "POST",
              body: row,
              headers: { Prefer: "return=minimal" }
            });
          }
          this.invalidateMetaRowCache();
          return { ok:true, at: nowISO(), mode:"rest-fallback" };
        } catch(secondaryErr) {
          const err = String(secondaryErr?.message || primaryErr?.message || secondaryErr || primaryErr);
          console.error("META_SAVE_FAILED:", err);
          return { ok:false, error: err };
        }
      }
    },

    invalidateMetaRowCache(){
      this._metaRowCache = null;
    },

    /** סנכרון נציגים לטבלת agents — bulk ואז upsert שורה-שורה; בלי rememberRows אם נכשל. */
    async syncAgentsFromState(state, options = {}){
      const agentRows = this.buildAgentRows(state);
      const onlyAgentIds = Array.isArray(options.onlyAgentIds)
        ? [...new Set(options.onlyAgentIds.map((id) => safeTrim(id)).filter(Boolean))]
        : [];
      const changedRows = onlyAgentIds.length
        ? agentRows.filter((row) => onlyAgentIds.includes(safeTrim(row?.id)))
        : (options.forceAll === true
          ? agentRows
          : this.getChangedRows(SUPABASE_TABLES.agents, agentRows));
      if(!changedRows.length) return { ok:true, skipped:true, synced:0, at: nowISO() };

      const rememberOnSuccess = () => {
        try { this.rememberRows(SUPABASE_TABLES.agents, agentRows); } catch(_e) {}
      };

      const upsertAgentRow = async (row) => {
        const res = await this.upsertSingleRow(SUPABASE_TABLES.agents, row);
        if(res?.ok) return res;
        const msg = safeTrim(res?.error);
        if(msg && /pin|team_manager|column|schema/i.test(msg) && row){
          const slim = { ...row };
          if(/pin/i.test(msg)) delete slim.pin;
          if(/team_manager/i.test(msg)){
            delete slim.team_manager_id;
            const slimRes = await this.upsertSingleRow(SUPABASE_TABLES.agents, slim);
            return { ...slimRes, teamManagerColumnSkipped: true };
          }
          return this.upsertSingleRow(SUPABASE_TABLES.agents, slim);
        }
        return res;
      };

      try {
        await this.syncTable(SUPABASE_TABLES.agents, changedRows, { allowDelete:false });
        rememberOnSuccess();
        return { ok:true, synced: changedRows.length, mode:"bulk", at: nowISO() };
      } catch(bulkErr) {
        console.warn("AGENTS_BULK_SYNC_FAILED:", bulkErr?.message || bulkErr);
      }

      const rowErrors = [];
      let synced = 0;
      let teamManagerColumnSkipped = false;
      for(const row of changedRows){
        const id = safeTrim(row?.id);
        if(!id) continue;
        try {
          const res = await upsertAgentRow(row);
          if(res?.teamManagerColumnSkipped) teamManagerColumnSkipped = true;
          if(res?.ok) synced += 1;
          else rowErrors.push(id + ": " + formatAgentServerPersistError(safeTrim(res?.error) || "UPSERT_FAILED"));
        } catch(rowErr) {
          rowErrors.push(id + ": " + formatAgentServerPersistError(rowErr?.message || rowErr));
        }
      }
      if(synced === changedRows.length){
        rememberOnSuccess();
        return {
          ok:true,
          synced,
          mode:"row-upsert",
          teamManagerColumnSkipped,
          at: nowISO()
        };
      }
      const joinedErr = rowErrors.join(" | ") || "AGENTS_SYNC_FAILED";
      return {
        ok:false,
        synced,
        total: changedRows.length,
        error: formatAgentServerPersistError(joinedErr),
        teamManagerColumnSkipped,
        at: nowISO()
      };
    },

    async syncTable(tableName, rows, options = {}){
      const safeRows = Array.isArray(rows) ? rows.filter(Boolean) : [];
      const allowDelete = options?.allowDelete === true;

      if(allowDelete && safeRows.length){
        console.warn("SYNC_DELETE_DISABLED_BY_POLICY:", tableName);
      }

      if(!safeRows.length) return { ok:true, skipped:true, at: nowISO() };

      try {
        const client = this.getClient();
        const { error: upsertError } = await this.withRetry(
          () => client.from(tableName).upsert(safeRows, { onConflict: "id" }),
          'שמירת טבלה ' + tableName,
          { timeoutMs: 18000 }
        );
        if(upsertError) throw upsertError;
        return { ok:true, at: nowISO() };
      } catch(primaryErr) {
        console.warn("SYNC_BULK_UPSERT_FAILED:", tableName, primaryErr?.message || primaryErr);
      }

      for (const row of safeRows){
        const id = safeTrim(row?.id);
        if(!id) continue;
        try {
          const updated = await this.restRequest(tableName + "?id=eq." + encodeURIComponent(id) + "&select=id", {
            method: "PATCH",
            body: row
          });
          if(Array.isArray(updated) && updated.length) continue;
          await this.restRequest(tableName, {
            method: "POST",
            body: row
          });
        } catch(rowErr) {
          throw rowErr;
        }
      }
      return { ok:true, at: nowISO(), mode:'row-upsert' };
    },

    async deleteRowByIdSafe(tableName, id, options = {}){
      const safeId = safeTrim(id);
      if(!safeId) return { ok:false, error:"MISSING_ID" };
      if(!/^[A-Za-z0-9_-]+$/.test(safeId)) return { ok:false, error:"INVALID_ID_FORMAT" };

      const guards = options?.guards && typeof options.guards === "object" ? options.guards : {};
      const requireArchivedStatus = options?.requireArchivedStatus === true;
      const allowMissing = options?.allowMissing === true;
      const selectExpr = safeTrim(options.selectExpr || "id,status,full_name,id_number") || "id,status,full_name,id_number";

      const pre = await this.loadSingleRow(tableName, safeId, selectExpr);
      if(!pre?.ok){
        return { ok:false, error: safeTrim(pre?.error) || "PRELOAD_FAILED" };
      }
      if(!pre?.data){
        return allowMissing ? { ok:true, skipped:true, at: nowISO(), id: safeId } : { ok:false, error:"ROW_NOT_FOUND" };
      }

      const row = pre.data;
      if(requireArchivedStatus && tableName === SUPABASE_TABLES.customers && !isSafePurgeCustomerServerStatus(row?.status)){
        return { ok:false, error:"CUSTOMER_NOT_ARCHIVED_ON_SERVER" };
      }
      if(safeTrim(guards.id_number) && safeTrim(row?.id_number) !== safeTrim(guards.id_number)){
        return { ok:false, error:"ID_NUMBER_MISMATCH" };
      }
      if(safeTrim(guards.full_name) && safeTrim(row?.full_name) !== safeTrim(guards.full_name)){
        return { ok:false, error:"FULL_NAME_MISMATCH" };
      }

      const performDelete = async () => {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => client.from(tableName).delete().eq("id", safeId).select("id"),
          "מחיקת רשומה " + tableName,
          { timeoutMs: 15000 }
        );
        if(error) throw error;
        const deleted = Array.isArray(data) ? data : [];
        if(deleted.length !== 1) throw new Error(deleted.length ? "UNEXPECTED_DELETE_COUNT" : "DELETE_NO_ROWS");
        return deleted;
      };

      try {
        await performDelete();
      } catch(primaryErr) {
        try {
          await this.restRequest(tableName + "?id=eq." + encodeURIComponent(safeId), {
            method: "DELETE",
            headers: { Prefer: "return=representation" },
            timeoutMs: 15000
          });
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }

      const post = await this.loadSingleRow(tableName, safeId, "id");
      if(post?.ok && post?.data) return { ok:false, error:"DELETE_VERIFY_FAILED" };
      return { ok:true, at: nowISO(), id: safeId, count: 1 };
    },

    async deleteAllCampaignLeadRows(){
      const tableName = SUPABASE_TABLES.campaignLeads;
      const countBefore = (await this.loadTableRows(tableName, "id"))?.data?.length || 0;
      if(!countBefore) return { ok:true, count:0, skipped:true, at: nowISO() };

      const verifyEmpty = async () => {
        const verify = await this.loadTableRows(tableName, "id");
        if(!verify?.ok) return { ok:false, error: safeTrim(verify?.error) || "VERIFY_FAILED" };
        const remaining = Array.isArray(verify.data) ? verify.data.length : 0;
        return remaining ? { ok:false, error:"DELETE_VERIFY_FAILED", remaining } : { ok:true };
      };

      const performBulkDelete = async () => {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => client.from(tableName).delete().neq("id", "").select("id"),
          "מחיקת כל לידי קמפיין",
          { timeoutMs: 30000 }
        );
        if(error) throw error;
        return Array.isArray(data) ? data.length : 0;
      };

      try {
        const deleted = await performBulkDelete();
        const empty = await verifyEmpty();
        if(empty.ok) return { ok:true, count: Math.max(deleted, countBefore), at: nowISO() };
      } catch(primaryErr) {
        try {
          await this.restRequest(tableName + "?id=neq.", {
            method: "DELETE",
            headers: { Prefer: "return=representation" },
            timeoutMs: 30000
          });
          const empty = await verifyEmpty();
          if(empty.ok) return { ok:true, count: countBefore, at: nowISO(), mode:"rest-fallback" };
        } catch(restErr) {
          console.warn("CAMPAIGN_LEADS_BULK_DELETE_FAILED:", restErr?.message || restErr);
        }
      }

      const reload = await this.loadTableRows(tableName, "id");
      if(!reload?.ok) return { ok:false, error: safeTrim(reload?.error) || "LOAD_FAILED" };
      const ids = (reload.data || []).map((row) => safeTrim(row?.id)).filter(Boolean);
      let deletedCount = 0;
      for(const id of ids){
        const attempt = await this.deleteRowByIdSafe(tableName, id, { allowMissing: true, selectExpr: "id" });
        if(attempt?.ok && !attempt?.skipped) deletedCount++;
      }
      const empty = await verifyEmpty();
      if(!empty.ok) return { ok:false, error: empty.error || "DELETE_VERIFY_FAILED", remaining: empty.remaining || ids.length };
      return { ok:true, count: Math.max(deletedCount, countBefore), at: nowISO(), mode:"row-by-row" };
    },

    async purgeArchivedCustomerOnServer(customerId, customerSnapshot = {}){
      const safeId = safeTrim(customerId);
      if(!safeId) return { ok:false, error:"MISSING_ID" };

      const guards = safeTrim(customerSnapshot?.idNumber) ? { id_number: safeTrim(customerSnapshot.idNumber) } : {};
      const deleteAttempt = await this.deleteRowByIdSafe(SUPABASE_TABLES.customers, safeId, {
        requireArchivedStatus: true,
        allowMissing: true,
        guards
      });
      if(deleteAttempt?.ok && !deleteAttempt?.skipped) return { ok:true, mode:"deleted", at: deleteAttempt.at || nowISO() };
      if(deleteAttempt?.ok && deleteAttempt?.skipped) return { ok:true, mode:"already_gone", at: deleteAttempt.at || nowISO() };

      const rawErr = safeTrim(deleteAttempt?.error);
      const canTombstone = /delete is blocked/i.test(rawErr)
        || /customers_history/i.test(rawErr)
        || /row-level security|rls/i.test(rawErr)
        || rawErr === "DELETE_VERIFY_FAILED"
        || rawErr === "DELETE_NO_ROWS";

      if(!canTombstone) return deleteAttempt;

      const normalized = normalizeCustomerRecord({
        ...(customerSnapshot && typeof customerSnapshot === "object" ? cloneCustomerRecordDeep(customerSnapshot) : {}),
        id: safeId,
        status: "purged",
        updatedAt: nowISO(),
        payload: {}
      }, 0);
      const row = this.buildCustomerRows({ customers: [normalized] })[0];
      const saveRes = await this.upsertSingleRow(SUPABASE_TABLES.customers, row);
      if(!saveRes?.ok) return { ok:false, error: safeTrim(saveRes?.error) || "PURGE_TOMBSTONE_FAILED" };

      const verify = await this.verifySavedRow(
        SUPABASE_TABLES.customers,
        safeId,
        { status: { equals: "purged" } },
        { selectExpr: "id,status", retries: 4, delayMs: 500 }
      );
      if(!verify?.ok) return { ok:false, error:"PURGE_TOMBSTONE_VERIFY_FAILED" };
      return { ok:true, mode:"tombstone", at: nowISO() };
    },

    async deleteRows(tableName, ids = [], options = {}){
      const normalizedIds = Array.from(new Set((Array.isArray(ids) ? ids : []).map((id) => safeTrim(id)).filter(Boolean)));
      if(!normalizedIds.length) return { ok:true, skipped:true, at: nowISO() };
      if(normalizedIds.length === 1){
        return this.deleteRowByIdSafe(tableName, normalizedIds[0], options?.purgeOptions || options || {});
      }
      try {
        const client = this.getClient();
        const { error } = await this.withRetry(
          () => client.from(tableName).delete().in('id', normalizedIds),
          'מחיקת רשומות ' + tableName
        );
        if(error) throw error;
        return { ok:true, at: nowISO(), count: normalizedIds.length };
      } catch(primaryErr) {
        try {
          const idsExpr = normalizedIds.map(id => '"' + String(id).replace(/"/g, '\"') + '"').join(',');
          await this.restRequest(tableName + '?id=in.(' + idsExpr + ')', {
            method: 'DELETE',
            headers: { Prefer: 'return=minimal' }
          });
          return { ok:true, at: nowISO(), count: normalizedIds.length };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    mapMeta(metaRow){
      const payload = metaRow?.payload && typeof metaRow.payload === "object" ? metaRow.payload : {};
      const updatedAt = safeTrim(payload?.updatedAt) || safeTrim(metaRow?.updated_at) || nowISO();
      const clocks = normalizeMetaSyncClocks(payload, updatedAt);
      return {
        updatedAt,
        ...clocks,
        adminAuth: payload?.adminAuth || defaultState().meta.adminAuth,
        usersManagementAccess: normalizeUsersManagementAccess(payload?.usersManagementAccess),
        opsEvents: Array.isArray(payload?.opsEvents) ? payload.opsEvents.map((ev, idx) => normalizeOpsEvent(ev, idx)).filter(Boolean) : [],
        chatAvatars: normalizeChatAvatarMap(payload?.chatAvatars),
        agentsShadow: Array.isArray(payload?.agentsShadow) ? payload.agentsShadow.map((row, idx) => ({
          id: safeTrim(row?.id) || ("a_" + idx),
          name: safeTrim(row?.name),
          username: safeTrim(row?.username),
          pin: safeTrim(row?.pin),
          birthDate: safeTrim(row?.birthDate || row?.birth_date),
          email: safeTrim(row?.email),
          monthlySalesTarget: Number(String(row?.monthlySalesTarget ?? row?.monthly_sales_target ?? '').replace(/[^\d.-]/g, '')) || 0,
          role: safeTrim(row?.role) || "agent",
          teamManagerId: safeTrim(row?.teamManagerId || row?.team_manager_id) || "",
          active: row?.active === false ? false : true,
          createdAt: safeTrim(row?.createdAt || row?.created_at),
          updatedAt: safeTrim(row?.updatedAt || row?.updated_at)
        })).filter(Boolean) : [],
        customersShadow: Array.isArray(payload?.customersShadow) ? payload.customersShadow.map((row, idx) => normalizeCustomerRecord(row, idx)).filter(Boolean) : [],
        proposalsShadow: Array.isArray(payload?.proposalsShadow) ? payload.proposalsShadow.map((row, idx) => normalizeProposalRecord(row, idx)).filter(Boolean) : [],
        auditLog: normalizeAuditLogList(payload?.auditLog),
        archivedCustomers: normalizeArchivedCustomersList(payload?.archivedCustomers),
        elementaryReferrals: Array.isArray(payload?.elementaryReferrals)
          ? payload.elementaryReferrals.map((row, idx) => normalizeElementaryReferral(row, idx)).filter(Boolean)
          : [],
        deletedElementaryReferralIds: normalizeDeletedElementaryReferralIds(payload?.deletedElementaryReferralIds),
        revision: normalizeRevisionMeta(payload?.revision, safeTrim(payload?.updatedAt) || safeTrim(metaRow?.updated_at) || nowISO()),
        teamManagerAssignments: normalizeTeamManagerAssignmentsMap(payload?.teamManagerAssignments),
        teamManagerAssignmentsUpdatedAt: safeTrim(payload?.teamManagerAssignmentsUpdatedAt) || null,
        agentReportAliases: normalizeAgentReportAliasesMap(payload?.agentReportAliases),
        agentReportAliasesUpdatedAt: safeTrim(payload?.agentReportAliasesUpdatedAt) || null
      };
    },

    async verifyTeamManagerAssignmentsOnServer(managerId, expectedAgentIds, options = {}){
      const mid = safeTrim(managerId);
      if(!mid) return { ok:false, error:"MISSING_MANAGER_ID" };
      const expected = [...new Set((Array.isArray(expectedAgentIds) ? expectedAgentIds : []).map((id) => safeTrim(id)).filter(Boolean))].sort();
      const retries = Math.max(1, Number(options.retries || SUPABASE_SAVE_VERIFY_RETRY_COUNT) || SUPABASE_SAVE_VERIFY_RETRY_COUNT);
      const delayMs = Math.max(0, Number(options.delayMs || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS) || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS);
      let last = null;
      for(let attempt = 1; attempt <= retries; attempt += 1){
        const metaRes = await this.loadMetaRow();
        if(!metaRes?.ok){
          last = { ok:false, error: safeTrim(metaRes?.error) || "META_LOAD_FAILED" };
        } else {
          const mapped = this.mapMeta(metaRes.data || {});
          const remoteMap = normalizeTeamManagerAssignmentsMap(mapped.teamManagerAssignments);
          const remote = [...new Set((remoteMap[mid] || []).map((id) => safeTrim(id)).filter(Boolean))].sort();
          const same = remote.length === expected.length && remote.every((id, idx) => id === expected[idx]);
          if(same) return { ok:true, remote, attempt, at: nowISO() };
          last = { ok:false, error:"TEAM_MANAGER_ASSIGNMENTS_MISMATCH", remote, expected };
        }
        if(attempt < retries && delayMs > 0){
          await new Promise((resolve) => window.setTimeout(resolve, delayMs));
        }
      }
      return last || { ok:false, error:"VERIFY_FAILED" };
    },

    async verifyAgentReportAliasesOnServer(agentId, expectedNames, options = {}){
      const id = safeTrim(agentId);
      if(!id) return { ok:false, error:"MISSING_AGENT_ID" };
      const expected = [...new Set((Array.isArray(expectedNames) ? expectedNames : []).map(safeTrim).filter(Boolean))].sort();
      const retries = Math.max(1, Number(options.retries || SUPABASE_SAVE_VERIFY_RETRY_COUNT) || SUPABASE_SAVE_VERIFY_RETRY_COUNT);
      const delayMs = Math.max(0, Number(options.delayMs || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS) || SUPABASE_SAVE_VERIFY_RETRY_DELAY_MS);
      let last = null;
      for(let attempt = 1; attempt <= retries; attempt += 1){
        const metaRes = await this.loadMetaRow();
        if(!metaRes?.ok){
          last = { ok:false, error: safeTrim(metaRes?.error) || "META_LOAD_FAILED" };
        } else {
          const mapped = this.mapMeta(metaRes.data || {});
          const remoteMap = normalizeAgentReportAliasesMap(mapped.agentReportAliases);
          let remote = Array.isArray(remoteMap[id]) ? remoteMap[id].slice() : [];
          if(!remote.length){
            const lower = id.toLowerCase();
            for(const k of Object.keys(remoteMap)){
              if(k.toLowerCase() === lower){
                remote = remoteMap[k].slice();
                break;
              }
            }
          }
          remote = [...new Set(remote.map(safeTrim).filter(Boolean))].sort();
          const same = remote.length === expected.length && remote.every((name, idx) => name === expected[idx]);
          if(same) return { ok:true, remote, attempt, at: nowISO() };
          last = { ok:false, error:"AGENT_REPORT_ALIASES_MISMATCH", remote, expected };
        }
        if(attempt < retries && delayMs > 0){
          await new Promise((resolve) => window.setTimeout(resolve, delayMs));
        }
      }
      return last || { ok:false, error:"VERIFY_FAILED" };
    },

    mapAgentRow(row, idx){
      return normalizeAgentRecord({
        id: row?.id,
        name: row?.name,
        username: row?.username,
        pin: row?.pin,
        birthDate: row?.birthDate || row?.birth_date,
        email: row?.email,
        monthlySalesTarget: row?.monthlySalesTarget ?? row?.monthly_sales_target,
        role: row?.role,
        teamManagerId: row?.teamManagerId ?? row?.team_manager_id,
        active: row?.active,
        createdAt: row?.createdAt || row?.created_at,
        updatedAt: row?.updatedAt || row?.updated_at,
        created_at: row?.created_at,
        updated_at: row?.updated_at
      }, idx);
    },

    mapCustomerRow(row, idx){
      return normalizeCustomerRecord({
        id: row?.id,
        status: row?.status,
        fullName: row?.full_name,
        idNumber: row?.id_number,
        phone: row?.phone,
        email: row?.email,
        city: row?.city,
        agentName: row?.agent_name,
        agentId: row?.agent_id || row?.agentId || row?.payload?.agentId,
        agentRole: row?.agent_role,
        insuredCount: row?.insured_count,
        existingPoliciesCount: row?.existing_policies_count,
        newPoliciesCount: row?.new_policies_count,
        createdAt: row?.created_at,
        updatedAt: row?.updated_at,
        payload: row?.payload || {}
      }, idx);
    },

    mapProposalRow(row, idx){
      return normalizeProposalRecord({
        id: row?.id,
        status: row?.status,
        fullName: row?.full_name,
        idNumber: row?.id_number,
        phone: row?.phone,
        email: row?.email,
        city: row?.city,
        agentName: row?.agent_name,
        agentId: row?.agent_id || row?.agentId || row?.payload?.agentId,
        agentRole: row?.agent_role,
        currentStep: row?.current_step,
        insuredCount: row?.insured_count,
        createdAt: row?.created_at,
        updatedAt: row?.updated_at,
        payload: row?.payload || {}
      }, idx);
    },

    _needsMergedAgentScope(tableName){
      const table = safeTrim(tableName);
      if(table !== SUPABASE_TABLES.customers && table !== SUPABASE_TABLES.proposals) return false;
      const scope = getServerListAgentScopeFilter();
      return !!(scope && (scope.ids.length || scope.names.length));
    },

    _mergeRowsById(rows){
      const rowById = new Map();
      (rows || []).forEach((row) => {
        const id = safeTrim(row?.id);
        if(id) rowById.set(id, row);
      });
      return Array.from(rowById.values());
    },

    async _fetchTableRowsInColumn(tableName, selectExpr, column, values, sinceIso = ""){
      const list = (Array.isArray(values) ? values : []).map((v) => safeTrim(v)).filter(Boolean);
      if(!list.length) return { ok:true, data:[] };
      const since = safeTrim(sinceIso);
      try {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => {
            let builder = client.from(tableName).select(selectExpr).in(column, list);
            if(since) builder = builder.gte("updated_at", since);
            return builder;
          },
          "טעינת טבלה " + tableName
        );
        if(error) throw error;
        return { ok:true, data: data || [] };
      } catch(primaryErr) {
        try {
          const vals = list
            .map((v) => encodeURIComponent('"' + String(v).replace(/\\/g, "\\\\").replace(/"/g, '\\"') + '"'))
            .join(",");
          let path = tableName + "?select=" + encodeURIComponent(selectExpr) + "&" + column + "=in.(" + vals + ")";
          if(since) path += "&updated_at=gte." + encodeURIComponent(since);
          const data = await this.restRequest(path, { method: "GET" });
          return { ok:true, data: data || [] };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    async _loadTableRowsMergedAgentScope(tableName, selectExpr = "*", options = {}){
      const scope = getServerListAgentScopeFilter();
      if(!scope) return this._loadTableRowsUnscoped(tableName, selectExpr, options);
      const since = safeTrim(options.sinceIso);
      const parts = [];
      if(scope.ids.length) parts.push(this._fetchTableRowsInColumn(tableName, selectExpr, "agent_id", scope.ids, since));
      if(scope.names.length) parts.push(this._fetchTableRowsInColumn(tableName, selectExpr, "agent_name", scope.names, since));
      if(!parts.length) return { ok:true, data:[] };
      const results = await Promise.all(parts);
      const errors = results.map((r) => safeTrim(r?.error)).filter(Boolean);
      const anyOk = results.some((r) => r?.ok);
      if(!anyOk) return { ok:false, error: errors.join(" | ") || "טעינת נתוני נציג נכשלה" };
      const merged = this._mergeRowsById(results.flatMap((r) => (r?.ok ? (r.data || []) : [])));
      if(errors.length){
        try { console.warn("AGENT_SCOPE_PARTIAL_LOAD:", tableName, errors.join(" | ")); } catch(_e) {}
      }
      return { ok:true, data: merged, warning: errors.join(" | ") };
    },

    async _loadTableRowsUnscoped(tableName, selectExpr = "*", options = {}){
      const since = safeTrim(options.sinceIso);
      try {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => {
            let builder = client.from(tableName).select(selectExpr);
            if(since) builder = builder.gte("updated_at", since);
            return builder;
          },
          "טעינת טבלה " + tableName
        );
        if(error) throw error;
        return { ok:true, data: data || [] };
      } catch(primaryErr) {
        try {
          let path = tableName + "?select=" + encodeURIComponent(selectExpr);
          if(since) path += "&updated_at=gte." + encodeURIComponent(since);
          const data = await this.restRequest(path, { method: "GET" });
          return { ok:true, data: data || [] };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    _applyListAgentScopeToQuery(builder, tableName){
      const table = safeTrim(tableName);
      if(table !== SUPABASE_TABLES.customers && table !== SUPABASE_TABLES.proposals) return builder;
      const scope = getServerListAgentScopeFilter();
      if(!scope) return builder;
      const orParts = [];
      if(scope.ids.length) orParts.push(`agent_id.in.(${buildAgentScopeInValues(scope.ids)})`);
      if(scope.names.length) orParts.push(`agent_name.in.(${buildAgentScopeInValues(scope.names)})`);
      if(!orParts.length) return builder;
      // Match if EITHER the row's agent_id or its agent_name belongs to the session scope.
      return builder.or(orParts.join(","));
    },

    _appendListAgentScopeToRestPath(path, tableName){
      const table = safeTrim(tableName);
      if(table !== SUPABASE_TABLES.customers && table !== SUPABASE_TABLES.proposals) return path;
      const scope = getServerListAgentScopeFilter();
      if(!scope) return path;
      const encodeVals = (values) => values
        .map((v) => encodeURIComponent('"' + String(v).replace(/\\/g, "\\\\").replace(/"/g, '\\"') + '"'))
        .join(",");
      const orParts = [];
      if(scope.ids.length) orParts.push(`agent_id.in.(${encodeVals(scope.ids)})`);
      if(scope.names.length) orParts.push(`agent_name.in.(${encodeVals(scope.names)})`);
      if(!orParts.length) return path;
      const joiner = String(path || "").includes("?") ? "&" : "?";
      // Match if EITHER agent_id or agent_name belongs to the session scope.
      return `${path}${joiner}or=(${orParts.join(",")})`;
    },

    async loadTableRows(tableName, selectExpr = "*"){
      if(this._needsMergedAgentScope(tableName)){
        return this._loadTableRowsMergedAgentScope(tableName, selectExpr);
      }
      return this._loadTableRowsUnscoped(tableName, selectExpr);
    },

    // מצטיין יומי כלל-ארגוני — שליפה קריא-בלבד של רשומות לקוחות שעודכנו מאז sinceIso,
    // ללא סינון-הנציג, אך ורק לצורך חישוב הפודיום. הנתונים לעולם לא נכנסים ל-State.data.
    // בוחרים מינימום עמודות (ללא שם/טלפון/ת"ז/אימייל) כדי לצמצם חשיפת מידע על הקו.
    async loadLeaderboardCustomerRows(sinceIso){
      const since = safeTrim(sinceIso);
      const selectExpr = "id,agent_name,agent_id,agent_role,created_at,updated_at,payload";
      const res = await this._loadTableRowsUnscoped(SUPABASE_TABLES.customers, selectExpr, { sinceIso: since });
      if(!res?.ok) return { ok:false, error: res?.error || "טעינת נתוני מצטיינים נכשלה" };
      const rows = Array.isArray(res.data) ? res.data : [];
      const mapped = rows.map((row, idx) => this.mapCustomerRow(row, idx));
      return { ok:true, rows: mapped };
    },

    async loadCampaignLeadRows(scope = "all", selectExpr = "*"){
      const useMineScope = scope === "mine";
      const pageSize = 1000;
      const maxRows = 25000;
      const agentIds = useMineScope ? [...getCampaignLeadSessionAgentIds()].filter(Boolean) : [];
      if(useMineScope && !agentIds.length) return { ok: true, data: [] };

      const fetchPage = async (from, extraFilter) => {
        const to = from + pageSize - 1;
        try {
          const client = this.getClient();
          let builder = client.from(SUPABASE_TABLES.campaignLeads)
            .select(selectExpr)
            .order("created_at", { ascending: false })
            .range(from, to);
          if(useMineScope && !extraFilter) builder = builder.in("assigned_agent_id", agentIds);
          if(extraFilter?.ilikeAgentId) builder = builder.ilike("description", `%"id":"${extraFilter.ilikeAgentId}"%`);
          const { data, error } = await this.withRetry(
            () => builder,
            'טעינת לידי קמפיין'
          );
          if(error) throw error;
          return data || [];
        } catch(primaryErr) {
          let path = SUPABASE_TABLES.campaignLeads
            + "?select=" + encodeURIComponent(selectExpr)
            + "&order=created_at.desc"
            + "&offset=" + from
            + "&limit=" + pageSize;
          if(useMineScope && !extraFilter){
            path += "&assigned_agent_id=in.(" + agentIds.map((id) => encodeURIComponent(id)).join(",") + ")";
          }
          if(extraFilter?.ilikeAgentId){
            path += "&description=ilike." + encodeURIComponent(`%"id":"${extraFilter.ilikeAgentId}"%`);
          }
          const data = await this.restRequest(path, { method: "GET" });
          return data || [];
        }
      };

      try {
        let allRows = [];
        const rowById = new Map();
        const ingest = (rows) => {
          (rows || []).forEach((row) => {
            const id = safeTrim(row?.id);
            if(id) rowById.set(id, row);
          });
        };
        for(let from = 0; from < maxRows; from += pageSize){
          const page = await fetchPage(from);
          ingest(page);
          if(page.length < pageSize) break;
        }
        if(useMineScope){
          for(const agentId of agentIds){
            for(let from = 0; from < maxRows; from += pageSize){
              const page = await fetchPage(from, { ilikeAgentId: agentId });
              ingest(page);
              if(page.length < pageSize) break;
            }
          }
        }
        allRows = Array.from(rowById.values());
        return { ok: true, data: allRows };
      } catch(err) {
        return { ok: false, error: String(err?.message || err) };
      }
    },

    async loadTableRowsSince(tableName, sinceIso, selectExpr = "*"){
      const since = safeTrim(sinceIso);
      if(!since) return this.loadTableRows(tableName, selectExpr);
      if(this._needsMergedAgentScope(tableName)){
        return this._loadTableRowsMergedAgentScope(tableName, selectExpr, { sinceIso: since });
      }
      return this._loadTableRowsUnscoped(tableName, selectExpr, { sinceIso: since });
    },

    mergeCustomersDelta(rawRows){
      if(!Array.isArray(rawRows) || !rawRows.length) return 0;
      State.data.customers = Array.isArray(State.data.customers) ? State.data.customers : [];
      const map = new Map(State.data.customers.map((c) => [String(c?.id), c]));
      const archivedAdds = [];
      const changedIds = [];
      let merged = 0;
      rawRows.forEach((row, idx) => {
        const rec = this.mapCustomerRow(row, idx);
        if(!rec?.id) return;
        const id = String(rec.id);
        changedIds.push(id);
        if(isServerArchivedCustomerRecord(rec)){
          map.delete(id);
          archivedAdds.push(normalizeArchivedCustomerEntry({
            customer: rec,
            archivedAt: safeTrim(row?.updated_at || row?.created_at || rec.updatedAt) || nowISO(),
            archivedBy: safeTrim(row?.updated_by) || "מערכת"
          }, idx));
        } else {
          map.set(id, rec);
        }
        merged += 1;
      });
      State.data.customers = Array.from(map.values());
      this._lastDeltaCustomerIds = changedIds;
      if(archivedAdds.length){
        State.data.meta = State.data.meta || {};
        State.data.meta.archivedCustomers = mergeArchivedCustomerLists(
          Array.isArray(State.data.meta.archivedCustomers) ? State.data.meta.archivedCustomers : [],
          archivedAdds
        );
      }
      return merged;
    },

    mergeProposalsDelta(rawRows){
      if(!Array.isArray(rawRows) || !rawRows.length) return 0;
      State.data.proposals = Array.isArray(State.data.proposals) ? State.data.proposals : [];
      const map = new Map(State.data.proposals.map((p) => [String(p?.id), p]));
      const changedIds = [];
      let merged = 0;
      rawRows.forEach((row, idx) => {
        const rec = this.mapProposalRow(row, idx);
        if(!rec?.id) return;
        changedIds.push(String(rec.id));
        map.set(String(rec.id), rec);
        merged += 1;
      });
      State.data.proposals = Array.from(map.values());
      this._lastDeltaProposalIds = changedIds;
      return merged;
    },

    consumeDeltaInvalidationIds(){
      const customerIds = Array.isArray(this._lastDeltaCustomerIds) ? this._lastDeltaCustomerIds.slice() : [];
      const proposalIds = Array.isArray(this._lastDeltaProposalIds) ? this._lastDeltaProposalIds.slice() : [];
      this._lastDeltaCustomerIds = null;
      this._lastDeltaProposalIds = null;
      return { customerIds, proposalIds };
    },

    pickNewerRecordForConflictMerge(localRec, serverRec, keepLocal){
      if(keepLocal) return localRec;
      if(!localRec) return serverRec;
      if(!serverRec) return localRec;
      const localAt = Date.parse(safeTrim(localRec?.updatedAt || localRec?.updated_at) || "") || 0;
      const serverAt = Date.parse(safeTrim(serverRec?.updatedAt || serverRec?.updated_at) || "") || 0;
      return serverAt >= localAt ? serverRec : localRec;
    },

    async mergeConflictRemoteTablesIntoState(localState){
      const state = normalizeState(localState || defaultState());
      const customerRows = this.buildCustomerRows(state);
      const proposalRows = this.buildProposalRows(state);
      const dirtyCustomerIds = new Set(
        this.getChangedRows(SUPABASE_TABLES.customers, customerRows).map((row) => String(row?.id)).filter(Boolean)
      );
      const dirtyProposalIds = new Set(
        this.getChangedRows(SUPABASE_TABLES.proposals, proposalRows).map((row) => String(row?.id)).filter(Boolean)
      );
      const [customersRes, proposalsRes] = await Promise.all([
        this.loadTableRows(SUPABASE_TABLES.customers),
        this.loadTableRows(SUPABASE_TABLES.proposals)
      ]);
      let merged = 0;
      if(customersRes?.ok){
        const map = new Map((state.customers || []).map((c) => [String(c?.id), c]));
        (customersRes.data || []).forEach((row, idx) => {
          const serverRec = this.mapCustomerRow(row, idx);
          const id = String(serverRec?.id || "");
          if(!id) return;
          if(isServerArchivedCustomerRecord(serverRec)){
            if(map.has(id) && !dirtyCustomerIds.has(id)) map.delete(id);
            merged += 1;
            return;
          }
          const localRec = map.get(id);
          if(!localRec){
            map.set(id, serverRec);
            merged += 1;
            return;
          }
          const next = this.pickNewerRecordForConflictMerge(localRec, serverRec, dirtyCustomerIds.has(id));
          if(next !== localRec) merged += 1;
          map.set(id, next);
        });
        state.customers = Array.from(map.values());
      }
      if(proposalsRes?.ok){
        const map = new Map((state.proposals || []).map((p) => [String(p?.id), p]));
        (proposalsRes.data || []).forEach((row, idx) => {
          const serverRec = this.mapProposalRow(row, idx);
          const id = String(serverRec?.id || "");
          if(!id) return;
          const localRec = map.get(id);
          if(!localRec){
            map.set(id, serverRec);
            merged += 1;
            return;
          }
          const next = this.pickNewerRecordForConflictMerge(localRec, serverRec, dirtyProposalIds.has(id));
          if(next !== localRec) merged += 1;
          map.set(id, next);
        });
        state.proposals = Array.from(map.values());
      }
      return {
        state: Auth?.current && !Auth.canViewAllCustomers() ? filterSessionStateForCurrentUserScope(state) : state,
        merged,
        warning: (!customersRes?.ok && !proposalsRes?.ok) ? "לא ניתן היה למזג נתונים מהשרת לפני השמירה" : ""
      };
    },

    async loadSheetsDelta(options = {}){
      if(!isWave3IncrementalEnabled()) return this.loadSheets(options);
      const localAt = safeTrim(options.sinceIso || getMetaSyncAt(State.data?.meta, "data") || State.data?.meta?.updatedAt);
      if(!localAt) return this.loadSheets(options);
      const useCachedFallback = options.useCachedFallback === true;
      try {
        const connection = await this.waitForConnection();
        if(!connection.ok){
          if(useCachedFallback){
            const backupState = this.loadBackup();
            if(backupState){
              return { ok:true, payload:backupState, at: safeTrim(backupState?.meta?.updatedAt) || nowISO(), source:"backup-cache", stale:true, warning: connection.error || "" };
            }
          }
          return { ok:false, error: connection.error || "" };
        }
        const sinceDate = new Date(localAt);
        const querySince = !isNaN(sinceDate.getTime())
          ? new Date(sinceDate.getTime() - GI_WAVE3_INCR_OVERLAP_MS).toISOString()
          : localAt;

        const [metaRes, agentsRes, customersRes, proposalsRes] = await Promise.all([
          this.loadMetaRow(),
          this.loadTableRows(SUPABASE_TABLES.agents),
          this.loadTableRowsSince(SUPABASE_TABLES.customers, querySince),
          this.loadTableRowsSince(SUPABASE_TABLES.proposals, querySince)
        ]);

        if(!metaRes.ok){
          console.warn("WAVE3_DELTA_FALLBACK: meta failed");
          return this.loadSheets(options);
        }

        const mappedMeta = this.mapMeta(metaRes.data || {});
        const prevMeta = State.data.meta && typeof State.data.meta === "object" ? State.data.meta : {};
        mappedMeta.teamManagerAssignments = mergeTeamManagerAssignmentsMaps(
          prevMeta.teamManagerAssignments,
          mappedMeta.teamManagerAssignments,
          {
            localAt: safeTrim(prevMeta.teamManagerAssignmentsUpdatedAt),
            remoteAt: safeTrim(mappedMeta.teamManagerAssignmentsUpdatedAt)
          }
        );
        mappedMeta.teamManagerAssignmentsUpdatedAt = (() => {
          const localTmaAt = safeTrim(prevMeta.teamManagerAssignmentsUpdatedAt);
          const remoteTmaAt = safeTrim(mappedMeta.teamManagerAssignmentsUpdatedAt);
          if(localTmaAt && remoteTmaAt){
            return compareIsoStamps(localTmaAt, remoteTmaAt) >= 0 ? localTmaAt : remoteTmaAt;
          }
          return localTmaAt || remoteTmaAt || safeTrim(mappedMeta.updatedAt) || nowISO();
        })();
        const mergedReferralTombstones = normalizeDeletedElementaryReferralIds([
          ...(prevMeta.deletedElementaryReferralIds || []),
          ...(mappedMeta.deletedElementaryReferralIds || [])
        ]);
        mappedMeta.deletedElementaryReferralIds = mergedReferralTombstones;
        mappedMeta.elementaryReferrals = mergeElementaryReferralsListsByRecency(
          Array.isArray(prevMeta.elementaryReferrals) ? prevMeta.elementaryReferrals : [],
          Array.isArray(mappedMeta.elementaryReferrals) ? mappedMeta.elementaryReferrals : [],
          { tombstones: new Set(mergedReferralTombstones), pinnedIds: getPinnedElementaryReferralIdSet() }
        );
        mappedMeta.agentReportAliases = mergeAgentReportAliasesMapsByRecency(
          prevMeta.agentReportAliases,
          mappedMeta.agentReportAliases,
          {
            localAt: safeTrim(prevMeta.agentReportAliasesUpdatedAt),
            remoteAt: safeTrim(mappedMeta.agentReportAliasesUpdatedAt)
          }
        );
        mappedMeta.agentReportAliasesUpdatedAt = (() => {
          const localAt = safeTrim(prevMeta.agentReportAliasesUpdatedAt);
          const remoteAt = safeTrim(mappedMeta.agentReportAliasesUpdatedAt);
          if(localAt && remoteAt){
            return compareIsoStamps(localAt, remoteAt) >= 0 ? localAt : remoteAt;
          }
          return localAt || remoteAt || safeTrim(mappedMeta.updatedAt) || nowISO();
        })();
        State.data.meta = { ...(prevMeta || defaultState().meta), ...mappedMeta };
        try { invalidateDailyReportMatchCaches(); } catch(_e) {}

        if(agentsRes.ok){
          const agentsRows = (agentsRes.data || []).map((row, idx) => this.mapAgentRow(row, idx));
          State.data.agents = mergeAgentsTableWithMetaShadow(agentsRows, State.data.meta);
        }
        hydrateTeamManagerLinksFromMeta(State.data);
        if(customersRes.ok) this.mergeCustomersDelta(customersRes.data || []);
        else console.warn("WAVE3_DELTA: customers delta skipped", customersRes.error);
        if(proposalsRes.ok) this.mergeProposalsDelta(proposalsRes.data || []);
        else console.warn("WAVE3_DELTA: proposals delta skipped", proposalsRes.error);

        refreshStateShadows({ skipNormalize: true });
        try {
          this._lastMetaUpdatedAt = safeTrim(mappedMeta.updatedAt) || nowISO();
          this.saveBackup(State.data);
        } catch(_e) {}

        return {
          ok:true,
          payload: State.data,
          at: safeTrim(mappedMeta.updatedAt) || nowISO(),
          source:"delta",
          stale:false,
          warning:""
        };
      } catch(err) {
        console.warn("WAVE3_DELTA_ERR:", err);
        return this.loadSheets(options);
      }
    },

    async loadMetaRow(){
      try {
        const client = this.getClient();
        const { data, error } = await this.withRetry(
          () => client.from(SUPABASE_TABLES.meta).select("key,payload,updated_at").eq("key", "global").maybeSingle(),
          'טעינת הגדרות מערכת'
        );
        if(error) throw error;
        return { ok:true, data: data || {} };
      } catch(primaryErr) {
        try {
          const data = await this.restRequest(
            SUPABASE_TABLES.meta + "?key=eq.global&select=key,payload,updated_at&_ts=" + encodeURIComponent(String(Date.now())),
            { method: "GET", cache: "no-store" }
          );
          return { ok:true, data: Array.isArray(data) ? (data[0] || {}) : (data || {}) };
        } catch(restErr) {
          return { ok:false, error: String(restErr?.message || primaryErr?.message || restErr || primaryErr) };
        }
      }
    },

    async loadLoginBootstrap(options = {}){
      const useCachedFallback = options.useCachedFallback === true;
      const buildPayload = (metaRes, agentsRes) => {
        const mappedMeta = this.mapMeta(metaRes?.data || {});
        const agentsRows = (agentsRes?.data || []).map((row, idx) => this.mapAgentRow(row, idx));
        const agentsMerged = mergeAgentsTableWithMetaShadow(agentsRows, mappedMeta);
        return {
          meta: mappedMeta,
          agents: agentsMerged
        };
      };
      const backupBootstrap = () => {
        const backupState = this.loadBackup();
        if(!backupState) return null;
        return {
          ok:true,
          payload: {
            meta: backupState.meta,
            agents: Array.isArray(backupState.agents) ? backupState.agents : []
          },
          at: safeTrim(backupState?.meta?.updatedAt) || nowISO(),
          source:'backup-cache',
          stale:true,
          warning:''
        };
      };
      try {
        const connection = await this.waitForConnection({ retries: 2, delayMs: 800 });
        if(!connection.ok){
          if(useCachedFallback){
            const backup = backupBootstrap();
            if(backup){
              backup.warning = connection.error || 'השרת לא זמין כרגע';
              return backup;
            }
          }
          return { ok:false, error: connection.error || 'בעיה זמנית בחיבור לשרת' };
        }

        const [metaRes, agentsRes] = await Promise.all([
          this.loadMetaRow(),
          this.loadTableRows(SUPABASE_TABLES.agents)
        ]);

        const failures = [
          !metaRes.ok ? ('meta: ' + safeTrim(metaRes.error)) : '',
          !agentsRes.ok ? ('agents: ' + safeTrim(agentsRes.error)) : ''
        ].filter(Boolean);

        if(failures.length){
          if(useCachedFallback){
            const backup = backupBootstrap();
            if(backup){
              backup.warning = failures.join(' | ');
              return backup;
            }
          }
          return { ok:false, error: failures.join(' | ') || 'טעינת נתוני כניסה מהשרת נכשלה' };
        }

        const payload = buildPayload(metaRes, agentsRes);
        return {
          ok:true,
          payload,
          at: safeTrim(payload?.meta?.updatedAt) || nowISO(),
          source:'server',
          stale:false,
          warning:''
        };
      } catch(e) {
        if(useCachedFallback){
          const backup = backupBootstrap();
          if(backup){
            backup.warning = String(e?.message || e);
            return backup;
          }
        }
        return { ok:false, error: String(e?.message || e) };
      }
    },

    async loadSheets(options = {}){
      GiPerf.mark("loadSheets");
      const prevSkipScope = this._skipServerAgentScope;
      this._skipServerAgentScope = options.skipServerAgentScope === true;
      try {
      const useCachedFallback = options.useCachedFallback === true;
      const allowFreshCache = options.allowFreshCache === true;
      const cacheMaxAgeMs = this.getServerCacheMaxAge(options);
      if(allowFreshCache){
        const cached = this.loadServerCache(cacheMaxAgeMs);
        if(cached){
          return { ok:true, payload:cached, at: safeTrim(cached?.meta?.updatedAt) || nowISO(), source:'fresh-cache', stale:false, cached:true, warning:'' };
        }
      }
      try {
        const connection = await this.waitForConnection();
        if(!connection.ok){
          if(useCachedFallback){
            const backupState = this.loadBackup();
            if(backupState){
              return { ok:true, payload:backupState, at: safeTrim(backupState?.meta?.updatedAt) || nowISO(), source:'backup-cache', stale:true, warning: connection.error || 'השרת לא זמין כרגע' };
            }
          }
          return { ok:false, error: connection.error || 'בעיה זמנית בחיבור לשרת' };
        }

        const [metaRes, agentsRes, customersRes, proposalsRes] = await Promise.all([
          this.loadMetaRow(),
          this.loadTableRows(SUPABASE_TABLES.agents),
          this.loadTableRows(SUPABASE_TABLES.customers),
          this.loadTableRows(SUPABASE_TABLES.proposals)
        ]);

        const failures = [
          !metaRes.ok ? ('meta: ' + safeTrim(metaRes.error)) : '',
          !agentsRes.ok ? ('agents: ' + safeTrim(agentsRes.error)) : '',
          !customersRes.ok ? ('customers: ' + safeTrim(customersRes.error)) : '',
          !proposalsRes.ok ? ('proposals: ' + safeTrim(proposalsRes.error)) : ''
        ].filter(Boolean);

        if(failures.length){
          if(useCachedFallback){
            const backupState = this.loadBackup();
            if(backupState){
              return { ok:true, payload:backupState, at: safeTrim(backupState?.meta?.updatedAt) || nowISO(), source:'backup-cache', stale:true, warning: failures.join(' | ') };
            }
          }
          return { ok:false, error: failures.join(' | ') || 'טעינת נתונים מהשרת נכשלה' };
        }

        const mappedMeta = this.mapMeta(metaRes.data || {});
        const agentsRows = (agentsRes.data || []).map((row, idx) => this.mapAgentRow(row, idx));
        const customerRows = await perfMapChunked(customersRes.data || [], (row, idx) => this.mapCustomerRow(row, idx));
        const archivedFromCustomers = [];
        const customerRaw = customersRes.data || [];
        for(let idx = 0; idx < customerRaw.length; idx += 1){
          const row = customerRaw[idx];
          if(!isServerArchivedCustomerRecord({ status: row?.status })) continue;
          const customer = this.mapCustomerRow(row, idx);
          archivedFromCustomers.push(normalizeArchivedCustomerEntry({
            customer,
            archivedAt: safeTrim(row?.updated_at || row?.created_at) || nowISO(),
            archivedBy: safeTrim(row?.updated_by) || "מערכת"
          }, idx));
          if(idx > 0 && (idx % LOAD_SHEETS_MAP_CHUNK_SIZE) === 0) await perfYield();
        }
        mappedMeta.archivedCustomers = mergeArchivedCustomerLists(
          Array.isArray(mappedMeta.archivedCustomers) ? mappedMeta.archivedCustomers : [],
          archivedFromCustomers
        );
        const proposalRows = await perfMapChunked(proposalsRes.data || [], (row, idx) => this.mapProposalRow(row, idx));
        const agentsMerged = mergeAgentsTableWithMetaShadow(agentsRows, mappedMeta);
        const payload = normalizeState({
          meta: mappedMeta,
          agents: agentsMerged,
          customers: customerRows,
          proposals: proposalRows
        });
        try {
          this.rememberRows(SUPABASE_TABLES.agents, this.buildAgentRows(payload));
          this.rememberRows(SUPABASE_TABLES.customers, this.buildCustomerRows(payload));
          this.rememberRows(SUPABASE_TABLES.proposals, this.buildProposalRows(payload));
          this._lastMetaUpdatedAt = safeTrim(payload?.meta?.updatedAt) || safeTrim(mappedMeta?.updatedAt) || nowISO();
        } catch(_e) {}
        try { this.clearLegacyCaches({ keepBackup:true }); } catch(_e) {}
        try { this.saveBackup(payload); } catch(_e) {}
        return { ok:true, payload, at: payload?.meta?.updatedAt || nowISO(), source:'server', stale:false, warning:'' };
      } catch(e) {
        if(useCachedFallback){
          const backupState = this.loadBackup();
          if(backupState){
            return { ok:true, payload:backupState, at: safeTrim(backupState?.meta?.updatedAt) || nowISO(), source:'backup-cache', stale:true, warning: String(e?.message || e) };
          }
        }
        return { ok:false, error: String(e?.message || e) };
      }
      } finally {
        this._skipServerAgentScope = prevSkipScope;
        GiPerf.mark("loadSheets:end");
        GiPerf.measure("loadSheets", "loadSheets");
      }
    },

    async saveSheets(state, options = {}){
      try {
        const connection = await this.waitForConnection();
        if(!connection.ok) return { ok:false, error: connection.error || 'בעיה זמנית בחיבור לשרת' };

        // skipNormalize: נתיבים קלים (למשל התחלת שיחת שיקוף) — בלי normalize מלא שחוסם UI
        const localState = options.skipNormalize === true
          ? (state && typeof state === "object" ? state : defaultState())
          : normalizeState(state || defaultState());

        if(options.metaOnly === true){
          const mergedState = localState;
          const scopes = options.metaSyncScopes || (options.metaSyncScope ? [options.metaSyncScope] : ["settings"]);
          try {
            const latestMeta = await this.loadMetaRow();
            if(latestMeta?.ok && latestMeta.data){
              mergeMetaElementaryReferralsIntoState(mergedState, this.mapMeta(latestMeta.data || {}));
            }
          } catch(_mergeErr){
            console.warn("META_ONLY_REFERRALS_MERGE_WARN", _mergeErr);
          }
          bumpMetaSyncClock(mergedState.meta, scopes);
          mergedState.meta.revision = normalizeRevisionMeta({
            ...(mergedState.meta.revision || {}),
            stateVersion: Math.max(
              Number(mergedState.meta.revision?.stateVersion || 0) || 0,
              Number(App?._lastServerRevision?.stateVersion || 0) || 0
            ) + 1,
            updatedAt: mergedState.meta.updatedAt,
            updatedBy: safeTrim(Auth?.current?.name || mergedState.meta?.revision?.updatedBy),
            sessionId: APP_SESSION_ID
          }, mergedState.meta.updatedAt);
          const metaOnlyRes = await this.upsertMeta(mergedState);
          if(!metaOnlyRes?.ok){
            return { ok:false, error: safeTrim(metaOnlyRes?.error) || 'META_SAVE_FAILED', mode:"meta-only" };
          }
          State.data = mergedState;
          try { this.saveBackup(mergedState); } catch(_e) {}
          return {
            ok:true,
            at: mergedState.meta.updatedAt || nowISO(),
            mode:"meta-only",
            conflictDetected:false,
            mergedState,
            agentsSyncOk:true,
            agentsSyncWarning:"",
            customersSyncWarning:"",
            proposalsSyncWarning:"",
            syncWarnings:[]
          };
        }

        let serverState = null;
        let conflictInfo = { detected:false, serverAt:"", localAt:safeTrim(localState?.meta?.updatedAt) || nowISO() };

        if(options.skipServerMerge !== true){
          // Egress Guard v2: check only the light meta row instead of re-downloading all tables before every save.
          const latestMeta = await this.loadMetaRow();
          if(latestMeta?.ok && latestMeta.data){
            const mappedMeta = this.mapMeta(latestMeta.data || {});
            conflictInfo.serverAt = safeTrim(mappedMeta?.updatedAt) || "";
            const serverRevision = normalizeRevisionMeta(mappedMeta?.revision, conflictInfo.serverAt);
            const localRevision = normalizeRevisionMeta(localState?.meta?.revision, conflictInfo.localAt);
            conflictInfo.detected = (
              compareIsoStamps(conflictInfo.serverAt, conflictInfo.localAt) > 0 &&
              serverRevision.sessionId !== APP_SESSION_ID &&
              serverRevision.stateVersion > localRevision.stateVersion
            );
            serverState = { ...defaultState(), meta: mappedMeta, agents:[], customers:[], proposals:[] };
          }
        }

        if(serverState?.meta){
          const localRefs = Array.isArray(localState.meta?.elementaryReferrals) ? localState.meta.elementaryReferrals : [];
          const serverRefs = Array.isArray(serverState.meta.elementaryReferrals) ? serverState.meta.elementaryReferrals : [];
          const mergedTombstones = normalizeDeletedElementaryReferralIds([
            ...(localState.meta?.deletedElementaryReferralIds || []),
            ...(serverState.meta.deletedElementaryReferralIds || [])
          ]);
          localState.meta.deletedElementaryReferralIds = mergedTombstones;
          localState.meta.elementaryReferrals = mergeElementaryReferralsListsByRecency(localRefs, serverRefs, {
            tombstones: new Set(mergedTombstones),
            pinnedIds: getPinnedElementaryReferralIdSet()
          });
          // BUG-FIX: merge team links from server before upsert so a stale local meta payload
          // cannot wipe assignments saved by another session or an earlier save.
          const mergedTeamLinks = mergeTeamManagerAssignmentsMaps(
            localState.meta?.teamManagerAssignments,
            serverState.meta.teamManagerAssignments,
            {
              localAt: safeTrim(localState.meta?.teamManagerAssignmentsUpdatedAt),
              remoteAt: safeTrim(serverState.meta.teamManagerAssignmentsUpdatedAt)
            }
          );
          localState.meta.teamManagerAssignments = mergedTeamLinks;
          localState.meta.teamManagerAssignmentsUpdatedAt = (() => {
            const localTmaAt = safeTrim(localState.meta?.teamManagerAssignmentsUpdatedAt);
            const serverTmaAt = safeTrim(serverState.meta.teamManagerAssignmentsUpdatedAt);
            if(localTmaAt && serverTmaAt){
              return compareIsoStamps(localTmaAt, serverTmaAt) >= 0 ? localTmaAt : serverTmaAt;
            }
            return localTmaAt || serverTmaAt || safeTrim(localState.meta?.teamManagerAssignmentsUpdatedAt) || null;
          })();
          if(Array.isArray(localState.agents) && localState.agents.length){
            reconcileTeamManagerAssignmentsFromAgents(localState);
            applyTeamManagerAssignmentsToAgents(localState);
          }
          const mergedReportAliases = mergeAgentReportAliasesMapsByRecency(
            localState.meta?.agentReportAliases,
            serverState.meta.agentReportAliases,
            {
              localAt: safeTrim(localState.meta?.agentReportAliasesUpdatedAt),
              remoteAt: safeTrim(serverState.meta.agentReportAliasesUpdatedAt)
            }
          );
          localState.meta.agentReportAliases = mergedReportAliases;
          localState.meta.agentReportAliasesUpdatedAt = (() => {
            const localAt = safeTrim(localState.meta?.agentReportAliasesUpdatedAt);
            const serverAt = safeTrim(serverState.meta.agentReportAliasesUpdatedAt);
            if(localAt && serverAt){
              return compareIsoStamps(localAt, serverAt) >= 0 ? localAt : serverAt;
            }
            return localAt || serverAt || safeTrim(localState.meta?.agentReportAliasesUpdatedAt) || null;
          })();
        }

        let conflictMergeWarning = "";
        if(conflictInfo.detected){
          try {
            const mergeRes = await this.mergeConflictRemoteTablesIntoState(localState);
            if(mergeRes?.state) localState = mergeRes.state;
            if(mergeRes?.merged > 0){
              conflictMergeWarning = `מוזגו ${mergeRes.merged} רשומות מהשרת לפני השמירה`;
            } else if(mergeRes?.warning){
              conflictMergeWarning = mergeRes.warning;
            }
          } catch(mergeErr){
            conflictMergeWarning = safeTrim(mergeErr?.message) || "מיזוג נתונים מהשרת נכשל";
            console.warn("CONFLICT_MERGE_FAILED:", mergeErr);
          }
        }

        const mergedState = localState;
        bumpMetaSyncClock(mergedState.meta, ["data"]);
        mergedState.meta.revision = normalizeRevisionMeta({
          ...(mergedState.meta.revision || {}),
          stateVersion: Math.max(
            Number(serverState?.meta?.revision?.stateVersion || 0) || 0,
            Number(localState?.meta?.revision?.stateVersion || 0) || 0
          ) + 1,
          updatedAt: mergedState.meta.updatedAt,
          updatedBy: safeTrim(Auth?.current?.name || mergedState.meta?.revision?.updatedBy),
          sessionId: APP_SESSION_ID
        }, mergedState.meta.updatedAt);

        const metaSaveRes = await this.upsertMeta(mergedState);
        if(!metaSaveRes?.ok){
          return {
            ok:false,
            error: safeTrim(metaSaveRes?.error) || 'META_SAVE_FAILED',
            mode:'meta-save-failed',
            agentsSyncOk:false,
            agentsSyncWarning:'',
            customersSyncWarning:'',
            proposalsSyncWarning:'',
            syncWarnings:[safeTrim(metaSaveRes?.error) || 'META_SAVE_FAILED']
          };
        }
        let agentsSyncWarning = '';
        let agentsSyncOk = true;
        let customersSyncWarning = '';
        let proposalsSyncWarning = '';
        const agentSyncOptions = Array.isArray(options.syncAgentIds) && options.syncAgentIds.length
          ? { onlyAgentIds: options.syncAgentIds }
          : (options.forceAgentsSync === true ? { forceAll: true } : {});
        const customerRows = this.buildCustomerRows(mergedState);
        const proposalRows = this.buildProposalRows(mergedState);
        const [agentsSyncResult, customersSyncResult, proposalsSyncResult] = await Promise.all([
          this.syncAgentsFromState(mergedState, agentSyncOptions).catch((err) => ({
            ok: false,
            error: String(err?.message || err || 'AGENTS_SYNC_FAILED')
          })),
          (async () => {
            try {
              await this.syncTable(SUPABASE_TABLES.customers, this.getChangedRows(SUPABASE_TABLES.customers, customerRows), { allowDelete:false });
              this.rememberRows(SUPABASE_TABLES.customers, customerRows);
              return { ok: true };
            } catch(customerSyncErr) {
              return { ok: false, error: String(customerSyncErr?.message || customerSyncErr || 'CUSTOMERS_SYNC_FAILED') };
            }
          })(),
          (async () => {
            try {
              if(options.skipProposalsSync === true){
                this.rememberRows(SUPABASE_TABLES.proposals, proposalRows);
                return { ok: true, skipped: true };
              }
              await this.syncTable(SUPABASE_TABLES.proposals, this.getChangedRows(SUPABASE_TABLES.proposals, proposalRows), { allowDelete:false });
              this.rememberRows(SUPABASE_TABLES.proposals, proposalRows);
              return { ok: true };
            } catch(proposalSyncErr) {
              return { ok: false, error: String(proposalSyncErr?.message || proposalSyncErr || 'PROPOSALS_SYNC_FAILED') };
            }
          })()
        ]);
        if(!agentsSyncResult?.ok){
          agentsSyncOk = false;
          agentsSyncWarning = safeTrim(agentsSyncResult?.error) || 'AGENTS_SYNC_FAILED';
          console.warn('AGENTS_SYNC_WARNING:', agentsSyncWarning);
        } else if(agentsSyncResult?.teamManagerColumnSkipped){
          agentsSyncWarning = 'שיוך נשמר במטא-דאטה; עמודת team_manager_id חסרה בטבלת agents ב-Supabase.';
        }
        if(!customersSyncResult?.ok){
          customersSyncWarning = safeTrim(customersSyncResult?.error) || 'CUSTOMERS_SYNC_FAILED';
          console.warn('CUSTOMERS_SYNC_WARNING:', customersSyncWarning);
        }
        if(!proposalsSyncResult?.ok){
          proposalsSyncWarning = safeTrim(proposalsSyncResult?.error) || 'PROPOSALS_SYNC_FAILED';
          console.warn('PROPOSALS_SYNC_WARNING:', proposalsSyncWarning);
        }

        State.data = mergedState;
        try { this.clearLegacyCaches({ keepBackup:true }); } catch(_e) {}
        try { this.saveBackup(mergedState); } catch(_e) {}
        return {
          ok:true,
          at: mergedState.meta.updatedAt || nowISO(),
          mode:'safe-upsert-only',
          conflictDetected: !!conflictInfo.detected,
          mergedState,
          agentsSyncOk,
          agentsSyncWarning,
          customersSyncWarning,
          proposalsSyncWarning,
          syncWarnings: [agentsSyncWarning, customersSyncWarning, proposalsSyncWarning, conflictMergeWarning].filter(Boolean)
        };
      } catch(e) {
        return { ok:false, error: String(e?.message || e) };
      }
    },

    // PERF: shared meta-row cache — deduplicates concurrent loadMetaRow() calls within the same browser.
    _metaRowCache: null,
    _metaRowCacheTtlMs: 2000,

    async loadMetaRowCached(){
      const now = Date.now();
      if(this._metaRowCache?.promise) return this._metaRowCache.promise;
      if(this._metaRowCache?.at && (now - this._metaRowCache.at) < this._metaRowCacheTtlMs){
        return this._metaRowCache.result;
      }
      const promise = this.loadMetaRow().then((result) => {
        this._metaRowCache = { result, at: Date.now(), promise: null };
        return result;
      }).catch((err) => {
        this._metaRowCache = null;
        throw err;
      });
      this._metaRowCache = { promise, at: null, result: null };
      return promise;
    },

    async sendAdminContact(){
      return { ok:false, error:"SUPABASE_NO_MAIL_ENDPOINT" };
    }
  };

  // ---------- Agent activity log (Supabase direct) ----------
  const AgentActivityLog = {
    _logoutLogged: false,
    _realtimeChannel: null,
    EVENT_LABELS: {
      login: "התחבר",
      logout_manual: "התנתק (לחיצה)",
      logout_idle: "התנתק (אי-פעילות 40 דק׳)",
      logout_browser: "יציאה / סגירת דפדפן",
      lead_assigned: "קיבל ליד",
      lead_open: "פתח ליד",
      lead_status: "שינה סטטוס",
      lead_call_note: "תיעוד שיחה",
      lead_irrelevant: "סימן לא רלוונטי",
      lead_closed: "סגר ליד",
      lead_proposal: "המשיך להקמת הצעה"
    },

    campaignLeadLabel(lead){
      const name = safeTrim(lead?.customerName || lead?.customer_name) || "ליד";
      const phone = safeTrim(lead?.phone);
      return phone ? `${name} · ${phone}` : name;
    },

    resolveAgentCtxForLead(lead, override = {}){
      if(safeTrim(override?.name)){
        return {
          id: safeTrim(override.id),
          name: safeTrim(override.name),
          role: safeTrim(override.role) || "agent"
        };
      }
      const rec = typeof getCurrentAgentRecord === "function" ? getCurrentAgentRecord() : null;
      return {
        id: safeTrim(Auth?.current?.id) || safeTrim(rec?.id) || safeTrim(lead?.assignedAgentId || lead?.assigned_agent_id),
        name: safeTrim(Auth?.current?.name) || safeTrim(rec?.name) || safeTrim(lead?.assignedAgentName || lead?.assigned_agent_name),
        role: safeTrim(Auth?.current?.role) || "agent"
      };
    },

    inferCategory(row){
      const cat = safeTrim(row?.event_category);
      if(cat === "session" || cat === "lead") return cat;
      const type = safeTrim(row?.event_type);
      if(type.startsWith("lead_")) return "lead";
      return "session";
    },

    canView(){
      return !!(Auth?.isAdmin?.() || Auth?.isManager?.() || Auth?.isTeamManager?.());
    },

    getScopeAgentIds(){
      if(Auth?.isAdmin?.() || Auth?.isManager?.()) return null;
      if(Auth?.isTeamManager?.()) return [...new Set(Auth.getManagedAgentIds().map(String))];
      return [];
    },

    agentInScope(row){
      const scopeIds = this.getScopeAgentIds();
      if(scopeIds === null) return true;
      if(!scopeIds.length) return false;
      const id = String(safeTrim(row?.agent_id));
      if(id && scopeIds.includes(id)) return true;
      const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
      const name = safeTrim(row?.agent_name);
      if(!name) return false;
      return agents.some((a) => {
        const aid = String(safeTrim(a?.id));
        if(!scopeIds.includes(aid)) return false;
        return safeTrim(a?.name) === name || safeTrim(a?.username) === name;
      });
    },

    buildRow(eventType, agentCtx, meta = {}){
      const now = nowISO();
      const type = safeTrim(eventType) || "login";
      const category = safeTrim(meta.category) || (type.startsWith("lead_") ? "lead" : "session");
      return {
        id: "actlog_" + Date.now().toString(16) + "_" + Math.random().toString(16).slice(2, 8),
        agent_id: safeTrim(agentCtx?.id) || "",
        agent_name: safeTrim(agentCtx?.name) || "",
        agent_role: safeTrim(agentCtx?.role) || "",
        event_type: type,
        event_category: category,
        entity_id: safeTrim(meta.entityId) || "",
        entity_label: safeTrim(meta.entityLabel) || "",
        detail_text: safeTrim(meta.detailText) || "",
        event_at: now,
        activity_date: getIsraelDateString(new Date()),
        session_id: APP_SESSION_ID,
        created_at: now
      };
    },

    async insertRow(row){
      const payload = row && typeof row === "object" ? row : {};
      const attempts = 5;
      const slimPayload = () => {
        const copy = { ...payload };
        delete copy.event_category;
        delete copy.entity_id;
        delete copy.entity_label;
        delete copy.detail_text;
        return copy;
      };
      for(let i = 0; i < attempts; i += 1){
        try {
          const body = i >= 2 ? slimPayload() : payload;
          await Storage.restRequest(SUPABASE_TABLES.agentActivityLog, {
            method: "POST",
            body,
            headers: { Prefer: "return=minimal" },
            timeoutMs: 10000
          });
          return { ok:true, id: safeTrim(body.id) };
        } catch(err) {
          const msg = String(err?.message || err);
          if(i >= attempts - 1){
            console.warn("[AgentActivityLog] insert failed:", msg, payload);
            return { ok:false, error: msg };
          }
          await new Promise((resolve) => window.setTimeout(resolve, 400 * (i + 1)));
        }
      }
      return { ok:false, error: "INSERT_FAILED" };
    },

    async log(eventType, agentCtx){
      const type = safeTrim(eventType);
      const ctx = agentCtx && typeof agentCtx === "object" ? agentCtx : null;
      if(!type || !ctx || !safeTrim(ctx?.name)) return { ok:false, error:"MISSING_CTX" };
      if(type.startsWith("logout_")){
        if(this._logoutLogged) return { ok:true, skipped:true };
        this._logoutLogged = true;
      } else if(type === "login") {
        this._logoutLogged = false;
      }
      const row = this.buildRow(type, ctx, { category: "session" });
      try {
        const res = await this.insertRow(row);
        return res;
      } catch(err) {
        console.warn("[AgentActivityLog] save error:", err);
        return { ok:false, error: String(err?.message || err) };
      }
    },

    async logLead(eventType, lead, options = {}){
      const type = safeTrim(eventType);
      const src = lead && typeof lead === "object" ? lead : {};
      if(!type.startsWith("lead_")) return { ok:false, error:"INVALID_LEAD_EVENT" };
      const agentCtx = this.resolveAgentCtxForLead(src, options.agent || {});
      if(!safeTrim(agentCtx.name)) return { ok:false, error:"MISSING_AGENT" };
      const row = this.buildRow(type, agentCtx, {
        category: "lead",
        entityId: safeTrim(src.id),
        entityLabel: this.campaignLeadLabel(src),
        detailText: safeTrim(options.detailText)
      });
      try {
        return await this.insertRow(row);
      } catch(err) {
        console.warn("[AgentActivityLog] lead save error:", err);
        return { ok:false, error: String(err?.message || err) };
      }
    },

    logLeadBeacon(eventType, lead, options = {}){
      const type = safeTrim(eventType);
      const src = lead && typeof lead === "object" ? lead : {};
      if(!type.startsWith("lead_")) return;
      const agentCtx = this.resolveAgentCtxForLead(src, options.agent || {});
      if(!safeTrim(agentCtx.name)) return;
      const row = this.buildRow(type, agentCtx, {
        category: "lead",
        entityId: safeTrim(src.id),
        entityLabel: this.campaignLeadLabel(src),
        detailText: safeTrim(options.detailText)
      });
      try {
        fetch(SUPABASE_URL + "/rest/v1/" + SUPABASE_TABLES.agentActivityLog, {
          method: "POST",
          keepalive: true,
          headers: {
            apikey: SUPABASE_PUBLISHABLE_KEY,
            Authorization: "Bearer " + SUPABASE_PUBLISHABLE_KEY,
            "Content-Type": "application/json",
            Prefer: "return=minimal"
          },
          body: JSON.stringify(row)
        }).catch(() => {});
      } catch(_e) {}
    },

    logBeacon(eventType, agentCtx){
      const type = safeTrim(eventType);
      const ctx = agentCtx && typeof agentCtx === "object" ? agentCtx : null;
      if(!type || !ctx || !safeTrim(ctx?.name)) return;
      if(type.startsWith("logout_") && this._logoutLogged) return;
      if(type.startsWith("logout_")) this._logoutLogged = true;
      const row = this.buildRow(type, ctx);
      try {
        fetch(SUPABASE_URL + "/rest/v1/" + SUPABASE_TABLES.agentActivityLog, {
          method: "POST",
          keepalive: true,
          headers: {
            apikey: SUPABASE_PUBLISHABLE_KEY,
            Authorization: "Bearer " + SUPABASE_PUBLISHABLE_KEY,
            "Content-Type": "application/json",
            Prefer: "return=minimal"
          },
          body: JSON.stringify(row)
        }).catch(() => {});
      } catch(_e) {}
    },

    async loadForDate(dateStr, category = ""){
      const date = safeTrim(dateStr) || getIsraelDateString();
      const cat = safeTrim(category);
      let loadError = "";
      try {
        let qs = SUPABASE_TABLES.agentActivityLog
          + "?activity_date=eq." + encodeURIComponent(date)
          + "&select=*&order=event_at.asc";
        if(cat) qs += "&event_category=eq." + encodeURIComponent(cat);
        const data = await Storage.restRequest(qs, { method: "GET", timeoutMs: 12000 });
        let rows = Array.isArray(data) ? data : [];
        if(cat && rows.some((row) => !safeTrim(row?.event_category))){
          rows = rows.filter((row) => this.inferCategory(row) === cat);
        } else if(!cat) {
          // loaded all — ok
        }
        return {
          rows: rows.filter((row) => this.agentInScope(row)),
          error: ""
        };
      } catch(err) {
        loadError = String(err?.message || err);
        if(cat && /column|event_category/i.test(loadError)){
          try {
            const qs = SUPABASE_TABLES.agentActivityLog
              + "?activity_date=eq." + encodeURIComponent(date)
              + "&select=*&order=event_at.asc";
            const data = await Storage.restRequest(qs, { method: "GET", timeoutMs: 12000 });
            const rows = (Array.isArray(data) ? data : [])
              .filter((row) => this.inferCategory(row) === cat)
              .filter((row) => this.agentInScope(row));
            return { rows, error: "" };
          } catch(err2) {
            loadError = String(err2?.message || err2);
          }
        }
        console.warn("[AgentActivityLog] load failed:", loadError);
        return { rows: [], error: loadError };
      }
    },

    startRealtime(onChange){
      this.stopRealtime();
      try {
        const client = Storage.getClient?.();
        if(!client) return;
        const cb = typeof onChange === "function" ? onChange : () => {};
        this._realtimeChannel = client
          .channel("gi-agent-activity-log-" + APP_SESSION_ID)
          .on("postgres_changes", {
            event: "INSERT",
            schema: "public",
            table: SUPABASE_TABLES.agentActivityLog
          }, () => { try { cb(); } catch(_e) {} })
          .subscribe();
      } catch(_e) {}
    },

    stopRealtime(){
      try {
        const client = Storage.getClient?.();
        if(client && this._realtimeChannel){
          client.removeChannel(this._realtimeChannel);
        }
      } catch(_e) {}
      this._realtimeChannel = null;
    },

    init(){
      if(this._pageHideBound) return;
      this._pageHideBound = true;
      window.addEventListener("pagehide", (ev) => {
        try {
          if(ev.persisted) return;
          const cur = Auth?.current;
          if(!cur) return;
          this.logBeacon("logout_browser", cur);
        } catch(_e) {}
      });
    }
  };

  // ---------- Auth ----------
  const Auth = {
    current: null, // {name, role}
    els: null,

    init(){
      this.els = {
        wrap: $("#lcLogin"),
        form: $("#lcLoginForm"),
        user: $("#lcLoginUser"),
        pin: $("#lcLoginPin"),
        err: $("#lcLoginError"),
      };

      // show login immediately
      try {
        document.body.classList.add("lcAuthLock");
        this.els.wrap?.setAttribute?.("aria-hidden","false");
      } catch(_) {}

      try { localStorage.removeItem(LS_SESSION_KEY); } catch(_) {}
      this.lock();

      on(this.els.form, "submit", async (e) => {
        e.preventDefault();
        await this._submit();
      });
    },

    lock(){
      try {
        document.body.classList.add("lcAuthLock");
        this.els.wrap?.setAttribute?.("aria-hidden","false");
        setTimeout(() => this.els.user?.focus?.(), 50);
      } catch(_) {}
      UI.renderAuthPill();
    },

    unlock(){
      try {
        document.body.classList.remove("lcAuthLock");
        this.els.wrap?.setAttribute?.("aria-hidden","true");
      } catch(_) {}
    },

    isAdmin(){
      return !!(this.current && (this.current.role === "admin" || this.current.role === "owner"))
        || isSystemAdminAgentIdentity();
    },

    isManager(){
      if(!this.current) return false;
      if(this.current.role === "manager") return true;
      try {
        const agents = Array.isArray(State.data?.agents) ? State.data.agents : [];
        const rec = agents.find((a) =>
          safeTrim(a?.id) === safeTrim(this.current?.id)
          || safeTrim(a?.name) === safeTrim(this.current?.name)
          || safeTrim(a?.username) === safeTrim(this.current?.name)
        );
        const roleRaw = safeTrim(rec?.role);
        if(roleRaw === "מנהל" || roleRaw.toLowerCase() === "manager" || roleRaw.toLowerCase() === "adminlite") return true;
      } catch(_e) {}
      return false;
    },

    isTeamManager(){
      if(!this.current) return false;
      if(this.current.role === "teamManager") return true;
      try {
        const rec = getCurrentAgentRecord();
        if(safeTrim(rec?.role) === "teamManager") return true;
      } catch(_e) {}
      return false;
    },

    getDashboardSalesScope(){
      if(this.isAdmin() || this.isManager()) return "all";
      if(this.isTeamManager()) return "team";
      return "self";
    },

    seesAllAgentsDashboardSales(){
      return this.getDashboardSalesScope() === "all";
    },

    seesTeamAgentsDashboardSales(){
      return this.getDashboardSalesScope() === "team";
    },

    getManagedAgentIds(){
      const id = safeTrim(this.current?.id) || safeTrim(getCurrentAgentRecord()?.id);
      return getAgentIdsForTeamManager(id);
    },

    isOps(){
      return !!(this.current && this.current.role === "ops");
    },

    isElementary(){
      return !!(this.current && this.current.role === "elementary");
    },

    isReferent(){
      return !!(this.current && this.current.role === "referent");
    },

    canAccessCampaignLeadsInbox(){
      return this.isReferent() || this.isAdmin() || this.isManager();
    },

    canAccessCampaignMyLeads(){
      return !!(this.current);
    },

    canManageCampaignLines(){
      return this.isAdmin() || this.isManager();
    },

    canMirrorAssign(){
      return this.isOps();
    },

    canViewAllCustomers(){
      return this.isAdmin() || this.isManager() || this.isOps();
    },

    canViewElementaryCustomersPool(){
      return this.isElementary() || this.isAdmin() || this.isManager();
    },

    canManageUsers(){
      return this.isAdmin() || this.isManager();
    },

    canArchiveCustomers(){
      return this.isAdmin() || this.isManager();
    },

    canUploadDailyReport(){
      return this.isAdmin() || this.isManager();
    },

    canViewActivityLog(){
      return this.isAdmin() || this.isManager() || this.isTeamManager();
    },

    logout(reason = "manual"){
      const cur = this.current ? { ...this.current } : null;
      if(cur){
        const eventType = reason === "idle" ? "logout_idle"
          : reason === "browser" ? "logout_browser"
          : "logout_manual";
        try { AgentActivityLog.logBeacon(eventType, cur); } catch(_e) {}
        try { void AgentActivityLog.log(eventType, cur); } catch(_e) {}
      }
      this.current = null;
      try { App._fullDataReady = false; } catch(_e) {}
      try { App._sessionDataScoped = false; } catch(_e) {}
      try { App.clearPostLoginDataRecovery(); } catch(_e) {}
      try { localStorage.removeItem(LS_SESSION_KEY); } catch(_) {}
      try { localStorage.removeItem(SIDEBAR_COLLAPSE_STORAGE_KEY); } catch(_) {}
      try { InactivityGuard.stop(); } catch(_e) {}
      try { CampaignAgentLeadWatcher.stop(); } catch(_e) {}
      try { BackgroundTimers.stopAll(); } catch(_e) {}
      this.lock();
      try { UI.applySidebarCollapse(true); } catch(_e) {}
      if(reason === "idle"){
        this._setError("בוצעה התנתקות אוטומטית לאחר 40 דקות של אי פעילות במערכת");
      } else {
        this._setError("");
      }
      try {
        if(this.els?.user) this.els.user.value = "";
        if(this.els?.pin) this.els.pin.value = "";
      } catch(_e) {}
      try {
        const mfa = document.getElementById('lcLoginMfaCode');
        if(mfa) mfa.value = '';
        const mfaStep = document.getElementById('lcLoginMfaStep');
        if(mfaStep) mfaStep.hidden = true;
        const credentialsStep = document.getElementById('lcLoginCredentialsStep');
        if(credentialsStep) credentialsStep.hidden = false;
      } catch(_e) {}
      UI.applyRoleUI();
      UI.goView("dashboard");
      try { window.dispatchEvent(new CustomEvent('gi:app-logout')); } catch(_e) {}
      try {
        const isElectron = typeof navigator !== 'undefined' && /electron/i.test(String(navigator.userAgent || ''));
        if(isElectron){
          try {
            window.dispatchEvent(new CustomEvent('gi:logout'));
          } catch(_e) {}
        }
      } catch(_e) {}
    },

    _setError(msg){
      showLoginError(msg);
    },

    _restoreSession(){
      try {
        const raw = localStorage.getItem(LS_SESSION_KEY);
        if(!raw) return null;
        const s = JSON.parse(raw);
        const name = safeTrim(s?.name);
        const role = safeTrim(s?.role) || "agent";
        if(!name) return null;
        return { name, role };
      } catch(_) { return null; }
    },

    _saveSession(cur){
      try {
        localStorage.setItem(LS_SESSION_KEY, JSON.stringify({ name: cur.name, role: cur.role }));
      } catch(_) {}
    }
  };

  const InactivityGuard = {
    idleMs: AUTO_LOGOUT_IDLE_MS,
    warnText: "בוצעה התנתקות אוטומטית לאחר 40 דקות של אי פעילות במערכת",
    timerId: null,
    started: false,
    boundActivityHandler: null,
    boundVisibilityHandler: null,
    events: ["mousemove", "mousedown", "keydown", "scroll", "touchstart", "pointerdown", "wheel"],

    init(){
      this.boundActivityHandler = this.boundActivityHandler || (() => this.bump());
      this.boundVisibilityHandler = this.boundVisibilityHandler || (() => {
        if(document.visibilityState === 'visible') this.bump();
      });
    },

    start(){
      this.init();
      this.stop();
      if(!Auth.current) return;
      this.events.forEach((evt) => window.addEventListener(evt, this.boundActivityHandler, true));
      document.addEventListener('visibilitychange', this.boundVisibilityHandler, true);
      this.started = true;
      this.bump();
    },

    stop(){
      if(this.timerId){
        clearTimeout(this.timerId);
        this.timerId = null;
      }
      if(this.boundActivityHandler){
        this.events.forEach((evt) => window.removeEventListener(evt, this.boundActivityHandler, true));
      }
      if(this.boundVisibilityHandler){
        document.removeEventListener('visibilitychange', this.boundVisibilityHandler, true);
      }
      this.started = false;
    },

    bump(){
      if(!Auth.current) return;
      if(this.timerId) clearTimeout(this.timerId);
      this.timerId = window.setTimeout(() => this.trigger(), this.idleMs);
    },

    trigger(){
      this.timerId = null;
      if(!Auth.current) return;
      this.stop();
      try { ChatUI.close?.(); } catch(_e) {}
      Auth.logout('idle');
    }
  };

  function getTimeGreeting(){
    const hour = new Date().getHours();
    if(hour < 12) return "בוקר טוב";
    if(hour < 17) return "צהריים טובים";
    return "ערב טוב";
  }

  const WelcomeLoader = {
    el: null,
    statusTimer: null,
    statuses: ["מאמת הרשאות","טוען נתוני מערכת","מכין סביבת עבודה","כמעט מוכן"],
    ensure(){
      if(this.el) return this.el;
      const root = document.createElement("div");
      root.id = "lcWelcomeLoader";
      root.className = "lcWelcomeLoader";
      root.setAttribute("aria-hidden", "true");
      root.innerHTML = `
        <div class="lcWelcomeLoader__backdrop"></div>
        <div class="lcWelcomeLoader__panel" role="status" aria-live="polite" aria-atomic="true">
          <div class="lcWelcomeLoader__content">
            <img class="lcWelcomeLoader__logo" src="./logo-login-clean.png" alt="GEMEL INVEST" />
            <div class="lcWelcomeLoader__greeting" id="lcWelcomeGreeting"></div>
            <div class="lcWelcomeLoader__name" id="lcWelcomeName"></div>
            <div class="lcWelcomeLoader__sub">טוען מערכת, אנא המתן</div>
            <div class="lcWelcomeLoader__status" id="lcWelcomeStatus">מאמת הרשאות</div>
            <div class="lcWelcomeLoader__line" aria-hidden="true">
              <span class="lcWelcomeLoader__lineTrack"></span>
              <span class="lcWelcomeLoader__lineFill"></span>
              <span class="lcWelcomeLoader__lineShine"></span>
            </div>
          </div>
        </div>
      `;
      document.body.appendChild(root);
      this.el = root;
      return root;
    },
    startStatusCycle(){
      const root = this.ensure();
      const statusEl = root.querySelector('#lcWelcomeStatus');
      let index = 0;
      if(statusEl) statusEl.textContent = this.statuses[0];
      this.stopStatusCycle();
      this.statusTimer = window.setInterval(() => {
        index = (index + 1) % this.statuses.length;
        if(statusEl) statusEl.textContent = this.statuses[index];
      }, 1500);
    },
    stopStatusCycle(){
      if(this.statusTimer){
        clearInterval(this.statusTimer);
        this.statusTimer = null;
      }
    },
    open(name){
      const root = this.ensure();
      const greetingEl = root.querySelector('#lcWelcomeGreeting');
      const nameEl = root.querySelector('#lcWelcomeName');
      if(greetingEl) greetingEl.textContent = getTimeGreeting();
      if(nameEl) nameEl.textContent = safeTrim(name);
      root.classList.add('is-open');
      root.setAttribute('aria-hidden', 'false');
      this.startStatusCycle();
    },
    close(){
      const root = this.ensure();
      this.stopStatusCycle();
      root.classList.remove('is-open');
      root.setAttribute('aria-hidden', 'true');
    },
    async play(name, ms=3000){
      this.open(name);
      await new Promise(resolve => setTimeout(resolve, ms));
      this.close();
    }
  };

  // ---------- Forgot Password / Contact Admin ----------
  const ForgotPasswordUI = {
    els: null,

    init(){
      this.els = {
        trigger: $("#lcForgotPasswordBtn"),
        wrap: $("#lcForgotModal"),
        backdrop: $("#lcForgotModalBackdrop"),
        close: $("#lcForgotModalClose"),
        cancel: $("#lcForgotModalCancel"),
        send: $("#lcForgotModalSend"),
        username: $("#lcForgotUsername"),
        message: $("#lcForgotMessage"),
        err: $("#lcForgotModalError"),
        success: $("#lcForgotModalSuccess")
      };

      on(this.els.trigger, "click", () => this.open());
      on(this.els.close, "click", () => this.close());
      on(this.els.cancel, "click", () => this.close());
      on(this.els.backdrop, "click", () => this.close());
      on(this.els.send, "click", () => this.submit());
      on(this.els.wrap, "keydown", (ev) => {
        if(ev.key === "Escape"){
          ev.preventDefault();
          this.close();
        }
      });
    },

    open(){
      if(!this.els?.wrap) return;
      this.setError("");
      this.setSuccess("");
      const loginUser = safeTrim($("#lcLoginUser")?.value);
      this.els.username.value = loginUser || this.els.username.value || "";
      this.els.wrap.classList.add("is-open");
      this.els.wrap.setAttribute("aria-hidden","false");
      setTimeout(() => {
        if(this.els.username.value) this.els.message?.focus?.();
        else this.els.username?.focus?.();
      }, 50);
    },

    close(){
      if(!this.els?.wrap) return;
      this.els.wrap.classList.remove("is-open");
      this.els.wrap.setAttribute("aria-hidden","true");
      this.setError("");
      this.setSuccess("");
    },

    setError(msg){
      if(this.els?.err) this.els.err.textContent = msg ? String(msg) : "";
    },

    setSuccess(msg){
      if(!this.els?.success) return;
      const hasMsg = !!msg;
      const textEl = this.els.success.querySelector('.lcForgotModal__successText');
      if(textEl) textEl.textContent = msg ? String(msg) : '';
      else this.els.success.textContent = msg ? String(msg) : '';
      this.els.success.classList.toggle('is-visible', hasMsg);
    },

    buildMailto(username, message){
      const subject = "פנייה ממסך כניסה – GEMEL INVEST";
      const body = [
        "שם משתמש: " + safeTrim(username),
        "",
        "הודעה:",
        safeTrim(message),
        "",
        "Build: " + BUILD,
        "Sent: " + nowISO()
      ].join("\n");
      return `mailto:${encodeURIComponent(ADMIN_CONTACT_EMAIL)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    },

    async submit(){
      const username = safeTrim(this.els?.username?.value);
      const message = safeTrim(this.els?.message?.value);
      this.setError("");
      this.setSuccess("");

      if(!username) return this.setError("נא להזין שם משתמש");
      if(!message) return this.setError("נא לכתוב את תוכן הפנייה");

      const btn = this.els?.send;
      const prevText = btn?.textContent || "שלח פנייה";
      if(btn){
        btn.disabled = true;
        btn.textContent = "שולח...";
      }

      const result = await Storage.sendAdminContact({ username, message });
      if(result.ok){
        this.setSuccess("הפנייה נשלחה בהצלחה למנהל המערכת.");
        if(this.els?.message) this.els.message.value = "";
        if(btn){
          btn.disabled = false;
          btn.textContent = prevText;
        }
        setTimeout(() => this.close(), 1800);
        return;
      }

      try {
        window.location.href = this.buildMailto(username, message);
        this.setSuccess("נפתח חלון מייל לשליחת הפנייה למנהל המערכת.");
      } catch(_e) {
        this.setError("לא הצלחתי לשלוח אוטומטית. בשלב זה הפנייה תיפתח כמייל רגיל למנהל המערכת.");
      } finally {
        if(btn){
          btn.disabled = false;
          btn.textContent = prevText;
        }
      }
    }
  };



