      const chip = this.els.body.querySelector('[data-elem-draft-age-inline]');
      const valueEl = this.els.body.querySelector('[data-elem-draft-age-value]');
      if(!chip || !valueEl) return;
      const hasAge = age !== null && Number.isFinite(age);
      valueEl.textContent = hasAge ? String(age) : '';
