    getTodayIsoDate(){
      const now = new Date();
      const y = now.getFullYear();
      const m = String(now.getMonth() + 1).padStart(2, '0');
      const d = String(now.getDate()).padStart(2, '0');
      return `${y}-${m}-${d}`;
    },


    async handleElementaryVehicleHarFile(ins, file){
      if(!file || !ins) return;
      try{
        this.setElementaryHarImportState(ins, { status:'loading', fileName:file.name || '', message:'קורא את קובץ הר הביטוח בזיכרון בלבד…' });
        this.render();
        if(window.GI_LOAD_LIBS?.xlsx) await window.GI_LOAD_LIBS.xlsx();
        const buffer = await file.arrayBuffer();
        const parsed = this.parseElementaryVehicleHarWorkbook(buffer, ins);
        const policies = Array.isArray(parsed?.policies) ? parsed.policies : [];
        if(!policies.length){
          this.setElementaryHarImportState(ins, { status:'empty', count:0, fileName:file.name || '', message:'לא נמצאו פוליסות רכב מתוך תחום כללי בקובץ שהועלה.' });
          this.render();
          return;
        }
        const approved = await showHarBituachImportModal({
          policies: policies.map((item) => ({ company:item.company, policyNumber:item.policyNumber, type:[item.sub, item.productType].filter(Boolean).join(' · ') || 'פוליסת רכב' })),
          title: `זוהו ${policies.length} רשומות רכב לייבוא`,
          note: 'המערכת תייבא רק פוליסות רכב מתוך תחום כללי. פוליסות דירה לא ייכנסו למסך הזה.',
          confirmText: 'אישור',
          cancelText: 'ביטול'
        });
        if(!approved){
          this.setElementaryHarImportState(ins, { status:'cancelled', count:policies.length, fileName:file.name || '', message:'הייבוא בוטל לפני הוספת פוליסות הרכב.' });
          this.render();
          return;
        }
        this.setElementaryHarImportState(ins, { status:'loading', count:policies.length, fileName:file.name || '', message:'מוריד נתוני רכב מהר הביטוח למערכת…' });
        this.render();
        await showHarBituachProcessingModal({
          title:'מוריד נתוני רכב מהר הביטוח',
          subtitle:'מסנן רק תחום כללי ורק ביטוח רכב',
          successTitle:'פוליסות הרכב נטענו בהצלחה',
          successSubtitle:`נמצאו ${policies.length} רשומות רכב להצגה`,
          loadingMs:1250,
          successMs:920
        });
        ins.data.elementaryVehiclePolicies = policies;
        this.setElementaryHarImportState(ins, { status:'done', count:policies.length, fileName:file.name || '', importedAt:nowISO(), message:`יובאו ${policies.length} פוליסות רכב מתוך תחום כללי. דירה לא נמשכה למסך זה.` });
        this.render();
      }catch(err){
        this.setElementaryHarImportState(ins, { status:'error', fileName:file?.name || '', message:`ייבוא הר הביטוח נכשל: ${safeTrim(err?.message || err)}` });
        this.render();
      }
    },

    normalizeOccupationSearch(value){
      return String(value || "")
        .normalize("NFKC")
        .replace(/[׳'"`]/g, "")
        .replace(/[-_/.,]/g, " ")
        .replace(/\s+/g, " ")
        .trim()
        .toLowerCase();
    },

    getOccupationSuggestions(term){
      const q = this.normalizeOccupationSearch(term);
      const list = Array.isArray(this.occupations) ? this.occupations : [];
      if(!q) return list.slice(0, 20);
      const exact = [];
      const starts = [];
      const includes = [];
      list.forEach(item => {
        const txt = this.normalizeOccupationSearch(item);
        if(!txt.includes(q)) return;
        if(txt === q) exact.push(item);
        else if(txt.startsWith(q)) starts.push(item);
        else includes.push(item);
      });
      return exact.concat(starts, includes).slice(0, 20);
    },

    renderOccupationSuggestions(term, currentValue){
      const cur = safeTrim(currentValue);
      const items = this.getOccupationSuggestions(term);
      if(!items.length){
        return `<button type="button" class="lcOccOption is-empty" data-occ-empty="1">לא נמצאו תוצאות. אפשר להקליד ידנית.</button>`;
      }
      return items.map(item => {
        const active = (safeTrim(item) === cur) ? " is-active" : "";
        return `<button type="button" class="lcOccOption${active}" data-occ-value="${escapeHtml(item)}">${escapeHtml(item)}</button>`;
      }).join("");
    },

    bindOccupationAutocomplete(ins){
      const input = $("#lcOccupationInput", this.els.body);
      const menu = $("#lcOccupationMenu", this.els.body);
      if(!input || !menu) return;

      const openMenu = () => {
        menu.classList.add("is-open");
        input.setAttribute("aria-expanded", "true");
      };
      const closeMenu = () => {
        menu.classList.remove("is-open");
        input.setAttribute("aria-expanded", "false");
      };
      const refreshMenu = () => {
        menu.innerHTML = this.renderOccupationSuggestions(input.value, ins.data.occupation || "");
      };
      const choose = (val) => {
        const picked = safeTrim(val);
        input.value = picked;
        ins.data.occupation = picked;
        refreshMenu();
        closeMenu();
        this.setHint("");
      };

      refreshMenu();
      on(input, "focus", () => { refreshMenu(); openMenu(); });
      on(input, "click", () => { refreshMenu(); openMenu(); });
      on(input, "input", () => { ins.data.occupation = safeTrim(input.value); refreshMenu(); openMenu(); });
      on(input, "keydown", (ev) => {
        const options = $$("[data-occ-value]", menu);
        const current = menu.querySelector(".lcOccOption.is-hover");
        let idx = current ? options.indexOf(current) : -1;
        if(ev.key === "ArrowDown"){
          ev.preventDefault();
          if(!menu.classList.contains("is-open")){ refreshMenu(); openMenu(); }
          idx = Math.min(idx + 1, options.length - 1);
          options.forEach(o => o.classList.remove("is-hover"));
          if(options[idx]) options[idx].classList.add("is-hover");
          return;
        }
        if(ev.key === "ArrowUp"){
          ev.preventDefault();
          idx = Math.max(idx - 1, 0);
          options.forEach(o => o.classList.remove("is-hover"));
          if(options[idx]) options[idx].classList.add("is-hover");
          return;
        }
        if(ev.key === "Enter" && menu.classList.contains("is-open")){
          const picked = menu.querySelector(".lcOccOption.is-hover") || menu.querySelector("[data-occ-value]");
          if(picked){
            ev.preventDefault();
            choose(picked.getAttribute("data-occ-value") || picked.textContent || "");
          }
          return;
        }
        if(ev.key === "Escape") closeMenu();
      });
      on(menu, "mousedown", (ev) => {
        const btn = ev.target && ev.target.closest ? ev.target.closest("[data-occ-value]") : null;
        if(!btn) return;
        ev.preventDefault();
        choose(btn.getAttribute("data-occ-value") || "");
      });
      on(document, "click", (ev) => {
        if(!this.els.body || !this.els.body.contains(input)) return;
        const inside = ev.target === input || menu.contains(ev.target);
        if(!inside) closeMenu();
      });
    },

    // ---------- Step 1 ----------
