        '17': { title:'גידול שפיר / ממאיר / סרטן', fields:[t('cancerDiagnosis','סוג גידול / אבחנה'), t('cancerDate','מועד אבחון'), t('cancerTreatment','טיפול / ניתוח / כימו / קרינה'), z('cancerStatus','שלב / גרורות / מעקב / מצב כיום')] },
