        'יח': { title:'שאלון יח׳ — אף / אוזן / גרון', fields:[z('diagnosis','אבחנה: שמיעה, מנייר, טינטון, סינוסיטיס, דלקות אוזניים, מחיצה/פוליפים/מיתרי קול'), z('tests','בדיקות שמיעה/שינה/הדמיה'), z('treatment','טיפול/ניתוח/מכשיר שמיעה/CPAP'), z('status','מצב עדכני') ]},
        'יט': { title:'שאלון יט׳ — מערכת המין והרבייה', fields:[z('female','נשים: גוש בשד, דימומים, הריון, קיסרי, רחם שרירני, צניחה, פריון, קונדילומה, הפלות — פרט'), z('male','גברים: פריון, אשך טמיר, וריקוצלה, הידרוצלה, היפוספדיאס — פרט'), z('testsTreatment','בדיקות/טיפולים/ניתוחים ומצב עדכני') ]},
