        '4': { title:'בלוטת התריס / אנדוקרינולוגיה', fields:[t('diagnosis','אבחנה'), t('tests','בדיקות / ערכים אחרונים'), t('treatment','טיפול'), z('status','מצב כיום / מעקב')] },
