        '7': { title:'אלכוהול / סמים', fields:[t('substance','סוג שימוש / חומר'), t('amount','כמות ותדירות'), t('period','תקופה / מועד הפסקה אם הופסק'), z('status','טיפול / גמילה / מצב כיום')] },
