  const CarInsuranceClickUI = {
    els: {},
    init(){
      this.els.btn = document.getElementById("btnCarInsuranceClick");
      this.els.modal = document.getElementById("lcCarInsuranceClickModal");
      this.els.backdrop = this.els.modal?.querySelector?.(".lcCarInsuranceClickModal__backdrop");
      this.els.btnClose = document.getElementById("lcCarInsuranceClickModalClose");
      this.els.btnCancel = document.getElementById("lcCarInsuranceClickCancelBtn");
      this.els.btnContinue = document.getElementById("lcCarInsuranceClickContinueBtn");
      this.els.input = document.getElementById("lcCarInsuranceClickIdInput");
      this.els.error = document.getElementById("lcCarInsuranceClickError");
      if(!this.els.btn || !this.els.modal) return;

      on(this.els.btn, "click", (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        if(!Auth.current){
          try{
            window.showToast?.({ title: "נדרשת התחברות", text: "יש להתחבר למערכת לפני פתיחת ביטוח רכב בקליק.", variant: "warn", durationMs: 4200 });
          }catch(_e){}
          return;
        }
        this.open();
      });

      on(this.els.btnClose, "click", (ev) => { ev.preventDefault(); this.close(); });
      on(this.els.btnCancel, "click", (ev) => { ev.preventDefault(); this.close(); });
      on(this.els.btnContinue, "click", (ev) => { ev.preventDefault(); this.submit(); });
      on(this.els.backdrop, "click", (ev) => { ev.preventDefault(); this.close(); });
      on(this.els.modal, "click", (ev) => {
        const t = ev.target;
        if(t && t.getAttribute && t.getAttribute("data-close") === "1") this.close();
      });
      on(this.els.input, "input", () => {
        if(this.els.input) this.els.input.value = digitsOnly(this.els.input.value).slice(0, 9);
        this.clearError();
      });
      on(this.els.input, "keydown", (ev) => {
        if(ev.key === "Enter"){ ev.preventDefault(); this.submit(); }
        if(ev.key === "Escape"){ ev.preventDefault(); this.close(); }
      });

      document.addEventListener("keydown", (ev) => {
        if(ev.key === "Escape" && this.isOpen()) this.close();
      });
    },
    isOpen(){
      return !!this.els.modal && this.els.modal.classList.contains("is-open");
    },
    open(){
      if(!Auth.current) return;
      try{ NewCustomerEntryUI?.close?.(); }catch(_e){}
      try{ Wizard?.close?.(); }catch(_e){}
      this.clearError();
      if(this.els.input) this.els.input.value = "";
      this.els.modal.classList.add("is-open");
      this.els.modal.setAttribute("aria-hidden", "false");
      document.body.classList.add("modal-open");
      window.setTimeout(() => this.els.input?.focus?.(), 60);
    },
    close(){
      if(!this.els.modal) return;
      this.clearError();
      this.els.modal.classList.remove("is-open");
      this.els.modal.setAttribute("aria-hidden", "true");
      const hasOtherOpenModal = !!document.querySelector(".modal.is-open, .drawer.is-open, .lcWizard.is-open");
      if(!hasOtherOpenModal) document.body.classList.remove("modal-open");
    },
    clearError(){
      if(!this.els.error) return;
      this.els.error.hidden = true;
      this.els.error.textContent = "";
    },
    setError(message){
      if(!this.els.error) return;
      this.els.error.hidden = false;
      this.els.error.textContent = safeTrim(message);
    },
    getCustomerIdNumber(rec){
      const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
      const direct = normalizeIdValue(rec?.idNumber);
      if(direct) return direct;
      const primary = payload.primary && typeof payload.primary === "object" ? payload.primary : {};
      const fromPrimary = normalizeIdValue(primary.idNumber);
      if(fromPrimary) return fromPrimary;
      const insureds = Array.isArray(payload.insureds) ? payload.insureds : [];
      for(const ins of insureds){
        const id = normalizeIdValue(ins?.data?.idNumber);
        if(id) return id;
      }
      return "";
    },
    customerMatchesIdNumber(rec, idNumber){
      const target = normalizeIdValue(idNumber);
      if(!target || target.length !== 9) return false;
      if(this.getCustomerIdNumber(rec) === target) return true;
      const payload = rec?.payload && typeof rec.payload === "object" ? rec.payload : {};
      const insureds = Array.isArray(payload.insureds) ? payload.insureds : [];
      return insureds.some((ins) => normalizeIdValue(ins?.data?.idNumber) === target);
    },
    canAccessCustomer(rec){
      if(!rec || !Auth.current) return false;
      if(Auth.canViewAllCustomers()) return true;
      return customerOwnedByCurrentAgent(rec);
    },
    findCustomersByIdNumber(idNumber){
      const id = normalizeIdValue(idNumber);
      if(id.length !== 9) return [];
      const all = Array.isArray(State.data?.customers) ? State.data.customers : [];
      return all.filter((rec) => this.customerMatchesIdNumber(rec, id));
    },
    lookupAuthorizedCustomer(idNumber){
      const matches = this.findCustomersByIdNumber(idNumber);
      if(!matches.length) return { status: "not_found" };
      const authorized = matches.filter((rec) => this.canAccessCustomer(rec));
      if(!authorized.length) return { status: "forbidden" };
      authorized.sort((a, b) => new Date(b.updatedAt || b.updated_at || 0) - new Date(a.updatedAt || a.created_at || 0));
      return { status: "found", customer: authorized[0] };
    },
    submit(){
      if(!Auth.current) return;
      const id = normalizeIdValue(this.els.input?.value);
      if(id.length !== 9 || !isValidIsraeliId(id)){
        this.setError("נא להזין תעודת זהות ישראלית תקינה (9 ספרות).");
        this.els.input?.focus?.();
        return;
      }
      const lookup = this.lookupAuthorizedCustomer(id);
      this.close();
      if(lookup.status === "found" && lookup.customer){
        const name = safeTrim(lookup.customer.fullName) || "הלקוח";
        Wizard.openElementaryVehicleFromCustomer(lookup.customer, {
          carInsuranceClick: true,
          hint: `פרטי ${name} נטענו — מלאו את שלבי האשף עד בחירת כיסוי, ואז הגישו לחיתום.`
        });
        return;
      }
      Wizard.openElementaryVehicleFromCustomer(null, {
        carInsuranceClick: true,
        prefillId: id,
        hint: "לא נמצא לקוח — מלאו את שלבי האשף עד בחירת כיסוי, ואז הגישו לחיתום."
      });
    }
  };

