  function getAgentApptProductTypes(){
    const core = ["ריסק משכנתא", "ריסק", "בריאות", "סרטן", "מחלות קשות", "אובדן כושר עבודה"];
    const wiz = (typeof Wizard !== "undefined" && Array.isArray(Wizard.insTypes)) ? Wizard.insTypes : [];
    return Array.from(new Set([...core, ...wiz].map((x) => safeTrim(x)).filter(Boolean)));
  }

  function getAgentApptCompany(id){
    const key = safeTrim(id);
    return AGENT_APPT_COMPANIES.find((c) => c.id === key) || null;
  }

  function newAgentApptPolicyRow(){
    const types = getAgentApptProductTypes();
    return {
      id: "aap_" + Math.random().toString(16).slice(2) + "_" + Date.now().toString(16),
      policyNumber: "",
      productType: types[0] || "בריאות",
      totalPremium: ""
    };
  }

  function newAgentApptState(){
    const today = new Date().toISOString().slice(0, 10);
    const agentRec = typeof findAgentRecordForSession === "function" ? findAgentRecordForSession() : null;
    return {
      companyId: "",
      scope: "specific",
      requestDate: today,
      customer: {
        firstName: "", lastName: "", idNumber: "", phone: "", phoneHome: "",
        email: "", street: "", houseNumber: "", city: "", zip: ""
      },
      agent: {
        name: safeTrim(agentRec?.name) || safeTrim(Auth?.current?.name) || "",
        agentNumber: "",
        idNumber: "",
        phone: safeTrim(agentRec?.phone) || "",
        address: ""
      },
      policies: [newAgentApptPolicyRow()]
    };
  }

